={{
  (() => {
    const totalTokens = Number(
      $node["BUSCAR EXECUÇÃO"].json["data"]["resultData"]["runData"]["OpenAI Chat Model"]["0"]["data"]["ai_languageModel"]["0"]["0"]["json"]["tokenUsage"]["totalTokens"]
    );

    const modelo = $json["modelo"];

    const multiplicador = ({
      "gpt-5-nano": 0.20,
      "gpt-5-mini": 1.00,
      "gpt-5": 5.00,
      "gpt-5-pro": 60.00,

      "gpt-4.1-nano": 0.22,
      "gpt-4.1-mini": 0.89,
      "gpt-4.1": 4.44,

      "gpt-4o-mini": 0.33,
      "gpt-4o": 5.56,
    }[modelo] ?? 1.00);

    const creditosNovos = Math.ceil(totalTokens * (multiplicador / 1000));
    return creditosNovos + Number($json["creditosGasto"] || 0);
  })()
}}

options.queryReplacement:
={{
  (() => {
    const id_agente = Number($('CALCULAR TOKEN IA').item.json.body.idAgente);

    const modelRaw = String(
      $json.data?.resultData?.runData?.['OpenAI Chat Model']?.[0]?.data?.ai_languageModel?.[0]?.[0]?.json?.response?.generations?.[0]?.[0]?.generationInfo?.model_name
      || ''
    ).toLowerCase();

    const totalTokens = Number(
      $json.data?.resultData?.runData?.['OpenAI Chat Model']?.[0]?.data?.ai_languageModel?.[0]?.[0]?.json?.tokenUsage?.totalTokens
      || 0
    );

    // ordem importa: específicos primeiro
    const mult =
      modelRaw.includes('gpt-5-pro') ? 60.00 :
      modelRaw.includes('gpt-5-mini') ? 1.00 :
      modelRaw.includes('gpt-5-nano') ? 0.20 :
      modelRaw.includes('gpt-5') ? 5.00 :
      modelRaw.includes('gpt-4.1-mini') ? 0.89 :
      modelRaw.includes('gpt-4.1-nano') ? 0.22 :
      modelRaw.includes('gpt-4.1') ? 4.44 :
      modelRaw.includes('gpt-4o-mini') ? 0.33 :
      modelRaw.includes('gpt-4o') ? 5.56 :
      1.00;

    // créditos (pode ter 1 casa decimal)
    let credits = (totalTokens / 1000) * mult;

    // arredonda para 1 casa decimal
    credits = Math.round(credits * 10) / 10;

    // nunca menos que 0.1 se teve uso de tokens
    if (totalTokens > 0 && credits < 0.1) credits = 0.1;

    return JSON.stringify({ id_agente, qnt_tokens: credits });
  })()
}}

