-- =========================
-- criar-tabelas-unificado.sql
-- =========================
-- Arquivo unificado: combina criar-tabelas-conta.sql (base) com adições
-- de criar-tabelas.sql (realtime, índices extras, cron, coluna nota).
-- Gerado em 2026-03-25.
--
-- Combina criar-tabelas + migração multi-usuários.
-- Lógica:
--   1. Tudo vazio (SAAS_Planos não existe) → cria direto no formato novo (SAAS_Contas + contaId)
--   2. Tabelas existem mas SAAS_Contas não existe → executa migração
--   3. SAAS_Contas existe ou contaId já presente → não migra, só ajustes (funções, RLS, views, grants)
--
-- IMPORTANTE: Faça backup do banco antes de executar!

CREATE EXTENSION IF NOT EXISTS pgcrypto;

DO $$
DECLARE
  ext TEXT;
BEGIN
  FOR ext IN SELECT unnest(ARRAY['http','pg_cron','pg_graphql','pg_stat_statements','pgcrypto','pgjwt','pgsodium','uuid-ossp','vector'])
  LOOP
    IF EXISTS (SELECT 1 FROM pg_available_extensions WHERE name = ext) THEN
      BEGIN EXECUTE format('CREATE EXTENSION IF NOT EXISTS %I', ext); EXCEPTION WHEN OTHERS THEN RAISE NOTICE 'Ext %: %', ext, SQLERRM; END;
    END IF;
  END LOOP;
END$$;

-- =========================
-- DETECÇÃO DE CENÁRIO
-- =========================
-- vazio: SAAS_Planos não existe
-- migrar: SAAS_Planos existe, SAAS_Contas não existe
-- ajustar: SAAS_Contas existe OU SAAS_Conexões tem contaId

-- =========================
-- CENÁRIO 1: VAZIO - Criar tudo no formato novo
-- =========================
DO $$
BEGIN
  IF to_regclass('public."SAAS_Planos"') IS NOT NULL THEN RETURN; END IF;

  RAISE NOTICE 'Cenário VAZIO: criando todas as tabelas no formato novo (SAAS_Contas + contaId).';

  CREATE TABLE IF NOT EXISTS public."SAAS_Planos" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    nome TEXT, preco REAL,
    "qntConexoes" BIGINT, "qntContatos" BIGINT, "qntDisparos" BIGINT, "qntUsuarios" BIGINT,
    "qntQuadros" BIGINT, "qntAgentesIa" BIGINT, "qntCreditosIa" BIGINT,
    menu_ocultar JSONB DEFAULT '[]'::jsonb
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Contas" (
    id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    status BOOLEAN DEFAULT TRUE,
    "dataValidade" DATE,
    plano BIGINT REFERENCES public."SAAS_Planos"(id) ON UPDATE CASCADE,
    tokens NUMERIC,
    email TEXT
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Usuarios" (
    id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    "contaId" UUID REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL,
    nome TEXT, "Email" TEXT, telefone TEXT,
    auth_user_id UUID UNIQUE,
    funcao TEXT NOT NULL DEFAULT 'admin' CHECK (funcao IN ('admin', 'membro')),
    super_admin BOOLEAN NOT NULL DEFAULT false
  );
  CREATE INDEX IF NOT EXISTS idx_usuarios_contaId ON public."SAAS_Usuarios"("contaId");
  CREATE INDEX IF NOT EXISTS idx_usuarios_auth_user_id ON public."SAAS_Usuarios"(auth_user_id);

  CREATE TABLE IF NOT EXISTS public."SAAS_Conexões" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    "instanceName" TEXT, "NomeConexao" TEXT, "Telefone" TEXT, "FotoPerfil" TEXT, "Apikey" TEXT,
    "contaId" UUID REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL,
    "idAgente" BIGINT
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Listas" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    nome TEXT NOT NULL, descricao TEXT, tipo TEXT, campos JSONB, "idConexao" BIGINT,
    "contaId" UUID NOT NULL REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Contatos" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    nome TEXT, telefone TEXT, "fotoPerfil" TEXT, "idLista" BIGINT NOT NULL, atributos JSONB NOT NULL DEFAULT '{}',
    "contaId" UUID NOT NULL REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Grupos" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    nome TEXT, "WhatsAppId" TEXT, "idLista" BIGINT NOT NULL, "idConexao" BIGINT,
    atributos JSONB NOT NULL DEFAULT '{}', participantes BIGINT,
    "contaId" UUID NOT NULL REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Disparos" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    "NomeDisparo" TEXT,
    "Mensagens" JSONB[], "TipoDisparo" TEXT, "TotalDisparos" BIGINT, "MensagensDisparadas" BIGINT,
    "StatusDisparo" TEXT, "idExecution" TEXT, "idListas" BIGINT[], "idConexoes" BIGINT[],
    "intervaloMin" INTEGER, "intervaloMax" INTEGER, "PausaAposMensagens" INTEGER, "PausaMinutos" INTEGER,
    "StartTime" TIME, "EndTime" TIME, "DiasSelecionados" SMALLINT[], "DataAgendamento" TIMESTAMPTZ,
    "contaId" UUID REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Detalhes_Disparos" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "idDisparo" BIGINT, "idContato" BIGINT, "Mensagem" TEXT, "idConexao" BIGINT,
    "dataEnvio" TIMESTAMPTZ, "Status" TEXT, "statusHttp" TEXT, "mensagemErro" TEXT,
    "respostaHttp" JSONB, "Payload" JSONB, "KeyRedis" TEXT, "FakeCall" BOOLEAN, "idGrupo" BIGINT
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Quadros" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    nome TEXT, descricao TEXT, cor TEXT, icone TEXT,
    "contaId" UUID REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Etapas_Quadros" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    "quadroId" BIGINT, nome TEXT, ordem SMALLINT,
    "contaId" UUID REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Cards_Quadros" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    "quadroId" BIGINT, "contatoId" BIGINT, valor DOUBLE PRECISION, "etapaQuadroId" BIGINT,
    observacoes TEXT, tarefas JSONB[], ordem SMALLINT, nome TEXT, contato TEXT
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_AgentesIA" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    nome TEXT, "conexaoId" BIGINT, instrucoes TEXT, modelo TEXT, criatividade REAL,
    "maxCreditos" BIGINT, ativo BOOLEAN, conhecimento JSONB, cor TEXT,
    "separarMensagens" BOOLEAN, "ouvirAudio" BOOLEAN, "analisarImagens" BOOLEAN,
    "aparecerDigitando" BOOLEAN, "pausarAtendimento" BOOLEAN, "qntMsgHistorico" INTEGER,
    "agruparMensagens" BOOLEAN, "intervaloEntreMensagens" INTEGER,
    "CRM" JSONB, "abrirAtendimento" JSONB, "notificarHumano" JSONB, "requisicaoHTTP" JSONB,
    "contaId" UUID REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Conversas_Agentes" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    "idAgente" BIGINT, "idConexao" BIGINT REFERENCES public."SAAS_Conexões"(id) ON UPDATE CASCADE ON DELETE CASCADE, telefone TEXT, pausado BOOLEAN,
    "pausaAte" TIMESTAMPTZ, "ultimaMensagem" TIMESTAMPTZ,
    "contaId" UUID REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL,
    "contatoId" BIGINT, lida BOOLEAN NOT NULL DEFAULT false,
    "statusAtendimento" TEXT NOT NULL DEFAULT 'aguardando', "nomeConversa" TEXT, "fotoPerfil" TEXT,
    nota TEXT,
    "atendente" UUID DEFAULT null REFERENCES public."SAAS_Usuarios"(id) ON UPDATE CASCADE ON DELETE SET NULL
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Mensagens" (
    id BIGINT GENERATED ALWAYS AS IDENTITY NOT NULL PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    "contaId" UUID NOT NULL REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL,
    "conexaoId" BIGINT, "conversaId" BIGINT NOT NULL REFERENCES public."SAAS_Conversas_Agentes"(id) ON UPDATE CASCADE ON DELETE CASCADE, mensagem TEXT,
    "tipoMensagem" TEXT NOT NULL, "arquivoUrl" TEXT, "fromMe" BOOLEAN NOT NULL DEFAULT false,
    apagada BOOLEAN NOT NULL DEFAULT false, "messageEvolutionId" TEXT, "mensagemRespondida" TEXT,
    enviada BOOLEAN, favorita BOOLEAN NOT NULL DEFAULT false, "IA" BOOLEAN
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Conhecimentos" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    content TEXT, metadata JSONB
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Webhook" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    "contaId" UUID REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL,
    "conexaoId" BIGINT, "tokenWebhook" UUID DEFAULT gen_random_uuid(), nome TEXT,
    status BOOLEAN, teste BOOLEAN, mapeamento JSONB, "ultimoPayload" JSONB, "idAgente" BIGINT, "mensagemPadrao" TEXT
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Resposta_Rapidas" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    "contaId" UUID REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL,
    nome TEXT, atalho TEXT, texto TEXT, arquivo TEXT, "tipoMedia" TEXT
  );

  CREATE TABLE IF NOT EXISTS public."SAAS_Versao" (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    "versaoAtual" TEXT, "ultimaAtualizacao" TIMESTAMPTZ
  );

  RAISE NOTICE 'Tabelas criadas no formato novo.';
END$$;

-- =========================
-- CENÁRIO 2: MIGRAR - Tabelas existem (formato antigo) mas SAAS_Contas não existe
-- =========================
-- Executa migração: SAAS_Usuarios → SAAS_Contas, cria nova SAAS_Usuarios, migra dados, renomeia userId/idUsuario → contaId
-- Se SAAS_Contas já existir (ex: cenário VAZIO ou já migrado), os blocos abaixo fazem RETURN e não alteram nada.
DO $$
BEGIN
  IF to_regclass('public."SAAS_Contas"') IS NOT NULL THEN
    RAISE NOTICE 'Cenário AJUSTAR ou já migrado: SAAS_Contas existe. Pulando migração.';
    RETURN;
  END IF;
  IF to_regclass('public."SAAS_Usuarios"') IS NULL THEN
    RAISE EXCEPTION 'Para migrar: execute criar-tabelas.sql antes. SAAS_Usuarios não encontrada.';
  END IF;
  RAISE NOTICE 'Cenário MIGRAR: executando migração multi-usuários...';
END$$;

-- Drop FKs que referenciam SAAS_Usuarios (será renomeada para SAAS_Contas)
DO $$
DECLARE r RECORD;
BEGIN
  IF to_regclass('public."SAAS_Contas"') IS NOT NULL THEN RETURN; END IF;
  FOR r IN
    SELECT c.conname, t.relname AS tabela
    FROM pg_constraint c JOIN pg_class t ON t.oid = c.conrelid
    WHERE c.confrelid = 'public."SAAS_Usuarios"'::regclass
  LOOP
    EXECUTE format('ALTER TABLE public.%I DROP CONSTRAINT IF EXISTS %I', r.tabela, r.conname);
  END LOOP;
END$$;

DROP TRIGGER IF EXISTS trg_usuarios_data_validade ON public."SAAS_Usuarios";

DO $$ BEGIN
  IF to_regclass('public."SAAS_Contas"') IS NULL THEN
    ALTER TABLE public."SAAS_Usuarios" RENAME TO "SAAS_Contas";
  END IF;
END$$;

DO $$ BEGIN
  IF to_regclass('public."SAAS_Usuarios"') IS NULL THEN
    CREATE TABLE public."SAAS_Usuarios" (
      id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
      created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
      "contaId" UUID REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL,
      nome TEXT, "Email" TEXT, telefone TEXT, auth_user_id UUID UNIQUE,
      funcao TEXT NOT NULL DEFAULT 'admin' CHECK (funcao IN ('admin', 'membro')),
      super_admin BOOLEAN NOT NULL DEFAULT false
    );
    CREATE INDEX IF NOT EXISTS idx_usuarios_contaId ON public."SAAS_Usuarios"("contaId");
    CREATE INDEX IF NOT EXISTS idx_usuarios_auth_user_id ON public."SAAS_Usuarios"(auth_user_id);
  END IF;
END$$;

DO $$ BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_Contas' AND column_name='nome') THEN
    INSERT INTO public."SAAS_Usuarios" ("contaId", nome, "Email", telefone, auth_user_id, funcao)
    SELECT id, nome, "Email", telefone, auth_user_id, 'admin' FROM public."SAAS_Contas";
  END IF;
END$$;

DROP VIEW IF EXISTS public."vw_Usuarios_Com_Plano" CASCADE;
DROP VIEW IF EXISTS public."vw_Contas_Com_Plano" CASCADE;
DROP VIEW IF EXISTS public."vw_Planos_Usuarios_Count" CASCADE;
DROP VIEW IF EXISTS public."vw_Detalhes_Completo" CASCADE;
DROP VIEW IF EXISTS public."VW_SAAS_AgentesIA_Conversas" CASCADE;
DROP VIEW IF EXISTS public."vw_SAAS_Quadros_CRM" CASCADE;
DROP VIEW IF EXISTS public."VW_SAAS_Etapas_Quadros" CASCADE;
DROP POLICY IF EXISTS "select_meu_usuario" ON public."SAAS_Contas";
DROP POLICY IF EXISTS "update_meu_usuario" ON public."SAAS_Contas";
DROP POLICY IF EXISTS "select_disparos_do_usuario" ON public."SAAS_Disparos";

-- Adicionar coluna email (criador da conta) e popular a partir de "Email" antes de dropar (só se "Email" ainda existir)
ALTER TABLE public."SAAS_Contas" ADD COLUMN IF NOT EXISTS email TEXT;
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Contas' AND column_name = 'Email') THEN
    UPDATE public."SAAS_Contas" SET email = "Email" WHERE email IS NULL AND "Email" IS NOT NULL;
  END IF;
END$$;
ALTER TABLE public."SAAS_Contas" DROP COLUMN IF EXISTS nome;
ALTER TABLE public."SAAS_Contas" DROP COLUMN IF EXISTS "Email";
ALTER TABLE public."SAAS_Contas" DROP COLUMN IF EXISTS telefone;
ALTER TABLE public."SAAS_Contas" DROP COLUMN IF EXISTS auth_user_id;

DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Usuarios_plano_fkey') THEN
    ALTER TABLE public."SAAS_Contas" RENAME CONSTRAINT "SAAS_Usuarios_plano_fkey" TO "SAAS_Contas_plano_fkey";
  END IF;
END$$;

DO $$
BEGIN
  IF to_regclass('public."SAAS_Disparos"') IS NOT NULL AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_Disparos' AND column_name='userId') THEN
    ALTER TABLE public."SAAS_Disparos" RENAME COLUMN "userId" TO "contaId";
  END IF;
  IF to_regclass('public."SAAS_Quadros"') IS NOT NULL AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_Quadros' AND column_name='userId') THEN
    ALTER TABLE public."SAAS_Quadros" RENAME COLUMN "userId" TO "contaId";
  END IF;
  IF to_regclass('public."SAAS_Etapas_Quadros"') IS NOT NULL AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_Etapas_Quadros' AND column_name='userId') THEN
    ALTER TABLE public."SAAS_Etapas_Quadros" RENAME COLUMN "userId" TO "contaId";
  END IF;
  IF to_regclass('public."SAAS_AgentesIA"') IS NOT NULL AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_AgentesIA' AND column_name='userId') THEN
    ALTER TABLE public."SAAS_AgentesIA" RENAME COLUMN "userId" TO "contaId";
  END IF;
  IF to_regclass('public."SAAS_Conversas_Agentes"') IS NOT NULL AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_Conversas_Agentes' AND column_name='userId') THEN
    ALTER TABLE public."SAAS_Conversas_Agentes" RENAME COLUMN "userId" TO "contaId";
  END IF;
  IF to_regclass('public."SAAS_Mensagens"') IS NOT NULL AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_Mensagens' AND column_name='userId') THEN
    ALTER TABLE public."SAAS_Mensagens" RENAME COLUMN "userId" TO "contaId";
  END IF;
  IF to_regclass('public."SAAS_Webhook"') IS NOT NULL AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_Webhook' AND column_name='userId') THEN
    ALTER TABLE public."SAAS_Webhook" RENAME COLUMN "userId" TO "contaId";
  END IF;
  IF to_regclass('public."SAAS_Resposta_Rapidas"') IS NOT NULL AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_Resposta_Rapidas' AND column_name='userId') THEN
    ALTER TABLE public."SAAS_Resposta_Rapidas" RENAME COLUMN "userId" TO "contaId";
  END IF;
  IF to_regclass('public."SAAS_Conexões"') IS NOT NULL AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_Conexões' AND column_name='idUsuario') THEN
    ALTER TABLE public."SAAS_Conexões" RENAME COLUMN "idUsuario" TO "contaId";
  END IF;
  IF to_regclass('public."SAAS_Listas"') IS NOT NULL AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_Listas' AND column_name='idUsuario') THEN
    ALTER TABLE public."SAAS_Listas" RENAME COLUMN "idUsuario" TO "contaId";
  END IF;
  IF to_regclass('public."SAAS_Contatos"') IS NOT NULL AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_Contatos' AND column_name='idUsuario') THEN
    ALTER TABLE public."SAAS_Contatos" RENAME COLUMN "idUsuario" TO "contaId";
  END IF;
  IF to_regclass('public."SAAS_Grupos"') IS NOT NULL AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_Grupos' AND column_name='idUsuario') THEN
    ALTER TABLE public."SAAS_Grupos" RENAME COLUMN "idUsuario" TO "contaId";
  END IF;
END$$;

-- Normalizar colunas com camelCase em SAAS_Disparos
DO $$
BEGIN
  IF to_regclass('public."SAAS_Disparos"') IS NULL THEN RETURN; END IF;
  IF EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema='public' AND table_name='SAAS_Disparos' AND column_name='intervalomin'
  ) AND NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema='public' AND table_name='SAAS_Disparos' AND column_name='intervaloMin'
  ) THEN
    ALTER TABLE public."SAAS_Disparos" RENAME COLUMN intervalomin TO "intervaloMin";
  END IF;
  IF EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema='public' AND table_name='SAAS_Disparos' AND column_name='intervalomax'
  ) AND NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema='public' AND table_name='SAAS_Disparos' AND column_name='intervaloMax'
  ) THEN
    ALTER TABLE public."SAAS_Disparos" RENAME COLUMN intervalomax TO "intervaloMax";
  END IF;
END$$;

DO $$
BEGIN
  IF to_regclass('public."SAAS_Conexões"') IS NOT NULL
     AND NOT EXISTS (
       SELECT 1
       FROM information_schema.columns
       WHERE table_schema = 'public'
         AND table_name = 'SAAS_Conexões'
         AND column_name = 'idAgente'
     ) THEN
    ALTER TABLE public."SAAS_Conexões" ADD COLUMN "idAgente" BIGINT;
  END IF;
END$$;

-- Dados inválidos: detalhes/disparos com conta inexistente em SAAS_Contas, ou detalhe sem disparo correspondente
DO $$
BEGIN
  IF to_regclass('public."SAAS_Contas"') IS NULL OR to_regclass('public."SAAS_Disparos"') IS NULL THEN
    RETURN;
  END IF;
  IF to_regclass('public."SAAS_Detalhes_Disparos"') IS NOT NULL THEN
    DELETE FROM public."SAAS_Detalhes_Disparos" d
    WHERE d."idDisparo" IS NULL
      OR NOT EXISTS (SELECT 1 FROM public."SAAS_Disparos" h WHERE h.id = d."idDisparo");
    IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Disparos' AND column_name = 'contaId') THEN
      DELETE FROM public."SAAS_Detalhes_Disparos" d
      WHERE d."idDisparo" IN (
        SELECT h.id FROM public."SAAS_Disparos" h
        WHERE h."contaId" IS NOT NULL
          AND NOT EXISTS (SELECT 1 FROM public."SAAS_Contas" c WHERE c.id = h."contaId")
      );
    ELSIF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Disparos' AND column_name = 'userId') THEN
      DELETE FROM public."SAAS_Detalhes_Disparos" d
      WHERE d."idDisparo" IN (
        SELECT h.id FROM public."SAAS_Disparos" h
        WHERE h."userId" IS NOT NULL
          AND NOT EXISTS (SELECT 1 FROM public."SAAS_Contas" c WHERE c.id = h."userId")
      );
    END IF;
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Disparos' AND column_name = 'contaId') THEN
    DELETE FROM public."SAAS_Disparos" d
    WHERE d."contaId" IS NOT NULL
      AND NOT EXISTS (SELECT 1 FROM public."SAAS_Contas" c WHERE c.id = d."contaId");
  ELSIF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Disparos' AND column_name = 'userId') THEN
    DELETE FROM public."SAAS_Disparos" d
    WHERE d."userId" IS NOT NULL
      AND NOT EXISTS (SELECT 1 FROM public."SAAS_Contas" c WHERE c.id = d."userId");
  END IF;
END$$;

