DROP INDEX IF EXISTS public.saas_mensagens_conversa_evolution_unique;
DO $$
BEGIN
  IF to_regclass('public."SAAS_Mensagens"') IS NULL THEN
    RETURN;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Mensagens' AND column_name = 'conversaId') THEN
    RETURN;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Mensagens' AND column_name = 'messageEvolutionId') THEN
    RETURN;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Mensagens' AND column_name = 'id') THEN
    RETURN;
  END IF;
  DELETE FROM public."SAAS_Mensagens" m
  USING (
    SELECT id,
      row_number() OVER (
        PARTITION BY "conversaId", "messageEvolutionId"
        ORDER BY id
      ) AS rn
    FROM public."SAAS_Mensagens"
    WHERE "messageEvolutionId" IS NOT NULL
      AND "messageEvolutionId" <> ''
  ) t
  WHERE m.id = t.id
    AND t.rn > 1;
END$$;
