-- Padrão: coluna de data em snake_case (alinhado ao restante do schema)
DO $$
BEGIN
  IF to_regclass('public."SAAS_Mensagens"') IS NULL THEN RETURN; END IF;
  IF EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND LOWER(table_name) = 'saas_mensagens' AND column_name = 'createdat'
  ) AND NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND LOWER(table_name) = 'saas_mensagens' AND column_name = 'created_at'
  ) THEN
    ALTER TABLE public."SAAS_Mensagens" RENAME COLUMN createdat TO created_at;
  END IF;
END$$;
-- Após RENAME createdat → created_at: regrava funções de trigger ligadas a SAAS_Mensagens que ainda usam NEW/OLD.createdat (evita 42703 no INSERT).
DO $$
DECLARE
  r RECORD;
  d text;
  d2 text;
BEGIN
  IF to_regclass('public."SAAS_Mensagens"') IS NULL THEN RETURN; END IF;
  FOR r IN
    SELECT DISTINCT p.oid AS proid, p.proname
    FROM pg_trigger t
    JOIN pg_class c ON c.oid = t.tgrelid
    JOIN pg_namespace n ON n.oid = c.relnamespace
    JOIN pg_proc p ON p.oid = t.tgfoid
    WHERE n.nspname = 'public'
      AND c.relname = 'SAAS_Mensagens'
      AND NOT t.tgisinternal
  LOOP
    d := pg_get_functiondef(r.proid);
    IF d IS NULL THEN CONTINUE; END IF;
    IF position('createdat' IN lower(d)) = 0 THEN CONTINUE; END IF;
    d2 := replace(d, 'NEW."createdat"', 'NEW.created_at');
    d2 := replace(d2, 'OLD."createdat"', 'OLD.created_at');
    d2 := replace(d2, 'NEW.createdat', 'NEW.created_at');
    d2 := replace(d2, 'OLD.createdat', 'OLD.created_at');
    IF d2 IS DISTINCT FROM d THEN
      BEGIN
        EXECUTE d2;
      EXCEPTION WHEN OTHERS THEN
        RAISE NOTICE 'Reparo trigger SAAS_Mensagens: não foi possível regravar função %: %', r.proname, SQLERRM;
      END;
    END IF;
  END LOOP;
END$$;
