-- Índice único: uq_SAAS_Usuarios_Email
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_indexes WHERE schemaname = 'public' AND tablename = 'SAAS_Usuarios' AND LOWER(indexname) = LOWER('uq_SAAS_Usuarios_Email')
  ) AND NOT EXISTS (
    SELECT 1 FROM pg_index i JOIN pg_class t ON t.oid = i.indrelid JOIN pg_class idx ON idx.oid = i.indexrelid JOIN pg_namespace n ON n.oid = t.relnamespace JOIN pg_attribute a ON a.attrelid = t.oid AND a.attnum = ANY(i.indkey)
    WHERE n.nspname = 'public' AND t.relname = 'SAAS_Usuarios' AND i.indisunique = true AND a.attname = 'Email' AND array_length(i.indkey, 1) = 1
  ) THEN
    BEGIN
      CREATE UNIQUE INDEX uq_SAAS_Usuarios_Email ON public."SAAS_Usuarios"("Email");
    EXCEPTION WHEN OTHERS THEN RAISE NOTICE 'Erro ao criar índice uq_SAAS_Usuarios_Email: %', SQLERRM; END;
  END IF;
END$$;

-- FKs: ON DELETE CASCADE: (1) Conexão→Conversas, (2) Conversa→Mensagens, (3) Conexão→Detalhes_Disparos, (4) Contato→Conversas (mensagens em cascata via conversa). Restante SET NULL onde aplicável.
DO $$
BEGIN
  -- (1) SAAS_Conversas_Agentes.idConexao → SAAS_Conexões: ON DELETE CASCADE
  IF to_regclass('public."SAAS_Conversas_Agentes"') IS NOT NULL AND to_regclass('public."SAAS_Conexões"') IS NOT NULL THEN
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Conversas_Agentes_idConexao_fkey') THEN
      ALTER TABLE public."SAAS_Conversas_Agentes" DROP CONSTRAINT "SAAS_Conversas_Agentes_idConexao_fkey";
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Conversas_Agentes_idConexao_fkey') THEN
      ALTER TABLE public."SAAS_Conversas_Agentes"
        ADD CONSTRAINT "SAAS_Conversas_Agentes_idConexao_fkey"
        FOREIGN KEY ("idConexao") REFERENCES public."SAAS_Conexões"(id) ON UPDATE CASCADE ON DELETE CASCADE;
    END IF;
  END IF;
  -- SAAS_Conversas_Agentes.contatoId → SAAS_Contatos: ON DELETE CASCADE (exclui conversa e, em cascata, SAAS_Mensagens)
  IF to_regclass('public."SAAS_Conversas_Agentes"') IS NOT NULL AND to_regclass('public."SAAS_Contatos"') IS NOT NULL THEN
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Conversas_Agentes_contatoId_fkey') THEN
      ALTER TABLE public."SAAS_Conversas_Agentes" DROP CONSTRAINT "SAAS_Conversas_Agentes_contatoId_fkey";
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Conversas_Agentes_contatoId_fkey') THEN
      ALTER TABLE public."SAAS_Conversas_Agentes"
        ADD CONSTRAINT "SAAS_Conversas_Agentes_contatoId_fkey"
        FOREIGN KEY ("contatoId") REFERENCES public."SAAS_Contatos"(id) ON UPDATE CASCADE ON DELETE CASCADE;
    END IF;
  END IF;
  -- (2) SAAS_Mensagens.conversaId → SAAS_Conversas_Agentes: ON DELETE CASCADE
  IF to_regclass('public."SAAS_Mensagens"') IS NOT NULL AND to_regclass('public."SAAS_Conversas_Agentes"') IS NOT NULL THEN
    -- Remove mensagens órfãs para permitir recriar FK de conversaId
    DELETE FROM public."SAAS_Mensagens" m
    WHERE m."conversaId" IS NOT NULL
      AND NOT EXISTS (
        SELECT 1
        FROM public."SAAS_Conversas_Agentes" c
        WHERE c.id = m."conversaId"
      );
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Mensagens_conversaId_fkey') THEN
      ALTER TABLE public."SAAS_Mensagens" DROP CONSTRAINT "SAAS_Mensagens_conversaId_fkey";
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Mensagens_conversaId_fkey') THEN
      ALTER TABLE public."SAAS_Mensagens"
        ADD CONSTRAINT "SAAS_Mensagens_conversaId_fkey"
        FOREIGN KEY ("conversaId") REFERENCES public."SAAS_Conversas_Agentes"(id) ON UPDATE CASCADE ON DELETE CASCADE;
    END IF;
  END IF;
  -- Remover FK SAAS_Mensagens.conexaoId → SAAS_Conexões (evita SET NULL ao excluir conexão; mensagens já são excluídas via CASCADE em conversaId)
  IF to_regclass('public."SAAS_Mensagens"') IS NOT NULL THEN
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Mensagens_conexaoId_fkey') THEN
      ALTER TABLE public."SAAS_Mensagens" DROP CONSTRAINT "SAAS_Mensagens_conexaoId_fkey";
    END IF;
    ALTER TABLE public."SAAS_Mensagens" ALTER COLUMN "conexaoId" DROP NOT NULL;
  END IF;
  -- (3) SAAS_Detalhes_Disparos.idConexao → SAAS_Conexões: ON DELETE CASCADE (ao excluir conexão, exclui linhas de disparo dessa conexão)
  IF to_regclass('public."SAAS_Detalhes_Disparos"') IS NOT NULL AND to_regclass('public."SAAS_Conexões"') IS NOT NULL THEN
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Detalhes_Disparos_idConexao_fkey') THEN
      ALTER TABLE public."SAAS_Detalhes_Disparos" DROP CONSTRAINT "SAAS_Detalhes_Disparos_idConexao_fkey";
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Detalhes_Disparos_idConexao_fkey') THEN
      ALTER TABLE public."SAAS_Detalhes_Disparos"
        ADD CONSTRAINT "SAAS_Detalhes_Disparos_idConexao_fkey"
        FOREIGN KEY ("idConexao") REFERENCES public."SAAS_Conexões"(id) ON UPDATE CASCADE ON DELETE CASCADE;
    END IF;
  END IF;
  -- SAAS_Detalhes_Disparos.idDisparo → SAAS_Disparos: ON DELETE CASCADE
  IF to_regclass('public."SAAS_Detalhes_Disparos"') IS NOT NULL AND to_regclass('public."SAAS_Disparos"') IS NOT NULL THEN
    DELETE FROM public."SAAS_Detalhes_Disparos" d
    WHERE d."idDisparo" IS NOT NULL
      AND NOT EXISTS (SELECT 1 FROM public."SAAS_Disparos" h WHERE h.id = d."idDisparo");
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Detalhes_Disparos_idDisparo_fkey') THEN
      ALTER TABLE public."SAAS_Detalhes_Disparos" DROP CONSTRAINT "SAAS_Detalhes_Disparos_idDisparo_fkey";
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Detalhes_Disparos_idDisparo_fkey') THEN
      ALTER TABLE public."SAAS_Detalhes_Disparos"
        ADD CONSTRAINT "SAAS_Detalhes_Disparos_idDisparo_fkey"
        FOREIGN KEY ("idDisparo") REFERENCES public."SAAS_Disparos"(id) ON UPDATE CASCADE ON DELETE CASCADE;
    END IF;
  END IF;
  -- SAAS_Detalhes_Disparos.idContato → SAAS_Contatos: ON DELETE SET NULL
  IF to_regclass('public."SAAS_Detalhes_Disparos"') IS NOT NULL AND to_regclass('public."SAAS_Contatos"') IS NOT NULL THEN
    DELETE FROM public."SAAS_Detalhes_Disparos" d
    WHERE d."idContato" IS NOT NULL
      AND NOT EXISTS (SELECT 1 FROM public."SAAS_Contatos" c WHERE c.id = d."idContato");
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Detalhes_Disparos_idContato_fkey') THEN
      ALTER TABLE public."SAAS_Detalhes_Disparos" DROP CONSTRAINT "SAAS_Detalhes_Disparos_idContato_fkey";
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Detalhes_Disparos_idContato_fkey') THEN
      ALTER TABLE public."SAAS_Detalhes_Disparos"
        ADD CONSTRAINT "SAAS_Detalhes_Disparos_idContato_fkey"
        FOREIGN KEY ("idContato") REFERENCES public."SAAS_Contatos"(id) ON UPDATE CASCADE ON DELETE SET NULL;
    END IF;
  END IF;
  -- SAAS_Etapas_Quadros.quadroId → SAAS_Quadros: ON DELETE CASCADE
  IF to_regclass('public."SAAS_Etapas_Quadros"') IS NOT NULL AND to_regclass('public."SAAS_Quadros"') IS NOT NULL THEN
    DELETE FROM public."SAAS_Etapas_Quadros" e
    WHERE e."quadroId" IS NOT NULL
      AND NOT EXISTS (SELECT 1 FROM public."SAAS_Quadros" q WHERE q.id = e."quadroId");
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Etapas_Quadros_quadroId_fkey') THEN
      ALTER TABLE public."SAAS_Etapas_Quadros" DROP CONSTRAINT "SAAS_Etapas_Quadros_quadroId_fkey";
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Etapas_Quadros_quadroId_fkey') THEN
      ALTER TABLE public."SAAS_Etapas_Quadros"
        ADD CONSTRAINT "SAAS_Etapas_Quadros_quadroId_fkey"
        FOREIGN KEY ("quadroId") REFERENCES public."SAAS_Quadros"(id) ON UPDATE CASCADE ON DELETE CASCADE;
    END IF;
  END IF;
  -- SAAS_Cards_Quadros.contatoId → SAAS_Contatos: ON DELETE SET NULL
  IF to_regclass('public."SAAS_Cards_Quadros"') IS NOT NULL AND to_regclass('public."SAAS_Contatos"') IS NOT NULL THEN
    DELETE FROM public."SAAS_Cards_Quadros" cq
    WHERE cq."contatoId" IS NOT NULL
      AND NOT EXISTS (SELECT 1 FROM public."SAAS_Contatos" c WHERE c.id = cq."contatoId");
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Cards_Quadros_contatoId_fkey') THEN
      ALTER TABLE public."SAAS_Cards_Quadros" DROP CONSTRAINT "SAAS_Cards_Quadros_contatoId_fkey";
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Cards_Quadros_contatoId_fkey') THEN
      ALTER TABLE public."SAAS_Cards_Quadros"
        ADD CONSTRAINT "SAAS_Cards_Quadros_contatoId_fkey"
        FOREIGN KEY ("contatoId") REFERENCES public."SAAS_Contatos"(id) ON UPDATE CASCADE ON DELETE SET NULL;
    END IF;
  END IF;
  -- SAAS_Cards_Quadros.etapaQuadroId → SAAS_Etapas_Quadros: ON DELETE CASCADE
  IF to_regclass('public."SAAS_Cards_Quadros"') IS NOT NULL AND to_regclass('public."SAAS_Etapas_Quadros"') IS NOT NULL THEN
    DELETE FROM public."SAAS_Cards_Quadros" cq
    WHERE cq."etapaQuadroId" IS NOT NULL
      AND NOT EXISTS (SELECT 1 FROM public."SAAS_Etapas_Quadros" e WHERE e.id = cq."etapaQuadroId");
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Cards_Quadros_etapaQuadroId_fkey') THEN
      ALTER TABLE public."SAAS_Cards_Quadros" DROP CONSTRAINT "SAAS_Cards_Quadros_etapaQuadroId_fkey";
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Cards_Quadros_etapaQuadroId_fkey') THEN
      ALTER TABLE public."SAAS_Cards_Quadros"
        ADD CONSTRAINT "SAAS_Cards_Quadros_etapaQuadroId_fkey"
        FOREIGN KEY ("etapaQuadroId") REFERENCES public."SAAS_Etapas_Quadros"(id) ON UPDATE CASCADE ON DELETE CASCADE;
    END IF;
  END IF;
  -- SAAS_Usuarios.contaId → SAAS_Contas: ON DELETE SET NULL (não CASCADE)
  IF to_regclass('public."SAAS_Usuarios"') IS NOT NULL AND to_regclass('public."SAAS_Contas"') IS NOT NULL THEN
    ALTER TABLE public."SAAS_Usuarios" ALTER COLUMN "contaId" DROP NOT NULL;
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Usuarios_contaId_fkey') THEN
      ALTER TABLE public."SAAS_Usuarios" DROP CONSTRAINT "SAAS_Usuarios_contaId_fkey";
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Usuarios_contaId_fkey') THEN
      ALTER TABLE public."SAAS_Usuarios" ADD CONSTRAINT "SAAS_Usuarios_contaId_fkey" FOREIGN KEY ("contaId") REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL;
    END IF;
  END IF;
  -- SAAS_Conexões.idAgente → SAAS_AgentesIA: ON DELETE SET NULL (excluir agente NÃO exclui conexão)
  IF to_regclass('public."SAAS_Conexões"') IS NOT NULL AND to_regclass('public."SAAS_AgentesIA"') IS NOT NULL AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Conexões' AND column_name = 'idAgente') THEN
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Conexões_idAgente_fkey') THEN
      ALTER TABLE public."SAAS_Conexões" DROP CONSTRAINT "SAAS_Conexões_idAgente_fkey";
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Conexões_idAgente_fkey') THEN
      ALTER TABLE public."SAAS_Conexões"
        ADD CONSTRAINT "SAAS_Conexões_idAgente_fkey"
        FOREIGN KEY ("idAgente") REFERENCES public."SAAS_AgentesIA"(id) ON UPDATE CASCADE ON DELETE SET NULL;
    END IF;
  END IF;
  -- SAAS_AgentesIA.conexaoId → SAAS_Conexões: ON DELETE SET NULL (excluir conexão NÃO exclui agente)
  IF to_regclass('public."SAAS_AgentesIA"') IS NOT NULL
     AND to_regclass('public."SAAS_Conexões"') IS NOT NULL
     AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_AgentesIA' AND column_name = 'conexaoId') THEN
    -- Limpa órfãos para permitir recriar a FK sem erro
    DELETE FROM public."SAAS_AgentesIA" a
    WHERE a."conexaoId" IS NOT NULL
      AND NOT EXISTS (
        SELECT 1
        FROM public."SAAS_Conexões" c
        WHERE c.id = a."conexaoId"
      );
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_AgentesIA_conexaoId_fkey') THEN
      ALTER TABLE public."SAAS_AgentesIA" DROP CONSTRAINT "SAAS_AgentesIA_conexaoId_fkey";
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_AgentesIA_conexaoId_fkey') THEN
      ALTER TABLE public."SAAS_AgentesIA"
        ADD CONSTRAINT "SAAS_AgentesIA_conexaoId_fkey"
        FOREIGN KEY ("conexaoId") REFERENCES public."SAAS_Conexões"(id) ON UPDATE CASCADE ON DELETE SET NULL;
    END IF;
  END IF;
  -- SAAS_Webhook.conexaoId → SAAS_Conexões: ON DELETE SET NULL
  IF to_regclass('public."SAAS_Webhook"') IS NOT NULL
     AND to_regclass('public."SAAS_Conexões"') IS NOT NULL
     AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Webhook' AND column_name = 'conexaoId') THEN
    DELETE FROM public."SAAS_Webhook" w
    WHERE w."conexaoId" IS NOT NULL
      AND NOT EXISTS (SELECT 1 FROM public."SAAS_Conexões" c WHERE c.id = w."conexaoId");
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Webhook_conexaoId_fkey') THEN
      ALTER TABLE public."SAAS_Webhook" DROP CONSTRAINT "SAAS_Webhook_conexaoId_fkey";
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Webhook_conexaoId_fkey') THEN
      ALTER TABLE public."SAAS_Webhook"
        ADD CONSTRAINT "SAAS_Webhook_conexaoId_fkey"
        FOREIGN KEY ("conexaoId") REFERENCES public."SAAS_Conexões"(id) ON UPDATE CASCADE ON DELETE SET NULL;
    END IF;
  END IF;
  -- SAAS_Webhook.idAgente → SAAS_AgentesIA: ON DELETE SET NULL
  IF to_regclass('public."SAAS_Webhook"') IS NOT NULL
     AND to_regclass('public."SAAS_AgentesIA"') IS NOT NULL
     AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Webhook' AND column_name = 'idAgente') THEN
    DELETE FROM public."SAAS_Webhook" w
    WHERE w."idAgente" IS NOT NULL
      AND NOT EXISTS (SELECT 1 FROM public."SAAS_AgentesIA" a WHERE a.id = w."idAgente");
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Webhook_idAgente_fkey') THEN
      ALTER TABLE public."SAAS_Webhook" DROP CONSTRAINT "SAAS_Webhook_idAgente_fkey";
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Webhook_idAgente_fkey') THEN
      ALTER TABLE public."SAAS_Webhook"
        ADD CONSTRAINT "SAAS_Webhook_idAgente_fkey"
        FOREIGN KEY ("idAgente") REFERENCES public."SAAS_AgentesIA"(id) ON UPDATE CASCADE ON DELETE SET NULL;
    END IF;
  END IF;
END$$;

-- Ao excluir conexão: excluir também os disparos (cabeçalho) que usam essa conexão em idConexoes
CREATE OR REPLACE FUNCTION public.f_delete_disparos_on_delete_conexao()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  -- Primeiro exclui detalhes dos disparos que referenciam esta conexão; depois exclui os disparos
  DELETE FROM public."SAAS_Detalhes_Disparos"
  WHERE "idDisparo" IN (SELECT id FROM public."SAAS_Disparos" WHERE OLD.id = ANY("idConexoes"));
  DELETE FROM public."SAAS_Disparos" WHERE OLD.id = ANY("idConexoes");
  RETURN OLD;
END;
$$;
DROP TRIGGER IF EXISTS trg_delete_disparos_on_delete_conexao ON public."SAAS_Conexões";
CREATE TRIGGER trg_delete_disparos_on_delete_conexao
  AFTER DELETE ON public."SAAS_Conexões"
  FOR EACH ROW EXECUTE FUNCTION public.f_delete_disparos_on_delete_conexao();

