-- CENÁRIO 3: AJUSTES COMUNS (sempre executados)
-- =========================
-- Funções helper, RLS, views, triggers, grants. Idempotentes - podem rodar sempre.

-- Criar SAAS_Webhook se não existir (mesmo quando SAAS_Contas ainda não existe — ex.: usuário sem tabela contas)
DO $$
BEGIN
  IF to_regclass('public."SAAS_Webhook"') IS NOT NULL THEN RETURN; END IF;
  IF to_regclass('public."SAAS_Contas"') IS NOT NULL THEN
    CREATE TABLE public."SAAS_Webhook" (
      id BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY,
      created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
      "contaId" UUID REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL,
      "conexaoId" BIGINT, "tokenWebhook" UUID DEFAULT gen_random_uuid(), nome TEXT,
      status BOOLEAN, teste BOOLEAN, mapeamento JSONB, "ultimoPayload" JSONB, "idAgente" BIGINT, "mensagemPadrao" TEXT
    );
  ELSE
    CREATE TABLE public."SAAS_Webhook" (
      id BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY,
      created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
      "contaId" UUID,
      "conexaoId" BIGINT, "tokenWebhook" UUID DEFAULT gen_random_uuid(), nome TEXT,
      status BOOLEAN, teste BOOLEAN, mapeamento JSONB, "ultimoPayload" JSONB, "idAgente" BIGINT, "mensagemPadrao" TEXT
    );
  END IF;
  CREATE INDEX IF NOT EXISTS idx_webhook_contaId ON public."SAAS_Webhook"("contaId");
END$$;
-- Adicionar FK contaId → SAAS_Contas quando a tabela contas existir (para webhook criado sem FK)
DO $$
BEGIN
  IF to_regclass('public."SAAS_Webhook"') IS NULL OR to_regclass('public."SAAS_Contas"') IS NULL THEN RETURN; END IF;
  IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'SAAS_Webhook_contaId_fkey') THEN RETURN; END IF;
  ALTER TABLE public."SAAS_Webhook" ADD CONSTRAINT "SAAS_Webhook_contaId_fkey"
    FOREIGN KEY ("contaId") REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE SET NULL;
END$$;

-- Coluna email em SAAS_Contas (email do usuário criador da conta)
DO $$
BEGIN
  IF to_regclass('public."SAAS_Contas"') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Contas' AND column_name = 'email') THEN
    ALTER TABLE public."SAAS_Contas" ADD COLUMN email TEXT;
    UPDATE public."SAAS_Contas" c SET email = (SELECT u."Email" FROM public."SAAS_Usuarios" u WHERE u."contaId" = c.id AND u.funcao = 'admin' ORDER BY u.created_at LIMIT 1) WHERE c.email IS NULL;
  END IF;
END$$;

-- Coluna tokens: alterar BIGINT para NUMERIC quando já existir (permite valores decimais)
DO $$
BEGIN
  IF to_regclass('public."SAAS_Contas"') IS NOT NULL AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Contas' AND column_name = 'tokens' AND data_type = 'bigint') THEN
    ALTER TABLE public."SAAS_Contas" ALTER COLUMN tokens TYPE NUMERIC USING tokens::numeric;
  END IF;
END$$;

-- p_conta_id = contaId (multi-tenant: quem pode acessar a conta)
CREATE OR REPLACE FUNCTION public.can_access_conta(p_conta_id uuid)
RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER AS $$
  SELECT EXISTS (SELECT 1 FROM public."SAAS_Usuarios" u WHERE u."contaId" = p_conta_id AND u.auth_user_id = auth.uid());
$$;

-- p_conta_id = contaId
CREATE OR REPLACE FUNCTION public.is_admin(p_conta_id uuid)
RETURNS boolean LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path = public AS $$
BEGIN
  RETURN EXISTS (SELECT 1 FROM public."SAAS_Usuarios" u WHERE u."contaId" = p_conta_id AND u.auth_user_id = auth.uid() AND u.funcao = 'admin');
END;
$$;

CREATE OR REPLACE FUNCTION public.is_owner(p_user_id uuid)
RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER AS $$ SELECT public.can_access_conta(p_user_id); $$;

-- Retorna os contaIds em que o usuário atual está vinculado (evita recursão no RLS de SAAS_Usuarios)
CREATE OR REPLACE FUNCTION public.get_conta_ids_usuario()
RETURNS uuid[] LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path = public AS $$
DECLARE arr uuid[];
BEGIN
  PERFORM set_config('row_security', 'off', true);
  SELECT array_agg("contaId") INTO arr FROM public."SAAS_Usuarios" WHERE auth_user_id = auth.uid();
  RETURN COALESCE(arr, ARRAY[]::uuid[]);
END;
$$;

-- Super admin do sistema: usuário com super_admin = true tem acesso a tudo (apenas service_role pode editar a coluna)
CREATE OR REPLACE FUNCTION public.is_super_admin()
RETURNS boolean LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path = public AS $$
BEGIN
  PERFORM set_config('row_security', 'off', true);
  RETURN EXISTS (SELECT 1 FROM public."SAAS_Usuarios" WHERE auth_user_id = auth.uid() AND super_admin = true);
END;
$$;

-- Coluna super_admin em SAAS_Usuarios (para instalações já existentes)
DO $$
BEGIN
  IF to_regclass('public."SAAS_Usuarios"') IS NOT NULL AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Usuarios' AND column_name = 'super_admin') THEN
    ALTER TABLE public."SAAS_Usuarios" ADD COLUMN super_admin BOOLEAN NOT NULL DEFAULT false;
  END IF;
END$$;

-- Promover o usuário logado a primeiro super admin. Só funciona se não existir NENHUM super admin no sistema.
CREATE OR REPLACE FUNCTION public.promover_primeiro_super_admin()
RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE
  v_count_super integer;
  v_usuario_id uuid;
BEGIN
  SELECT count(*) INTO v_count_super FROM public."SAAS_Usuarios" WHERE super_admin = true;
  IF v_count_super > 0 THEN
    RETURN jsonb_build_object('ok', false, 'erro', 'Já existe super admin no sistema.');
  END IF;

  UPDATE public."SAAS_Usuarios"
  SET super_admin = true
  WHERE auth_user_id = auth.uid()
  RETURNING id INTO v_usuario_id;

  IF v_usuario_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'erro', 'Usuário não encontrado em SAAS_Usuarios.');
  END IF;

  RETURN jsonb_build_object('ok', true);
END;
$$;

