-- Retorna true se o usuário atual pode ver a conversa (atendente vinculado OU admin da conta).
-- p_conta_id = contaId. Super_admin vê apenas conversas das contas em que está vinculado.
CREATE OR REPLACE FUNCTION public.can_see_conversa(p_conta_id uuid, p_atendente uuid)
RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public AS $$
  SELECT public.is_admin(p_conta_id)
    OR (p_atendente IS NULL AND public.can_access_conta(p_conta_id))
    OR (p_atendente IS NOT NULL AND EXISTS (SELECT 1 FROM public."SAAS_Usuarios" u WHERE u.auth_user_id = auth.uid() AND u.id = p_atendente));
$$;

-- Compatibilidade com ambientes que já usam can_see_mensagem nas policies de SAAS_Mensagens.
-- Importante para Realtime: não usar set_config('row_security','off',...) aqui.
CREATE OR REPLACE FUNCTION public.can_see_mensagem(p_conta_id uuid, p_conversa_id bigint, p_conexao_id bigint)
RETURNS boolean LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path = public AS $$
DECLARE
  v_conv_conta_id uuid;
  v_conv_atendente uuid;
BEGIN
  SELECT c."contaId", c.atendente
    INTO v_conv_conta_id, v_conv_atendente
    FROM public."SAAS_Conversas_Agentes" c
   WHERE c.id = p_conversa_id;

  IF v_conv_conta_id IS NULL THEN
    RETURN false;
  END IF;

  -- Regra principal: mesma regra de visualização da conversa.
  IF public.can_see_conversa(v_conv_conta_id, v_conv_atendente) THEN
    RETURN true;
  END IF;

  -- Regra compatível com políticas antigas baseadas em conta+conexão.
  IF p_conexao_id IS NOT NULL
     AND public.can_access_conta(p_conta_id)
     AND EXISTS (
       SELECT 1
         FROM public."SAAS_Conexões" co
        WHERE co.id = p_conexao_id
          AND co."contaId" = p_conta_id
     ) THEN
    RETURN true;
  END IF;

  RETURN false;
END;
$$;

-- Transferência de atendente: o UPDATE direto falha no RLS para o membro atual (WITH CHECK exige ver a conversa já com o novo atendente).
-- Esta função valida admin da conta OU atendente atual = usuário logado e atualiza atendente.
CREATE OR REPLACE FUNCTION public.f_transferir_atendimento_conversa(
  p_conversa_id bigint,
  p_novo_atendente uuid
)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_conta uuid;
  v_atendente uuid;
BEGIN
  IF p_conversa_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'erro', 'conversa_id obrigatório');
  END IF;

  SELECT c."contaId", c.atendente INTO v_conta, v_atendente
  FROM public."SAAS_Conversas_Agentes" c
  WHERE c.id = p_conversa_id
  FOR UPDATE;

  IF v_conta IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'erro', 'Conversa não encontrada');
  END IF;

  IF NOT (
    public.is_admin(v_conta)
    OR (
      v_atendente IS NOT NULL
      AND EXISTS (
        SELECT 1 FROM public."SAAS_Usuarios" u
        WHERE u.id = v_atendente AND u.auth_user_id = auth.uid()
      )
    )
  ) THEN
    RETURN jsonb_build_object('ok', false, 'erro', 'Sem permissão para transferir este atendimento');
  END IF;

  IF p_novo_atendente IS NULL THEN
    IF NOT public.is_admin(v_conta) THEN
      RETURN jsonb_build_object('ok', false, 'erro', 'Apenas administradores podem remover a atribuição');
    END IF;
  ELSE
    IF NOT EXISTS (
      SELECT 1 FROM public."SAAS_Usuarios" u
      WHERE u.id = p_novo_atendente AND u."contaId" = v_conta
    ) THEN
      RETURN jsonb_build_object('ok', false, 'erro', 'Usuário não pertence a esta conta');
    END IF;
  END IF;

  UPDATE public."SAAS_Conversas_Agentes"
  SET atendente = p_novo_atendente
  WHERE id = p_conversa_id;

  RETURN jsonb_build_object('ok', true);
END;
$$;

GRANT EXECUTE ON FUNCTION public.f_transferir_atendimento_conversa(bigint, uuid) TO authenticated;
GRANT EXECUTE ON FUNCTION public.f_transferir_atendimento_conversa(bigint, uuid) TO service_role;

-- =========================
-- Funções de apoio (templates de mensagem e agendamento de disparos)
-- =========================
CREATE OR REPLACE FUNCTION public.f_saudacao(p_ts timestamptz)
RETURNS TEXT LANGUAGE sql IMMUTABLE AS $$
  SELECT CASE
           WHEN (p_ts AT TIME ZONE 'America/Sao_Paulo')::time BETWEEN TIME '05:00' AND TIME '11:59' THEN 'bom dia'
           WHEN (p_ts AT TIME ZONE 'America/Sao_Paulo')::time BETWEEN TIME '12:00' AND TIME '17:59' THEN 'boa tarde'
           ELSE 'boa noite'
         END
$$;

CREATE OR REPLACE FUNCTION public.f_next_valid_time(
  p_ts    timestamptz,
  p_start time,
  p_end   time,
  p_days  integer[]
) RETURNS timestamptz LANGUAGE plpgsql STABLE AS $$
DECLARE v_local timestamp;
BEGIN
  LOOP
    v_local := p_ts AT TIME ZONE 'America/Sao_Paulo';
    IF v_local::time < p_start THEN
      v_local := date_trunc('day', v_local) + p_start;
    ELSIF v_local::time > p_end THEN
      v_local := date_trunc('day', v_local + interval '1 day') + p_start;
    END IF;

    IF p_days IS NULL OR array_length(p_days,1) IS NULL
       OR extract(isodow FROM v_local) = ANY(p_days)
    THEN
      RETURN v_local AT TIME ZONE 'America/Sao_Paulo';
    END IF;

    v_local := date_trunc('day', v_local + interval '1 day') + p_start;
    p_ts    := v_local AT TIME ZONE 'America/Sao_Paulo';
  END LOOP;
END
$$;

CREATE OR REPLACE FUNCTION public.f_render_message(
  p_template TEXT, p_nome TEXT, p_attrs JSONB, p_send_ts timestamptz
) RETURNS TEXT LANGUAGE plpgsql IMMUTABLE AS $$
DECLARE v_msg TEXT := COALESCE(p_template,''); v_token TEXT; v_val TEXT; v_rec TEXT[];
BEGIN
  FOR v_rec IN SELECT regexp_matches(v_msg, '<([^>]+)>', 'g') LOOP
    v_token := v_rec[1];
    IF v_token='nome' THEN v_val := COALESCE(p_nome,'');
    ELSIF v_token='data' THEN v_val := to_char(p_send_ts AT TIME ZONE 'America/Sao_Paulo','DD/MM/YYYY');
    ELSIF v_token='diadasemana' THEN
      v_val := lower(to_char(p_send_ts AT TIME ZONE 'America/Sao_Paulo','TMDay'));
      v_val := replace(replace(replace(replace(replace(replace(replace(
               v_val,'monday','segunda-feira'),'tuesday','terça-feira'),
               'wednesday','quarta-feira'),'thursday','quinta-feira'),
               'friday','sexta-feira'),'saturday','sábado'),'sunday','domingo');
    ELSIF v_token='hora' THEN v_val := to_char(p_send_ts AT TIME ZONE 'America/Sao_Paulo','HH24:MI');
    ELSIF v_token='mes' THEN v_val := lower(to_char(p_send_ts AT TIME ZONE 'America/Sao_Paulo','TMMonth'));
    ELSIF v_token='saudacao' THEN v_val := f_saudacao(p_send_ts);
    ELSE v_val := COALESCE(p_attrs ->> v_token,'');
    END IF;
    v_msg := replace(v_msg, '<'||v_token||'>', COALESCE(v_val,''));
  END LOOP;
  RETURN v_msg;
END
$$;

-- match_documents (RAG) - cria apenas se tipo vector existir
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM pg_type WHERE typname = 'vector') THEN
    EXECUTE '
CREATE OR REPLACE FUNCTION public.match_documents(
  query_embedding vector,
  match_count int DEFAULT 10,
  filter jsonb DEFAULT ''{}''
) RETURNS TABLE (
  id bigint,
  content text,
  metadata jsonb,
  similarity float
)
LANGUAGE plpgsql
AS $func$
BEGIN
  RETURN QUERY
  SELECT
    d.id,
    d.content,
    d.metadata,
    1 - (d.embedding <=> query_embedding) AS similarity
  FROM public."SAAS_Conhecimentos" d
  WHERE d.metadata @> filter
  ORDER BY d.embedding <=> query_embedding
  LIMIT match_count;
END;
$func$;';
  ELSE
    RAISE NOTICE 'Tipo vector não disponível. Função match_documents não será criada.';
  END IF;
EXCEPTION
  WHEN OTHERS THEN
    RAISE NOTICE 'Erro ao criar função match_documents: %.', SQLERRM;
END$$;

-- f_excluir_conhecimento_por_idunico
DO $$
BEGIN
  IF to_regclass('public."SAAS_Conhecimentos"') IS NOT NULL THEN
    EXECUTE '
CREATE OR REPLACE FUNCTION public.f_excluir_conhecimento_por_idunico(p_idunico text)
RETURNS bigint
LANGUAGE plpgsql
AS $func$
DECLARE
  v_deleted bigint;
BEGIN
  DELETE FROM public."SAAS_Conhecimentos"
  WHERE metadata->>''idUnico'' = p_idunico;

  GET DIAGNOSTICS v_deleted = ROW_COUNT;
  RETURN v_deleted;
END;
$func$;';
  ELSE
    RAISE NOTICE 'Tabela SAAS_Conhecimentos não existe. Função f_excluir_conhecimento_por_idunico não será criada.';
  END IF;
EXCEPTION
  WHEN OTHERS THEN
    RAISE NOTICE 'Erro ao criar função f_excluir_conhecimento_por_idunico: %.', SQLERRM;
END$$;

-- RLS: permitir DELETE em SAAS_Conhecimentos apenas se o conhecimento estiver
-- vinculado a um agente da mesma conta (SAAS_AgentesIA.conhecimento -> idUnico)
DO $$
BEGIN
  IF to_regclass('public."SAAS_Conhecimentos"') IS NOT NULL
     AND to_regclass('public."SAAS_AgentesIA"') IS NOT NULL THEN

    -- Habilitar RLS (idempotente)
    EXECUTE 'ALTER TABLE public."SAAS_Conhecimentos" ENABLE ROW LEVEL SECURITY';

    -- Criar policy de DELETE se ainda não existir
    IF NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'SAAS_Conhecimentos'
        AND policyname = 'delete_knowledge_linked_to_own_agents'
    ) THEN
      EXECUTE $policy$
        CREATE POLICY delete_knowledge_linked_to_own_agents
        ON public."SAAS_Conhecimentos"
        FOR DELETE
        TO authenticated
        USING (
          EXISTS (
            SELECT 1
            FROM public."SAAS_AgentesIA" a
            CROSS JOIN LATERAL jsonb_array_elements(COALESCE(a.conhecimento, '[]'::jsonb)) AS c(elem)
            WHERE
              -- conta do agente deve ser a mesma do JWT
              a."contaId" = ((current_setting('request.jwt.claims', true)::jsonb->>'contaId')::uuid)
              -- idUnico do conhecimento deve aparecer no array conhecimento do agente
              AND c.elem->>'idUnico' = metadata->>'idUnico'
          )
        );
      $policy$;
    END IF;
  END IF;
END$$;

-- Coluna embedding em SAAS_Conhecimentos (RAG/vector) – só se o tipo vector existir
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM pg_type WHERE typname = 'vector') THEN
    IF to_regclass('public."SAAS_Conhecimentos"') IS NOT NULL
       AND NOT EXISTS (
         SELECT 1 FROM information_schema.columns
         WHERE table_schema = 'public' AND table_name = 'SAAS_Conhecimentos' AND column_name = 'embedding'
       ) THEN
      ALTER TABLE public."SAAS_Conhecimentos" ADD COLUMN embedding vector;
      RAISE NOTICE 'Coluna embedding adicionada à tabela SAAS_Conhecimentos.';
    END IF;
  ELSE
    RAISE NOTICE 'Tipo vector não disponível. Habilite a extensão vector no Supabase (Database > Extensions) e execute novamente ou adicione a coluna manualmente.';
  END IF;
EXCEPTION
  WHEN OTHERS THEN
    RAISE NOTICE 'Erro ao adicionar coluna embedding: %.', SQLERRM;
END$$;

-- Índice ivfflat para busca por similaridade (embedding)
DO $$
BEGIN
  IF to_regclass('public."SAAS_Conhecimentos"') IS NOT NULL
     AND EXISTS (
       SELECT 1 FROM information_schema.columns
       WHERE table_schema = 'public' AND table_name = 'SAAS_Conhecimentos' AND column_name = 'embedding'
     ) THEN
    IF NOT EXISTS (
      SELECT 1 FROM pg_indexes
      WHERE schemaname = 'public' AND tablename = 'SAAS_Conhecimentos' AND indexname = 'saas_conhecimentos_embedding_idx'
    ) THEN
      BEGIN
        EXECUTE 'CREATE INDEX saas_conhecimentos_embedding_idx ON public."SAAS_Conhecimentos" USING ivfflat (embedding vector_cosine_ops) WITH (lists = ''100'') TABLESPACE pg_default';
        RAISE NOTICE 'Índice saas_conhecimentos_embedding_idx criado com sucesso.';
      EXCEPTION
        WHEN OTHERS THEN
          RAISE NOTICE 'Não foi possível criar o índice IVFFlat agora: %. Crie manualmente depois de inserir dados com embeddings. Erro: %', SQLSTATE, SQLERRM;
      END;
    END IF;
  END IF;
END$$;

-- get_dashboard e get_dashboard_crm: ambas usam p_user_id (valor = contaId)
CREATE OR REPLACE FUNCTION public.get_dashboard(
  p_user_id       UUID,
  p_data_inicial  TIMESTAMPTZ,
  p_data_final    TIMESTAMPTZ,
  p_conexao_ids   BIGINT[] DEFAULT NULL,
  p_quadro_id     BIGINT DEFAULT NULL
)
RETURNS JSONB LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path = public AS $$
DECLARE
  v_conversas JSONB; v_crm JSONB; v_disparos JSONB; v_atendentes JSONB;
  v_total_conv BIGINT; v_respondidas_ia BIGINT; v_tempo_abrir NUMERIC; v_tempo_concl NUMERIC;
  v_em_aberto BIGINT; v_aguardando BIGINT; v_fechadas BIGINT; v_conv_por_dia JSONB;
  v_quadro_id BIGINT; v_etapas JSONB; v_conversao TEXT; v_valor_fechado TEXT;
  v_total_disp BIGINT; v_total_conex BIGINT; v_media_disp BIGINT; v_disp_por_dia JSONB;
BEGIN
  -- Garantir que o chamador só acesse dados da conta à qual tem permissão (evita RLS bloquear e mantém segurança)
  IF NOT (public.can_access_conta(p_user_id) OR public.is_super_admin()) THEN
    RETURN jsonb_build_object(
      'conversas', jsonb_build_object('total', 0, 'respondidasIA', 0, 'tempoMedioAbrirMin', null, 'tempoMedioConclusaoHoras', null, 'emAberto', 0, 'aguardando', 0, 'fechadas', 0, 'conversasPorDia', '[]'::jsonb),
      'crm', jsonb_build_object('etapas', '[]'::jsonb, 'conversaoTotal', '0%', 'valorFechado', 'R$ 0'),
      'disparos', jsonb_build_object('totalDisparos', 0, 'conexoesAtivas', 0, 'totalConexoes', 0, 'mediaDisparosPorConexao', 0, 'disparosPorDia', '[]'::jsonb),
      'performanceAtendentes', '[]'::jsonb
    );
  END IF;

  SELECT COUNT(DISTINCT c.id) INTO v_total_conv
  FROM public."SAAS_Conversas_Agentes" c
  INNER JOIN public."SAAS_Mensagens" m ON m."conversaId" = c.id
  WHERE c."contaId" = p_user_id AND (p_conexao_ids IS NULL OR c."idConexao" = ANY(p_conexao_ids))
    AND m.created_at >= p_data_inicial AND m.created_at <= p_data_final;

  SELECT COUNT(DISTINCT c.id) INTO v_respondidas_ia
  FROM public."SAAS_Conversas_Agentes" c
  INNER JOIN public."SAAS_Mensagens" m ON m."conversaId" = c.id AND m."IA" = true
  WHERE c."contaId" = p_user_id AND (p_conexao_ids IS NULL OR c."idConexao" = ANY(p_conexao_ids))
    AND m.created_at >= p_data_inicial AND m.created_at <= p_data_final;

  SELECT ROUND(AVG(EXTRACT(EPOCH FROM (prim.primeira_msg - c.created_at)) / 60.0)::numeric, 0) INTO v_tempo_abrir
  FROM public."SAAS_Conversas_Agentes" c
  INNER JOIN (SELECT "conversaId", MIN(created_at) AS primeira_msg FROM public."SAAS_Mensagens" WHERE "fromMe" = true GROUP BY "conversaId") prim ON prim."conversaId" = c.id
  WHERE c."contaId" = p_user_id AND (p_conexao_ids IS NULL OR c."idConexao" = ANY(p_conexao_ids))
    AND prim.primeira_msg >= p_data_inicial AND prim.primeira_msg <= p_data_final;

  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_Conversas_Agentes' AND column_name='dataFechamento') THEN
    SELECT ROUND(AVG(EXTRACT(EPOCH FROM (c."dataFechamento" - c.created_at)) / 3600.0)::numeric, 1) INTO v_tempo_concl
    FROM public."SAAS_Conversas_Agentes" c
    WHERE c."contaId" = p_user_id AND (p_conexao_ids IS NULL OR c."idConexao" = ANY(p_conexao_ids))
      AND c."dataFechamento" IS NOT NULL AND c."dataFechamento" >= p_data_inicial AND c."dataFechamento" <= p_data_final;
  END IF;

  SELECT COUNT(*) FILTER (WHERE LOWER(TRIM(COALESCE("statusAtendimento", ''))) = 'aberto') INTO v_em_aberto
  FROM public."SAAS_Conversas_Agentes" WHERE "contaId" = p_user_id AND (p_conexao_ids IS NULL OR "idConexao" = ANY(p_conexao_ids));

  SELECT COUNT(*) FILTER (WHERE LOWER(TRIM(COALESCE("statusAtendimento", ''))) = 'aguardando') INTO v_aguardando
  FROM public."SAAS_Conversas_Agentes" WHERE "contaId" = p_user_id AND (p_conexao_ids IS NULL OR "idConexao" = ANY(p_conexao_ids));

  SELECT COUNT(*) FILTER (WHERE LOWER(TRIM(COALESCE("statusAtendimento", ''))) = 'fechado') INTO v_fechadas
  FROM public."SAAS_Conversas_Agentes" WHERE "contaId" = p_user_id AND (p_conexao_ids IS NULL OR "idConexao" = ANY(p_conexao_ids));

  SELECT COALESCE(jsonb_agg(jsonb_build_object('data', to_char(d, 'YYYY-MM-DD'), 'dataFormatada', to_char(d, 'DD/MM'), 'total', cnt) ORDER BY d), '[]'::jsonb) INTO v_conv_por_dia
  FROM (SELECT (created_at AT TIME ZONE 'America/Sao_Paulo')::date AS d, COUNT(*) AS cnt
        FROM public."SAAS_Conversas_Agentes"
        WHERE "contaId" = p_user_id AND (p_conexao_ids IS NULL OR "idConexao" = ANY(p_conexao_ids))
          AND created_at >= p_data_inicial AND created_at <= p_data_final
        GROUP BY (created_at AT TIME ZONE 'America/Sao_Paulo')::date) sub;

  v_conversas := jsonb_build_object('total', COALESCE(v_total_conv, 0), 'respondidasIA', COALESCE(v_respondidas_ia, 0), 'tempoMedioAbrirMin', v_tempo_abrir, 'tempoMedioConclusaoHoras', v_tempo_concl, 'emAberto', COALESCE(v_em_aberto, 0), 'aguardando', COALESCE(v_aguardando, 0), 'fechadas', COALESCE(v_fechadas, 0), 'conversasPorDia', COALESCE(v_conv_por_dia, '[]'::jsonb));

  v_quadro_id := p_quadro_id;
  IF v_quadro_id IS NULL THEN SELECT id INTO v_quadro_id FROM public."SAAS_Quadros" WHERE "contaId" = p_user_id ORDER BY id LIMIT 1; END IF;

  IF v_quadro_id IS NOT NULL THEN
    WITH primeira AS (SELECT COUNT(*) AS total FROM public."SAAS_Cards_Quadros" c INNER JOIN public."SAAS_Etapas_Quadros" e ON e.id = c."etapaQuadroId" AND e."quadroId" = v_quadro_id WHERE c."quadroId" = v_quadro_id AND e.ordem = (SELECT MIN(ordem) FROM public."SAAS_Etapas_Quadros" WHERE "quadroId" = v_quadro_id)),
         por_etapa AS (SELECT e.nome, e.ordem, COUNT(c.id) AS qtd FROM public."SAAS_Etapas_Quadros" e LEFT JOIN public."SAAS_Cards_Quadros" c ON c."etapaQuadroId" = e.id AND c."quadroId" = e."quadroId" WHERE e."quadroId" = v_quadro_id GROUP BY e.id, e.nome, e.ordem)
    SELECT jsonb_agg(jsonb_build_object('nome', pe.nome, 'quantidade', pe.qtd, 'percentual', CASE WHEN prim.total > 0 THEN ROUND((pe.qtd::numeric / prim.total * 100)::numeric, 0) ELSE 0 END) ORDER BY pe.ordem) INTO v_etapas
    FROM por_etapa pe CROSS JOIN primeira prim;

    WITH ordens AS (SELECT ordem FROM public."SAAS_Etapas_Quadros" WHERE "quadroId" = v_quadro_id ORDER BY ordem),
         primeira_qtd AS (SELECT COUNT(c.id) AS q FROM public."SAAS_Cards_Quadros" c INNER JOIN public."SAAS_Etapas_Quadros" e ON e.id = c."etapaQuadroId" WHERE e."quadroId" = v_quadro_id AND e.ordem = (SELECT MIN(ordem) FROM ordens)),
         ultima_qtd AS (SELECT COUNT(c.id) AS q FROM public."SAAS_Cards_Quadros" c INNER JOIN public."SAAS_Etapas_Quadros" e ON e.id = c."etapaQuadroId" WHERE e."quadroId" = v_quadro_id AND e.ordem = (SELECT MAX(ordem) FROM ordens))
    SELECT TRIM(ROUND((u.q::numeric / NULLIF(p.q, 0) * 100)::numeric, 0)::text) || '%' INTO v_conversao FROM ultima_qtd u, primeira_qtd p;

    SELECT 'R$ ' || TRIM(TO_CHAR(COALESCE(SUM(c.valor), 0), 'FM999G999G990')) INTO v_valor_fechado
    FROM public."SAAS_Cards_Quadros" c INNER JOIN public."SAAS_Etapas_Quadros" e ON e.id = c."etapaQuadroId"
    WHERE e."quadroId" = v_quadro_id AND (e.ordem = (SELECT MAX(ordem) FROM public."SAAS_Etapas_Quadros" WHERE "quadroId" = v_quadro_id) OR LOWER(TRIM(e.nome)) LIKE '%fechad%');

    v_crm := jsonb_build_object('etapas', COALESCE(v_etapas, '[]'::jsonb), 'conversaoTotal', COALESCE(v_conversao, '0%'), 'valorFechado', COALESCE(v_valor_fechado, 'R$ 0'));
  ELSE
    v_crm := jsonb_build_object('etapas', '[]'::jsonb, 'conversaoTotal', '0%', 'valorFechado', 'R$ 0');
  END IF;

  SELECT COUNT(*) INTO v_total_disp FROM public."SAAS_Detalhes_Disparos" d INNER JOIN public."SAAS_Disparos" h ON h.id = d."idDisparo"
  WHERE h."contaId" = p_user_id AND d."dataEnvio" >= p_data_inicial AND d."dataEnvio" <= p_data_final AND (p_conexao_ids IS NULL OR d."idConexao" = ANY(p_conexao_ids));

  SELECT COUNT(*) INTO v_total_conex FROM public."SAAS_Conexões" WHERE "contaId" = p_user_id;

  v_media_disp := CASE WHEN v_total_conex > 0 THEN (v_total_disp / v_total_conex)::BIGINT ELSE 0 END;

  SELECT COALESCE(jsonb_agg(jsonb_build_object('data', to_char(d, 'YYYY-MM-DD'), 'dataFormatada', to_char(d, 'DD/MM'), 'disparos', cnt) ORDER BY d), '[]'::jsonb) INTO v_disp_por_dia
  FROM (SELECT (d."dataEnvio" AT TIME ZONE 'America/Sao_Paulo')::date AS d, COUNT(*) AS cnt
        FROM public."SAAS_Detalhes_Disparos" d INNER JOIN public."SAAS_Disparos" h ON h.id = d."idDisparo"
        WHERE h."contaId" = p_user_id AND d."dataEnvio" >= p_data_inicial AND d."dataEnvio" <= p_data_final AND (p_conexao_ids IS NULL OR d."idConexao" = ANY(p_conexao_ids))
        GROUP BY (d."dataEnvio" AT TIME ZONE 'America/Sao_Paulo')::date) sub;

  v_disparos := jsonb_build_object('totalDisparos', COALESCE(v_total_disp, 0), 'conexoesAtivas', COALESCE(v_total_conex, 0), 'totalConexoes', COALESCE(v_total_conex, 0), 'mediaDisparosPorConexao', COALESCE(v_media_disp, 0), 'disparosPorDia', COALESCE(v_disp_por_dia, '[]'::jsonb));

  -- Performance por atendente: todos os usuários da conta com qtd atendimentos, tempo médio abertura e fechamento
  SELECT COALESCE(jsonb_agg(row ORDER BY row->>'nome'), '[]'::jsonb) INTO v_atendentes
  FROM (
    SELECT jsonb_build_object(
      'id', u.id,
      'nome', COALESCE(NULLIF(TRIM(COALESCE(u.nome, '')), ''), NULLIF(TRIM(COALESCE(u."Email", '')), ''), '—'),
      'email', u."Email",
      'quantidadeAtendimentos', COALESCE((s.stats->>'qtd')::bigint, 0),
      'tempoMedioAberturaMin', (s.stats->>'tempoMedioAberturaMin')::numeric,
      'tempoMedioFechamentoHoras', (s.stats->>'tempoMedioFechamentoHoras')::numeric
    ) AS row
    FROM public."SAAS_Usuarios" u
    LEFT JOIN (
      SELECT c.atendente,
        jsonb_build_object(
          'qtd', COUNT(*)::bigint,
          'tempoMedioAberturaMin', ROUND(AVG(EXTRACT(EPOCH FROM (prim.primeira_msg - c.created_at)) / 60.0))::numeric,
          'tempoMedioFechamentoHoras', ROUND((AVG(EXTRACT(EPOCH FROM (c."dataFechamento" - c.created_at)) / 3600.0) FILTER (WHERE c."dataFechamento" IS NOT NULL))::numeric, 1)
        ) AS stats
      FROM public."SAAS_Conversas_Agentes" c
      INNER JOIN (SELECT "conversaId", MIN(created_at) AS primeira_msg FROM public."SAAS_Mensagens" WHERE "fromMe" = true GROUP BY "conversaId") prim ON prim."conversaId" = c.id
      WHERE c."contaId" = p_user_id AND (p_conexao_ids IS NULL OR c."idConexao" = ANY(p_conexao_ids))
        AND c.created_at >= p_data_inicial AND c.created_at <= p_data_final
        AND c.atendente IS NOT NULL
      GROUP BY c.atendente
    ) s ON s.atendente = u.id
    WHERE u."contaId" = p_user_id
  ) sub;

  RETURN jsonb_build_object('conversas', v_conversas, 'crm', v_crm, 'disparos', v_disparos, 'performanceAtendentes', COALESCE(v_atendentes, '[]'::jsonb));
END;
$$;
GRANT EXECUTE ON FUNCTION public.get_dashboard(UUID, TIMESTAMPTZ, TIMESTAMPTZ, BIGINT[], BIGINT) TO authenticated, anon;

-- get_chat_overview: payload único para sidebar do chat (contagens + lista paginada + última mensagem)
CREATE OR REPLACE FUNCTION public.get_chat_overview(
  p_conta_id UUID,
  p_status TEXT DEFAULT 'aberto',
  p_limit INTEGER DEFAULT 20,
  p_offset INTEGER DEFAULT 0,
  p_conexao_ids BIGINT[] DEFAULT NULL,
  p_contato_ids BIGINT[] DEFAULT NULL,
  p_search TEXT DEFAULT NULL
)
RETURNS JSONB
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_status TEXT := LOWER(TRIM(COALESCE(p_status, 'aberto')));
  v_limit INTEGER := GREATEST(1, LEAST(COALESCE(p_limit, 20), 200));
  v_offset INTEGER := GREATEST(0, COALESCE(p_offset, 0));
  v_search TEXT := NULLIF(TRIM(COALESCE(p_search, '')), '');
  v_aberto BIGINT := 0;
  v_aguardando BIGINT := 0;
  v_fechado BIGINT := 0;
  v_agente_ia BIGINT := 0;
  v_total_filtered BIGINT := 0;
  v_next_offset INTEGER := 0;
  v_has_more BOOLEAN := false;
  v_items JSONB := '[]'::jsonb;
BEGIN
  IF p_conta_id IS NULL THEN
    RETURN jsonb_build_object(
      'counts', jsonb_build_object('aberto', 0, 'aguardando', 0, 'fechado', 0, 'agente_ia', 0),
      'total_filtered', 0,
      'next_offset', 0,
      'has_more', false,
      'conversations', '[]'::jsonb
    );
  END IF;

  -- Em chamadas via app (JWT presente), valida acesso à conta.
  -- Em execução administrativa sem JWT (ex.: SQL Editor), permite inspeção.
  IF auth.uid() IS NOT NULL
     AND NOT (public.can_access_conta(p_conta_id) OR public.is_super_admin()) THEN
    RETURN jsonb_build_object(
      'counts', jsonb_build_object('aberto', 0, 'aguardando', 0, 'fechado', 0, 'agente_ia', 0),
      'total_filtered', 0,
      'next_offset', 0,
      'has_more', false,
      'conversations', '[]'::jsonb
    );
  END IF;

  WITH base AS (
    SELECT
      c.*,
      cx."NomeConexao" AS conexao_nome,
      cx."Telefone" AS conexao_telefone,
      cx."idAgente" AS conexao_id_agente,
      ag.id AS agente_id,
      ag.nome AS agente_nome,
      ag."pausarAtendimento" AS agente_pausar,
      ag.ativo AS agente_ativo,
      ct.nome AS contato_nome,
      au.nome AS atendente_nome
    FROM public."SAAS_Conversas_Agentes" c
    LEFT JOIN public."SAAS_Conexões" cx ON cx.id = c."idConexao"
    LEFT JOIN public."SAAS_AgentesIA" ag ON ag.id = cx."idAgente"
    LEFT JOIN public."SAAS_Contatos" ct ON ct.id = c."contatoId"
    LEFT JOIN public."SAAS_Usuarios" au ON au.id = c.atendente
    WHERE c."contaId" = p_conta_id
      AND (
        p_conexao_ids IS NULL
        OR cardinality(p_conexao_ids) = 0
        OR c."idConexao" = ANY(p_conexao_ids)
      )
      AND (
        p_contato_ids IS NULL
        OR cardinality(p_contato_ids) = 0
        OR c."contatoId" = ANY(p_contato_ids)
      )
      AND (
        v_search IS NULL
        OR c.telefone ILIKE ('%' || v_search || '%')
        OR COALESCE(ct.nome, '') ILIKE ('%' || v_search || '%')
      )
  ),
  flagged AS (
    SELECT
      b.*,
      (LOWER(TRIM(COALESCE(b."statusAtendimento", ''))) = 'aberto') AS is_aberto,
      (LOWER(TRIM(COALESCE(b."statusAtendimento", ''))) = 'fechado') AS is_fechado,
      (LOWER(TRIM(COALESCE(b."statusAtendimento", ''))) = 'aguardando') AS is_aguardando,
      (
        LOWER(TRIM(COALESCE(b."statusAtendimento", ''))) = 'aguardando'
        AND COALESCE(b.pausado, false) = false
        AND b.conexao_id_agente IS NOT NULL
        AND COALESCE(b.agente_ativo, false) = true
      ) AS is_agente_ia
    FROM base b
  ),
  filtered AS (
    SELECT *
    FROM flagged f
    WHERE (
      (v_status = 'aberto' AND f.is_aberto)
      OR (v_status = 'fechado' AND f.is_fechado)
      OR (v_status = 'agente-ia' AND f.is_agente_ia)
      OR (v_status = 'aguardando' AND f.is_aguardando AND NOT f.is_agente_ia)
      OR (v_status NOT IN ('aberto', 'fechado', 'aguardando', 'agente-ia'))
    )
  ),
  enriched AS (
    SELECT
      f.*,
      lm.mensagem AS last_message_text,
      lm."tipoMensagem" AS last_message_tipo,
      lm.created_at AS last_message_created_at,
      COALESCE(lm.created_at, f."ultimaMensagem", f.created_at) AS sort_time
    FROM filtered f
    LEFT JOIN LATERAL (
      SELECT m.mensagem, m."tipoMensagem", m.created_at
      FROM public."SAAS_Mensagens" m
      WHERE m."conversaId" = f.id
        AND COALESCE(m.apagada, false) = false
      ORDER BY m.created_at DESC, m.id DESC
      LIMIT 1
    ) lm ON true
  ),
  paged AS (
    SELECT *
    FROM enriched
    ORDER BY sort_time DESC NULLS LAST, id DESC
    LIMIT v_limit
    OFFSET v_offset
  )
  SELECT
    COALESCE(SUM(CASE WHEN is_aberto THEN 1 ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN is_aguardando AND NOT is_agente_ia THEN 1 ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN is_fechado THEN 1 ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN is_agente_ia THEN 1 ELSE 0 END), 0)
  INTO v_aberto, v_aguardando, v_fechado, v_agente_ia
  FROM flagged;

  WITH base AS (
    SELECT
      c.*,
      cx."NomeConexao" AS conexao_nome,
      cx."Telefone" AS conexao_telefone,
      cx."idAgente" AS conexao_id_agente,
      ag.id AS agente_id,
      ag.nome AS agente_nome,
      ag."pausarAtendimento" AS agente_pausar,
      ag.ativo AS agente_ativo,
      ct.nome AS contato_nome,
      au.nome AS atendente_nome
    FROM public."SAAS_Conversas_Agentes" c
    LEFT JOIN public."SAAS_Conexões" cx ON cx.id = c."idConexao"
    LEFT JOIN public."SAAS_AgentesIA" ag ON ag.id = cx."idAgente"
    LEFT JOIN public."SAAS_Contatos" ct ON ct.id = c."contatoId"
    LEFT JOIN public."SAAS_Usuarios" au ON au.id = c.atendente
    WHERE c."contaId" = p_conta_id
      AND (
        p_conexao_ids IS NULL
        OR cardinality(p_conexao_ids) = 0
        OR c."idConexao" = ANY(p_conexao_ids)
      )
      AND (
        p_contato_ids IS NULL
        OR cardinality(p_contato_ids) = 0
        OR c."contatoId" = ANY(p_contato_ids)
      )
      AND (
        v_search IS NULL
        OR c.telefone ILIKE ('%' || v_search || '%')
        OR COALESCE(ct.nome, '') ILIKE ('%' || v_search || '%')
      )
  ),
  flagged AS (
    SELECT
      b.*,
      (LOWER(TRIM(COALESCE(b."statusAtendimento", ''))) = 'aberto') AS is_aberto,
      (LOWER(TRIM(COALESCE(b."statusAtendimento", ''))) = 'fechado') AS is_fechado,
      (LOWER(TRIM(COALESCE(b."statusAtendimento", ''))) = 'aguardando') AS is_aguardando,
      (
        LOWER(TRIM(COALESCE(b."statusAtendimento", ''))) = 'aguardando'
        AND COALESCE(b.pausado, false) = false
        AND b.conexao_id_agente IS NOT NULL
        AND COALESCE(b.agente_ativo, false) = true
      ) AS is_agente_ia
    FROM base b
  ),
  filtered AS (
    SELECT *
    FROM flagged f
    WHERE (
      (v_status = 'aberto' AND f.is_aberto)
      OR (v_status = 'fechado' AND f.is_fechado)
      OR (v_status = 'agente-ia' AND f.is_agente_ia)
      OR (v_status = 'aguardando' AND f.is_aguardando AND NOT f.is_agente_ia)
      OR (v_status NOT IN ('aberto', 'fechado', 'aguardando', 'agente-ia'))
    )
  )
  SELECT COUNT(*) INTO v_total_filtered FROM filtered;
  v_next_offset := v_offset + v_limit;
  v_has_more := v_next_offset < v_total_filtered;
  IF NOT v_has_more THEN
    v_next_offset := v_total_filtered::INTEGER;
  END IF;

  WITH base AS (
    SELECT
      c.*,
      cx."NomeConexao" AS conexao_nome,
      cx."Telefone" AS conexao_telefone,
      cx."idAgente" AS conexao_id_agente,
      ag.id AS agente_id,
      ag.nome AS agente_nome,
      ag."pausarAtendimento" AS agente_pausar,
      ag.ativo AS agente_ativo,
      ct.nome AS contato_nome,
      au.nome AS atendente_nome
    FROM public."SAAS_Conversas_Agentes" c
    LEFT JOIN public."SAAS_Conexões" cx ON cx.id = c."idConexao"
    LEFT JOIN public."SAAS_AgentesIA" ag ON ag.id = cx."idAgente"
    LEFT JOIN public."SAAS_Contatos" ct ON ct.id = c."contatoId"
    LEFT JOIN public."SAAS_Usuarios" au ON au.id = c.atendente
    WHERE c."contaId" = p_conta_id
      AND (
        p_conexao_ids IS NULL
        OR cardinality(p_conexao_ids) = 0
        OR c."idConexao" = ANY(p_conexao_ids)
      )
      AND (
        p_contato_ids IS NULL
        OR cardinality(p_contato_ids) = 0
        OR c."contatoId" = ANY(p_contato_ids)
      )
      AND (
        v_search IS NULL
        OR c.telefone ILIKE ('%' || v_search || '%')
        OR COALESCE(ct.nome, '') ILIKE ('%' || v_search || '%')
      )
  ),
  flagged AS (
    SELECT
      b.*,
      (LOWER(TRIM(COALESCE(b."statusAtendimento", ''))) = 'aberto') AS is_aberto,
      (LOWER(TRIM(COALESCE(b."statusAtendimento", ''))) = 'fechado') AS is_fechado,
      (LOWER(TRIM(COALESCE(b."statusAtendimento", ''))) = 'aguardando') AS is_aguardando,
      (
        LOWER(TRIM(COALESCE(b."statusAtendimento", ''))) = 'aguardando'
        AND COALESCE(b.pausado, false) = false
        AND b.conexao_id_agente IS NOT NULL
        AND COALESCE(b.agente_ativo, false) = true
      ) AS is_agente_ia
    FROM base b
  ),
  filtered AS (
    SELECT *
    FROM flagged f
    WHERE (
      (v_status = 'aberto' AND f.is_aberto)
      OR (v_status = 'fechado' AND f.is_fechado)
      OR (v_status = 'agente-ia' AND f.is_agente_ia)
      OR (v_status = 'aguardando' AND f.is_aguardando AND NOT f.is_agente_ia)
      OR (v_status NOT IN ('aberto', 'fechado', 'aguardando', 'agente-ia'))
    )
  ),
  enriched AS (
    SELECT
      f.*,
      lm.mensagem AS last_message_text,
      lm."tipoMensagem" AS last_message_tipo,
      lm.created_at AS last_message_created_at,
      COALESCE(lm.created_at, f."ultimaMensagem", f.created_at) AS sort_time
    FROM filtered f
    LEFT JOIN LATERAL (
      SELECT m.mensagem, m."tipoMensagem", m.created_at
      FROM public."SAAS_Mensagens" m
      WHERE m."conversaId" = f.id
        AND COALESCE(m.apagada, false) = false
      ORDER BY m.created_at DESC, m.id DESC
      LIMIT 1
    ) lm ON true
  ),
  paged AS (
    SELECT *
    FROM enriched
    ORDER BY sort_time DESC NULLS LAST, id DESC
    LIMIT v_limit
    OFFSET v_offset
  )
  SELECT COALESCE(
    jsonb_agg(
      (
        to_jsonb(p) - 'is_aberto' - 'is_fechado' - 'is_aguardando' - 'is_agente_ia'
        || jsonb_build_object(
          'contato', jsonb_build_object('nome', p.contato_nome),
          'atendente_usuario', jsonb_build_object('nome', p.atendente_nome),
          'SAAS_Conexões', jsonb_build_object(
            'idAgente', p.conexao_id_agente,
            'NomeConexao', p.conexao_nome,
            'Telefone', p.conexao_telefone,
            'SAAS_AgentesIA', jsonb_build_object(
              'id', p.agente_id,
              'nome', p.agente_nome,
              'pausarAtendimento', p.agente_pausar,
              'ativo', p.agente_ativo
            )
          ),
          'ultimaMensagemTexto', p.last_message_text,
          'ultimaMensagemTipo', p.last_message_tipo,
          'ultimaMensagemData', p.last_message_created_at
        )
      )
      ORDER BY p.sort_time DESC NULLS LAST, p.id DESC
    ),
    '[]'::jsonb
  ) INTO v_items
  FROM paged p;

  RETURN jsonb_build_object(
    'counts', jsonb_build_object(
      'aberto', v_aberto,
      'aguardando', v_aguardando,
      'fechado', v_fechado,
      'agente_ia', v_agente_ia
    ),
    'total_filtered', v_total_filtered,
    'next_offset', v_next_offset,
    'has_more', v_has_more,
    'conversations', v_items
  );
END;
$$;
GRANT EXECUTE ON FUNCTION public.get_chat_overview(UUID, TEXT, INTEGER, INTEGER, BIGINT[], BIGINT[], TEXT) TO authenticated;

-- get_dashboard_crm: p_user_id = contaId (igual get_dashboard)
CREATE OR REPLACE FUNCTION public.get_dashboard_crm(p_user_id UUID, p_quadro_id BIGINT DEFAULT NULL)
RETURNS JSONB LANGUAGE plpgsql STABLE SECURITY INVOKER SET search_path = public AS $$
DECLARE v_quadro_id BIGINT; v_etapas JSONB; v_conversao TEXT; v_valor_fechado TEXT;
BEGIN
  v_quadro_id := p_quadro_id;
  IF v_quadro_id IS NULL THEN SELECT id INTO v_quadro_id FROM public."SAAS_Quadros" WHERE "contaId" = p_user_id ORDER BY id LIMIT 1; END IF;

  IF v_quadro_id IS NOT NULL THEN
    WITH primeira AS (SELECT COUNT(*) AS total FROM public."SAAS_Cards_Quadros" c INNER JOIN public."SAAS_Etapas_Quadros" e ON e.id = c."etapaQuadroId" AND e."quadroId" = v_quadro_id WHERE c."quadroId" = v_quadro_id AND e.ordem = (SELECT MIN(ordem) FROM public."SAAS_Etapas_Quadros" WHERE "quadroId" = v_quadro_id)),
         por_etapa AS (SELECT e.nome, e.ordem, COUNT(c.id) AS qtd FROM public."SAAS_Etapas_Quadros" e LEFT JOIN public."SAAS_Cards_Quadros" c ON c."etapaQuadroId" = e.id AND c."quadroId" = e."quadroId" WHERE e."quadroId" = v_quadro_id GROUP BY e.id, e.nome, e.ordem)
    SELECT jsonb_agg(jsonb_build_object('nome', pe.nome, 'quantidade', pe.qtd, 'percentual', CASE WHEN prim.total > 0 THEN ROUND((pe.qtd::numeric / prim.total * 100)::numeric, 0) ELSE 0 END) ORDER BY pe.ordem) INTO v_etapas FROM por_etapa pe CROSS JOIN primeira prim;

    WITH ordens AS (SELECT ordem FROM public."SAAS_Etapas_Quadros" WHERE "quadroId" = v_quadro_id ORDER BY ordem),
         primeira_qtd AS (SELECT COUNT(c.id) AS q FROM public."SAAS_Cards_Quadros" c INNER JOIN public."SAAS_Etapas_Quadros" e ON e.id = c."etapaQuadroId" WHERE e."quadroId" = v_quadro_id AND e.ordem = (SELECT MIN(ordem) FROM ordens)),
         ultima_qtd AS (SELECT COUNT(c.id) AS q FROM public."SAAS_Cards_Quadros" c INNER JOIN public."SAAS_Etapas_Quadros" e ON e.id = c."etapaQuadroId" WHERE e."quadroId" = v_quadro_id AND e.ordem = (SELECT MAX(ordem) FROM ordens))
    SELECT TRIM(ROUND((u.q::numeric / NULLIF(p.q, 0) * 100)::numeric, 0)::text) || '%' INTO v_conversao FROM ultima_qtd u, primeira_qtd p;

    SELECT 'R$ ' || TRIM(TO_CHAR(COALESCE(SUM(c.valor), 0), 'FM999G999G990')) INTO v_valor_fechado
    FROM public."SAAS_Cards_Quadros" c INNER JOIN public."SAAS_Etapas_Quadros" e ON e.id = c."etapaQuadroId"
    WHERE e."quadroId" = v_quadro_id AND (e.ordem = (SELECT MAX(ordem) FROM public."SAAS_Etapas_Quadros" WHERE "quadroId" = v_quadro_id) OR LOWER(TRIM(e.nome)) LIKE '%fechad%');

    RETURN jsonb_build_object('etapas', COALESCE(v_etapas, '[]'::jsonb), 'conversaoTotal', COALESCE(v_conversao, '0%'), 'valorFechado', COALESCE(v_valor_fechado, 'R$ 0'));
  ELSE
    RETURN jsonb_build_object('etapas', '[]'::jsonb, 'conversaoTotal', '0%', 'valorFechado', 'R$ 0');
  END IF;
END;
$$;
GRANT EXECUTE ON FUNCTION public.get_dashboard_crm(UUID, BIGINT) TO authenticated, anon;

-- get_contatos_by_lista e get_grupos_by_lista: aliases para modelo etiquetas (idLista/SAAS_Grupos não existem mais)
DROP FUNCTION IF EXISTS public.get_contatos_by_lista(bigint);
DROP FUNCTION IF EXISTS public.get_grupos_by_lista(bigint);

-- Criar get_contatos_by_etiqueta, get_grupos_by_etiqueta e aliases quando SAAS_Etiquetas existir
DO $block$
BEGIN
  IF to_regclass('public."SAAS_Etiquetas"') IS NOT NULL AND to_regclass('public."SAAS_Contatos_Etiquetas"') IS NOT NULL THEN
    CREATE OR REPLACE FUNCTION public.get_contatos_by_etiqueta(p_id_etiqueta bigint)
    RETURNS SETOF public."SAAS_Contatos" LANGUAGE sql STABLE AS $func$
      SELECT c.* FROM public."SAAS_Contatos" c JOIN public."SAAS_Contatos_Etiquetas" ce ON ce."contatoId" = c.id
      WHERE ce."etiquetaId" = p_id_etiqueta AND c.tipo = 'contato';
    $func$;
    CREATE OR REPLACE FUNCTION public.get_grupos_by_etiqueta(p_id_etiqueta bigint)
    RETURNS SETOF public."SAAS_Contatos" LANGUAGE sql STABLE AS $func$
      SELECT c.* FROM public."SAAS_Contatos" c JOIN public."SAAS_Contatos_Etiquetas" ce ON ce."contatoId" = c.id
      WHERE ce."etiquetaId" = p_id_etiqueta AND c.tipo = 'grupo';
    $func$;
    CREATE OR REPLACE FUNCTION public.get_contatos_by_lista(p_id bigint) RETURNS SETOF public."SAAS_Contatos" AS $func$ SELECT * FROM public.get_contatos_by_etiqueta(p_id); $func$ LANGUAGE sql STABLE;
    CREATE OR REPLACE FUNCTION public.get_grupos_by_lista(p_id bigint) RETURNS SETOF public."SAAS_Contatos" AS $func$ SELECT * FROM public.get_grupos_by_etiqueta(p_id); $func$ LANGUAGE sql STABLE;
  END IF;
END$block$;

-- Contas com plano (equivalente multi-tenant a f_usuarios_com_plano)
DROP FUNCTION IF EXISTS public.f_contas_com_plano();
CREATE OR REPLACE FUNCTION public.f_contas_com_plano()
RETURNS TABLE (
  id UUID, created_at TIMESTAMPTZ, email TEXT, status BOOLEAN, "dataValidade" DATE,
  plano_id BIGINT, plano_nome TEXT, plano_preco REAL,
  "plano_qntConexoes" BIGINT, "plano_qntContatos" BIGINT, "plano_qntDisparos" BIGINT,
  "plano_qntQuadros" BIGINT, "plano_qntAgentesIa" BIGINT, "plano_qntCreditosIa" BIGINT
