-- Reordenar etapas e cards de quadro
CREATE OR REPLACE FUNCTION public.f_reordenar_etapas_quadro()
RETURNS trigger LANGUAGE plpgsql AS $$
DECLARE v_quadro_id bigint; v_old_pos smallint; v_new_pos smallint; v_flag text;
BEGIN
  v_flag := current_setting('saas.reordering_etapas', true);
  IF v_flag = 'on' THEN RETURN NEW; END IF;
  IF NEW."quadroId" IS DISTINCT FROM OLD."quadroId" THEN RETURN NEW; END IF;
  IF NEW.ordem IS NULL OR OLD.ordem IS NULL THEN RETURN NEW; END IF;
  IF NEW.ordem = OLD.ordem THEN RETURN NEW; END IF;
  v_quadro_id := NEW."quadroId"; v_old_pos := OLD.ordem; v_new_pos := NEW.ordem;
  PERFORM set_config('saas.reordering_etapas', 'on', true);
  IF v_new_pos < v_old_pos THEN
    UPDATE public."SAAS_Etapas_Quadros" SET ordem = ordem + 1 WHERE "quadroId" = v_quadro_id AND id <> NEW.id AND ordem >= v_new_pos AND ordem < v_old_pos;
  ELSIF v_new_pos > v_old_pos THEN
    UPDATE public."SAAS_Etapas_Quadros" SET ordem = ordem - 1 WHERE "quadroId" = v_quadro_id AND id <> NEW.id AND ordem <= v_new_pos AND ordem > v_old_pos;
  END IF;
  PERFORM set_config('saas.reordering_etapas', 'off', true);
  RETURN NEW;
END;
$$;

CREATE OR REPLACE FUNCTION public.f_reordenar_cards_quadro()
RETURNS trigger LANGUAGE plpgsql AS $$
DECLARE v_quadro_id bigint; v_etapa_id bigint; v_old_pos smallint; v_new_pos smallint; v_flag text;
BEGIN
  v_flag := current_setting('saas.reordering_cards', true);
  IF v_flag = 'on' THEN RETURN NEW; END IF;
  IF NEW."quadroId" IS DISTINCT FROM OLD."quadroId" OR NEW."etapaQuadroId" IS DISTINCT FROM OLD."etapaQuadroId" THEN RETURN NEW; END IF;
  IF NEW.ordem IS NULL OR OLD.ordem IS NULL THEN RETURN NEW; END IF;
  IF NEW.ordem = OLD.ordem THEN RETURN NEW; END IF;
  v_quadro_id := NEW."quadroId"; v_etapa_id := NEW."etapaQuadroId"; v_old_pos := OLD.ordem; v_new_pos := NEW.ordem;
  PERFORM set_config('saas.reordering_cards', 'on', true);
  IF v_new_pos < v_old_pos THEN
    UPDATE public."SAAS_Cards_Quadros" SET ordem = ordem + 1 WHERE "quadroId" = v_quadro_id AND "etapaQuadroId" = v_etapa_id AND id <> NEW.id AND ordem >= v_new_pos AND ordem < v_old_pos;
  ELSIF v_new_pos > v_old_pos THEN
    UPDATE public."SAAS_Cards_Quadros" SET ordem = ordem - 1 WHERE "quadroId" = v_quadro_id AND "etapaQuadroId" = v_etapa_id AND id <> NEW.id AND ordem <= v_new_pos AND ordem > v_old_pos;
  END IF;
  PERFORM set_config('saas.reordering_cards', 'off', true);
  RETURN NEW;
END;
$$;

