CREATE OR REPLACE FUNCTION public.f_sync_pausado_status_atendimento()
RETURNS trigger LANGUAGE plpgsql AS $$
BEGIN
  IF LOWER(TRIM(COALESCE(NEW."statusAtendimento", ''))) = 'aberto' THEN NEW.pausado := TRUE; ELSE NEW.pausado := FALSE; END IF;
  RETURN NEW;
END;
$$;

CREATE OR REPLACE FUNCTION public.f_set_data_fechamento_conversa()
RETURNS trigger LANGUAGE plpgsql AS $$
BEGIN
  IF LOWER(TRIM(COALESCE(NEW."statusAtendimento", ''))) = 'fechado' THEN
    NEW."dataFechamento" := COALESCE(NEW."dataFechamento", now());
  ELSE
    NEW."dataFechamento" := NULL;
  END IF;
  RETURN NEW;
END;
$$;

CREATE OR REPLACE FUNCTION public.f_pausar_atendimento_por_mensagem(p_mensagem_id BIGINT)
RETURNS void LANGUAGE plpgsql AS $$
DECLARE v_conversa_id BIGINT; v_conexao_id BIGINT; v_agente_id BIGINT; v_pausar BOOLEAN;
BEGIN
  SELECT m."conversaId" INTO v_conversa_id FROM public."SAAS_Mensagens" m WHERE m.id = p_mensagem_id;
  IF v_conversa_id IS NULL THEN RETURN; END IF;
  SELECT c."idConexao" INTO v_conexao_id FROM public."SAAS_Conversas_Agentes" c WHERE c.id = v_conversa_id;
  IF v_conexao_id IS NULL THEN RETURN; END IF;
  SELECT c."idAgente" INTO v_agente_id FROM public."SAAS_Conversas_Agentes" c WHERE c.id = v_conversa_id;
  IF v_agente_id IS NULL THEN
    UPDATE public."SAAS_Conversas_Agentes" SET "statusAtendimento" = 'aberto', pausado = TRUE WHERE id = v_conversa_id;
    RETURN;
  END IF;
  SELECT a."pausarAtendimento" INTO v_pausar FROM public."SAAS_AgentesIA" a WHERE a.id = v_agente_id;
  IF v_pausar IS TRUE THEN
    UPDATE public."SAAS_Conversas_Agentes" SET "statusAtendimento" = 'aberto', pausado = TRUE WHERE id = v_conversa_id;
  END IF;
END;
$$;

-- =========================
-- Auth mirror: auth.users -> SAAS_Usuarios (ao criar/atualizar usuário no Auth)
-- =========================
CREATE OR REPLACE FUNCTION public.f_sync_auth_user_to_saas_usuarios()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public, auth AS $$
DECLARE v_nome text; v_plano_id bigint; v_data_validade date; v_conta_id uuid; v_usuario_id uuid;
BEGIN
  PERFORM set_config('row_security', 'off', true);
  v_nome := COALESCE(NEW.raw_user_meta_data->>'name', NEW.raw_user_meta_data->>'full_name', NEW.raw_user_meta_data->>'nome', NEW.raw_user_meta_data->>'first_name');
  v_plano_id := NULLIF(NEW.raw_user_meta_data->>'planoId', '')::bigint;
  v_data_validade := NULLIF(NEW.raw_user_meta_data->>'dataValidade', '')::date;

  IF TG_OP = 'UPDATE' THEN
    UPDATE public."SAAS_Usuarios" SET "Email" = NEW.email, telefone = COALESCE(NEW.phone, telefone), nome = COALESCE(v_nome, nome) WHERE auth_user_id = NEW.id;
    -- Atualizar plano/data/status da conta, mas não o email (conta mantém email do criador/primeiro admin)
    UPDATE public."SAAS_Contas" c SET plano = COALESCE(v_plano_id, plano), "dataValidade" = COALESCE(v_data_validade, "dataValidade"), status = COALESCE(status, true)
    FROM public."SAAS_Usuarios" u WHERE u."contaId" = c.id AND u.auth_user_id = NEW.id;
    RETURN NEW;
  END IF;

  -- Antes de criar qualquer coisa: se já existe SAAS_Usuarios com este email, só vincula auth_user_id (prioridade para linha com auth_user_id NULL = convite pendente)
  SELECT u.id INTO v_usuario_id FROM public."SAAS_Usuarios" u WHERE u."Email" = NEW.email ORDER BY (CASE WHEN u.auth_user_id IS NULL THEN 0 ELSE 1 END), u.created_at DESC LIMIT 1;
  IF v_usuario_id IS NOT NULL THEN
    UPDATE public."SAAS_Usuarios" SET auth_user_id = NEW.id, "Email" = NEW.email, telefone = COALESCE(NEW.phone, telefone), nome = COALESCE(v_nome, nome) WHERE id = v_usuario_id;
    SELECT "contaId" INTO v_conta_id FROM public."SAAS_Usuarios" WHERE id = v_usuario_id;
    IF v_conta_id IS NOT NULL THEN
      -- Não alterar email da conta ao vincular convidado: manter email do criador/primeiro admin
      UPDATE public."SAAS_Contas" SET plano = COALESCE(v_plano_id, plano), "dataValidade" = COALESCE(v_data_validade, "dataValidade"), status = COALESCE(status, true) WHERE id = v_conta_id;
    END IF;
    RETURN NEW;
  END IF;

  -- Convite por metadata: raw_user_meta_data tem contaId e invite (fallback quando o front não pré-criou a linha)
  v_conta_id := (NEW.raw_user_meta_data->>'contaId')::uuid;
  IF v_conta_id IS NOT NULL AND (NEW.raw_user_meta_data->>'invite') = 'true' THEN
    INSERT INTO public."SAAS_Usuarios" ("contaId", nome, "Email", telefone, auth_user_id, funcao)
    VALUES (v_conta_id, v_nome, NEW.email, NEW.phone, NEW.id, COALESCE(NULLIF(NEW.raw_user_meta_data->>'funcao', ''), 'membro'));
    RETURN NEW;
  END IF;

  -- Cadastro novo: cria conta e usuário admin
  INSERT INTO public."SAAS_Contas" (status, "dataValidade", plano, email) VALUES (true, v_data_validade, v_plano_id, NEW.email) RETURNING id INTO v_conta_id;
  INSERT INTO public."SAAS_Usuarios" ("contaId", nome, "Email", telefone, auth_user_id, funcao)
  VALUES (v_conta_id, v_nome, NEW.email, NEW.phone, NEW.id, 'admin');
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_sync_auth_user_to_saas_usuarios ON auth.users;
CREATE TRIGGER trg_sync_auth_user_to_saas_usuarios
  AFTER INSERT OR UPDATE OF email, phone, raw_user_meta_data ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.f_sync_auth_user_to_saas_usuarios();

-- Trigger: manter SAAS_Contas.email = email do usuário vinculado (criador = primeiro admin da conta)
CREATE OR REPLACE FUNCTION public.f_sync_conta_email_from_usuario()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  UPDATE public."SAAS_Contas" c
  SET email = (SELECT u."Email" FROM public."SAAS_Usuarios" u WHERE u."contaId" = COALESCE(NEW."contaId", OLD."contaId") AND u.funcao = 'admin' ORDER BY u.created_at ASC LIMIT 1)
  WHERE c.id = COALESCE(NEW."contaId", OLD."contaId");
  RETURN COALESCE(NEW, OLD);
END;
$$;
DROP TRIGGER IF EXISTS trg_sync_conta_email_from_usuario ON public."SAAS_Usuarios";
CREATE TRIGGER trg_sync_conta_email_from_usuario
  AFTER INSERT OR UPDATE OF "Email" ON public."SAAS_Usuarios"
  FOR EACH ROW EXECUTE FUNCTION public.f_sync_conta_email_from_usuario();

-- Função: Pausar disparos de contas com status = false (executada 1x ao dia via cron)
CREATE OR REPLACE FUNCTION public.f_cancelar_disparos_usuarios_inativos()
RETURNS void LANGUAGE plpgsql AS $$
BEGIN
  UPDATE public."SAAS_Disparos" d
  SET "StatusDisparo" = 'Pausado'
  FROM public."SAAS_Contas" c
  WHERE d."contaId" = c.id
    AND COALESCE(c.status, false) = false
    AND d."StatusDisparo" IN ('Aguardando', 'Em andamento', 'Pausado');
END;
$$;

-- Trigger: dataValidade em SAAS_Contas (só ajusta status da conta; não lê/escreve em nenhuma outra tabela com RLS)
-- Conta com super_admin nunca desativa. SECURITY DEFINER + row_security off só para o SELECT em Usuarios (evita 42501)
CREATE OR REPLACE FUNCTION public.trg_contas_data_validade()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  PERFORM set_config('row_security', 'off', true);
  IF EXISTS (SELECT 1 FROM public."SAAS_Usuarios" u WHERE u."contaId" = NEW.id AND u.super_admin = true) THEN
    NEW.status := true;
    RETURN NEW;
  END IF;
  IF NEW."dataValidade" IS NOT NULL AND NEW."dataValidade" < CURRENT_DATE AND COALESCE(NEW.status, true) IS NOT TRUE THEN
    NEW.status := false;
  END IF;
  RETURN NEW;
END;
$$;
DROP TRIGGER IF EXISTS trg_usuarios_data_validade ON public."SAAS_Contas";
DROP TRIGGER IF EXISTS trg_contas_data_validade ON public."SAAS_Contas";
CREATE TRIGGER trg_contas_data_validade
  BEFORE INSERT OR UPDATE ON public."SAAS_Contas"
  FOR EACH ROW EXECUTE FUNCTION public.trg_contas_data_validade();

-- Funções de disparo (p_user_id = contaId)
CREATE OR REPLACE FUNCTION public.f_add_tokens_usuario_por_agente(p_id_agente bigint, p_qnt_tokens numeric)
RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE v_conta_id uuid; v_atual numeric; v_novo numeric;
BEGIN
  SELECT a."contaId" INTO v_conta_id FROM public."SAAS_AgentesIA" a WHERE a.id = p_id_agente LIMIT 1;
  IF v_conta_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Agente não encontrado', 'id_agente_informado', p_id_agente);
  END IF;
  SELECT COALESCE(c.tokens, 0) INTO v_atual FROM public."SAAS_Contas" c WHERE c.id = v_conta_id;
  v_novo := v_atual + p_qnt_tokens;
  PERFORM set_config('saas.allow_tokens_update', '1', true);
  UPDATE public."SAAS_Contas" SET tokens = v_novo WHERE id = v_conta_id;
  RETURN jsonb_build_object('ok', true, 'id_agente', p_id_agente, 'contaId', v_conta_id, 'tokensAnterior', v_atual, 'tokensNovo', v_novo);
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('ok', false, 'error', SQLERRM, 'id_agente_informado', p_id_agente);
END;
$$;

CREATE OR REPLACE FUNCTION public.swap_connection(p_disparo_id bigint, p_blocked_conn_id bigint)
RETURNS void LANGUAGE plpgsql AS $$
DECLARE hdr record; v_conn_ids bigint[]; v_new_conn_id bigint;
BEGIN
  SELECT * INTO hdr FROM public."SAAS_Disparos" WHERE id=p_disparo_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Disparo % não existe', p_disparo_id; END IF;
  v_conn_ids := array_remove(hdr."idConexoes", p_blocked_conn_id);
  IF v_conn_ids IS NULL OR COALESCE(array_length(v_conn_ids,1),0)=0 THEN
    UPDATE public."SAAS_Disparos" SET "StatusDisparo"='Cancelado' WHERE id=p_disparo_id;
    UPDATE public."SAAS_Detalhes_Disparos" SET "mensagemErro"='Whatsapp desconectado ou bloqueado'
      WHERE "idDisparo"=p_disparo_id AND "Status" IN ('pending','processing');
    RETURN;
  END IF;
  v_new_conn_id := v_conn_ids[1];
  UPDATE public."SAAS_Disparos" SET "idConexoes"=v_conn_ids WHERE id=p_disparo_id;
  UPDATE public."SAAS_Detalhes_Disparos" SET "idConexao"=v_new_conn_id
    WHERE "idDisparo"=p_disparo_id AND "Status"='pending' AND ("idConexao"=p_blocked_conn_id OR "idConexao" IS NULL);
  IF hdr."contaId" IS NOT NULL THEN
    PERFORM public.resume_disparo(p_disparo_id, hdr."contaId");
  END IF;
END;
$$;

DROP FUNCTION IF EXISTS public.resume_disparo(bigint, text);
CREATE OR REPLACE FUNCTION public.resume_disparo(p_disparo_id bigint, p_user_id uuid)
RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE hdr record; v_base_ts timestamptz; v_cur_ts timestamptz; v_counter int := 0; v_gap int; v_days_arr int[]; rec_det record;
BEGIN
  PERFORM set_config('row_security', 'off', true);
  SELECT * INTO hdr FROM public."SAAS_Disparos" WHERE id=p_disparo_id AND "contaId"=p_user_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Usuário inválido'; END IF;
  hdr."intervaloMin" := COALESCE(hdr."intervaloMin", 15);
  hdr."intervaloMax" := COALESCE(hdr."intervaloMax", 15);
  hdr."PausaAposMensagens" := COALESCE(hdr."PausaAposMensagens", 0);
  hdr."PausaMinutos" := COALESCE(hdr."PausaMinutos", 0);
  hdr."StartTime" := COALESCE(hdr."StartTime", time '00:00');
  hdr."EndTime" := COALESCE(hdr."EndTime", time '23:59:59');
  v_days_arr := COALESCE(hdr."DiasSelecionados", ARRAY[]::smallint[])::int[];
  UPDATE public."SAAS_Disparos" SET "StatusDisparo" = 'Em andamento' WHERE id=p_disparo_id AND "StatusDisparo" = 'Pausado';
  v_base_ts := now() + interval '1 minute';
  IF hdr."DataAgendamento" IS NOT NULL AND hdr."DataAgendamento" > v_base_ts THEN v_base_ts := hdr."DataAgendamento"; END IF;
  v_cur_ts := f_next_valid_time(v_base_ts, hdr."StartTime", hdr."EndTime", v_days_arr);
  FOR rec_det IN SELECT * FROM public."SAAS_Detalhes_Disparos" WHERE "idDisparo"=p_disparo_id AND "Status"='pending' ORDER BY id
  LOOP
    IF hdr."PausaAposMensagens" > 0 AND v_counter > 0 AND v_counter % hdr."PausaAposMensagens" = 0 THEN
      v_cur_ts := v_cur_ts + make_interval(mins => hdr."PausaMinutos");
      v_cur_ts := f_next_valid_time(v_cur_ts, hdr."StartTime", hdr."EndTime", v_days_arr);
    END IF;
    UPDATE public."SAAS_Detalhes_Disparos" SET "dataEnvio" = v_cur_ts WHERE id = rec_det.id;
    v_counter := v_counter + 1;
    v_gap := hdr."intervaloMin" + floor(random() * (hdr."intervaloMax" - hdr."intervaloMin" + 1))::int;
    v_cur_ts := f_next_valid_time(v_cur_ts + make_interval(secs => v_gap), hdr."StartTime", hdr."EndTime", v_days_arr);
  END LOOP;
END;
$$;

DROP FUNCTION IF EXISTS public.pause_disparo(bigint, text);
CREATE OR REPLACE FUNCTION public.pause_disparo(p_disparo_id bigint, p_user_id uuid)
RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ BEGIN
  PERFORM set_config('row_security', 'off', true);
  IF NOT EXISTS (SELECT 1 FROM public."SAAS_Disparos" WHERE id=p_disparo_id AND "contaId"=p_user_id) THEN RAISE EXCEPTION 'Usuário inválido'; END IF;
  UPDATE public."SAAS_Disparos" SET "StatusDisparo"='Pausado' WHERE id=p_disparo_id;
END $$;

DROP FUNCTION IF EXISTS public.delete_disparo(bigint, text);
CREATE OR REPLACE FUNCTION public.delete_disparo(p_disparo_id bigint, p_user_id uuid)
RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ BEGIN
  PERFORM set_config('row_security', 'off', true);
  IF NOT EXISTS (SELECT 1 FROM public."SAAS_Disparos" WHERE id=p_disparo_id AND "contaId"=p_user_id) THEN RAISE EXCEPTION 'Usuário inválido'; END IF;
  DELETE FROM public."SAAS_Detalhes_Disparos" WHERE "idDisparo"=p_disparo_id;
  DELETE FROM public."SAAS_Disparos" WHERE id=p_disparo_id;
END $$;

CREATE OR REPLACE FUNCTION public.add_connections_disparo(p_disparo_id bigint, p_conn_ids bigint[], p_user_id uuid)
RETURNS void LANGUAGE plpgsql AS $$
DECLARE hdr record; v_all_conns bigint[]; v_conn_count int; v_idx_conn int := 1; v_cur_ts timestamptz; v_counter int := 0; v_gap int; rec_det record; v_first_ts timestamptz;
BEGIN
  SELECT * INTO hdr FROM public."SAAS_Disparos" WHERE id=p_disparo_id AND "contaId"=p_user_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Usuário inválido ou disparo inexistente'; END IF;
  SELECT array_agg(DISTINCT conn)::bigint[] INTO v_all_conns FROM unnest(COALESCE(hdr."idConexoes", array[]::bigint[]) || COALESCE(p_conn_ids, array[]::bigint[])) AS conn;
  v_conn_count := COALESCE(array_length(v_all_conns, 1), 0);
  IF v_conn_count = 0 THEN RAISE EXCEPTION 'É necessário fornecer pelo menos 1 conexão válida'; END IF;
  UPDATE public."SAAS_Disparos" SET "idConexoes" = v_all_conns WHERE id = p_disparo_id;
  v_cur_ts := f_next_valid_time(now() + interval '1 minute', hdr."StartTime", hdr."EndTime", COALESCE(hdr."DiasSelecionados", ARRAY[]::smallint[])::int[]);
  FOR rec_det IN SELECT * FROM public."SAAS_Detalhes_Disparos" WHERE "idDisparo"=p_disparo_id AND "Status"='pending' ORDER BY id
  LOOP
    IF hdr."PausaAposMensagens" > 0 AND v_counter > 0 AND v_counter % hdr."PausaAposMensagens" = 0 THEN
      v_cur_ts := v_cur_ts + make_interval(mins => hdr."PausaMinutos");
      v_cur_ts := f_next_valid_time(v_cur_ts, hdr."StartTime", hdr."EndTime", COALESCE(hdr."DiasSelecionados", ARRAY[]::smallint[])::int[]);
    END IF;
    UPDATE public."SAAS_Detalhes_Disparos" SET "idConexao"=v_all_conns[v_idx_conn], "dataEnvio"=v_cur_ts, "mensagemErro"=NULL WHERE id=rec_det.id;
    IF v_counter = 0 THEN v_first_ts := v_cur_ts; END IF;
    v_counter := v_counter + 1; v_idx_conn := (v_idx_conn % v_conn_count) + 1;
    v_gap := hdr."intervaloMin" + floor(random() * (hdr."intervaloMax" - hdr."intervaloMin" + 1))::int;
    v_cur_ts := f_next_valid_time(v_cur_ts + make_interval(secs => v_gap), hdr."StartTime", hdr."EndTime", COALESCE(hdr."DiasSelecionados", ARRAY[]::smallint[])::int[]);
  END LOOP;
  IF v_counter > 0 THEN
    UPDATE public."SAAS_Disparos" SET "StatusDisparo" = CASE WHEN v_first_ts <= now() THEN 'Em andamento' ELSE 'Aguardando' END WHERE id = p_disparo_id;
  END IF;
END;
$$;

