CREATE OR REPLACE FUNCTION public.f_upsert_conversas_agentes(p_items jsonb)
RETURNS jsonb LANGUAGE plpgsql AS $$
DECLARE v_item jsonb; v_inserted int := 0; v_skipped int := 0; v_exists boolean; v_telefone text; v_idconexao bigint; v_items jsonb;
BEGIN
  IF p_items IS NULL THEN RETURN jsonb_build_object('inserted', 0, 'skipped', 0, 'error', 'payload null'); END IF;
  IF jsonb_typeof(p_items) = 'array' THEN v_items := p_items;
  ELSIF jsonb_typeof(p_items) = 'object' AND (p_items ? 'data') AND jsonb_typeof(p_items->'data') = 'array' THEN v_items := p_items->'data';
  ELSE RETURN jsonb_build_object('inserted', 0, 'skipped', 0, 'error', 'payload deve ser array ou {"data": [...]}', 'received_type', jsonb_typeof(p_items)); END IF;
  IF jsonb_array_length(v_items) = 0 THEN RETURN jsonb_build_object('inserted', 0, 'skipped', 0, 'error', 'array vazio'); END IF;
  FOR v_item IN SELECT * FROM jsonb_array_elements(v_items) LOOP
    v_telefone := NULLIF(trim(v_item->>'telefone'), ''); v_idconexao := (v_item->>'idConexao')::bigint;
    IF v_telefone IS NULL AND v_idconexao IS NULL THEN CONTINUE; END IF;
    SELECT EXISTS (SELECT 1 FROM public."SAAS_Conversas_Agentes" WHERE (telefone IS NOT DISTINCT FROM v_telefone) AND ("idConexao" IS NOT DISTINCT FROM v_idconexao)) INTO v_exists;
    IF v_exists THEN v_skipped := v_skipped + 1; CONTINUE; END IF;
    INSERT INTO public."SAAS_Conversas_Agentes" (telefone, "nomeConversa", "statusAtendimento", "idConexao", pausado, "contaId", lida, "fotoPerfil")
    VALUES (v_telefone, NULLIF(trim(v_item->>'nomeConversa'), ''), COALESCE(NULLIF(trim(lower(v_item->>'statusAtendimento')), ''), 'aberto'), v_idconexao,
            COALESCE((v_item->>'pausado')::boolean, false), (v_item->>'userId')::uuid, COALESCE((v_item->>'lida')::boolean, false), NULLIF(trim(v_item->>'fotoPerfil'), ''));
    v_inserted := v_inserted + 1;
  END LOOP;
  RETURN jsonb_build_object('inserted', v_inserted, 'skipped', v_skipped);
EXCEPTION WHEN OTHERS THEN RETURN jsonb_build_object('inserted', v_inserted, 'skipped', v_skipped, 'error', SQLERRM);
END;
$$;

CREATE OR REPLACE FUNCTION public.f_inserir_mensagens_conversa(p_mensagens jsonb, p_user_id uuid, p_conversa_id bigint, p_conexao_id bigint)
RETURNS jsonb LANGUAGE plpgsql AS $$
DECLARE v_item jsonb; v_items jsonb; v_inserted int := 0; v_skipped int := 0; v_msg_text text; v_tipo text; v_arquivo text; v_from_me boolean; v_ev_id text; v_respondida text; v_created timestamptz;
BEGIN
  IF p_mensagens IS NULL THEN RETURN jsonb_build_object('inserted', 0, 'skipped', 0, 'error', 'payload null'); END IF;
  IF jsonb_typeof(p_mensagens) = 'array' THEN v_items := p_mensagens;
  ELSIF jsonb_typeof(p_mensagens) = 'object' AND (p_mensagens ? 'data') AND jsonb_typeof(p_mensagens->'data') = 'array' THEN v_items := p_mensagens->'data';
  ELSE RETURN jsonb_build_object('inserted', 0, 'skipped', 0, 'error', 'payload deve ser array ou {"data": [...]}'); END IF;
  IF jsonb_array_length(v_items) = 0 THEN RETURN jsonb_build_object('inserted', 0, 'skipped', 0, 'error', 'array vazio'); END IF;
  FOR v_item IN SELECT * FROM jsonb_array_elements(v_items) LOOP
    v_ev_id := NULLIF(trim(v_item->>'id'), '');
    IF v_ev_id IS NOT NULL AND EXISTS (SELECT 1 FROM public."SAAS_Mensagens" WHERE "messageEvolutionId" = v_ev_id AND "conversaId" = p_conversa_id) THEN v_skipped := v_skipped + 1; CONTINUE; END IF;
    v_tipo := COALESCE(NULLIF(trim(lower(v_item->>'messageType')), ''), 'conversation'); v_from_me := COALESCE((v_item->'key'->>'fromMe')::boolean, false);
    v_msg_text := v_item->'message'->>'conversation'; IF v_msg_text IS NULL THEN v_msg_text := v_item->'message'->'extendedTextMessage'->>'text'; END IF;
    IF v_msg_text IS NULL THEN v_msg_text := v_item->'message'->'imageMessage'->>'caption'; END IF;
    IF v_msg_text IS NULL THEN v_msg_text := v_item->'message'->'videoMessage'->>'caption'; END IF;
    IF v_msg_text IS NULL THEN v_msg_text := v_item->'message'->'documentMessage'->>'caption'; END IF;
    v_arquivo := v_item->'message'->'imageMessage'->>'url'; IF v_arquivo IS NULL THEN v_arquivo := v_item->'message'->'audioMessage'->>'url'; END IF;
    IF v_arquivo IS NULL THEN v_arquivo := v_item->'message'->'videoMessage'->>'url'; END IF;
    IF v_arquivo IS NULL THEN v_arquivo := v_item->'message'->'documentMessage'->>'url'; END IF;
    v_respondida := NULL; IF v_item->'contextInfo' IS NOT NULL AND v_item->'contextInfo' != 'null'::jsonb THEN
      v_respondida := v_item->'contextInfo'->>'stanzaId'; IF v_respondida IS NULL THEN v_respondida := v_item->'contextInfo'->>'quotedMessageId'; END IF;
    END IF;
    IF (v_item->>'messageTimestamp') IS NOT NULL AND (v_item->>'messageTimestamp') ~ '^\d+$' THEN v_created := to_timestamp((v_item->>'messageTimestamp')::numeric); ELSE v_created := now(); END IF;
    INSERT INTO public."SAAS_Mensagens" (created_at, "contaId", "conexaoId", "conversaId", mensagem, "tipoMensagem", "arquivoUrl", "fromMe", apagada, "messageEvolutionId", "mensagemRespondida", enviada, "IA")
    VALUES (v_created, p_user_id, p_conexao_id, p_conversa_id, NULLIF(trim(v_msg_text), ''), v_tipo, NULLIF(trim(v_arquivo), ''), v_from_me, false, v_ev_id, NULLIF(trim(v_respondida), ''), true, NULL);
    v_inserted := v_inserted + 1;
  END LOOP;
  RETURN jsonb_build_object('inserted', v_inserted, 'skipped', v_skipped);
EXCEPTION WHEN OTHERS THEN RETURN jsonb_build_object('inserted', v_inserted, 'skipped', v_skipped, 'error', SQLERRM);
END;
$$;

CREATE OR REPLACE FUNCTION public.f_conversa_ou_mensagem(p_telefone text, p_idconexao bigint, p_user_id uuid, p_mensagem text, p_message_evolution_id text DEFAULT NULL, p_id_agente bigint DEFAULT NULL)
RETURNS jsonb LANGUAGE plpgsql AS $$
DECLARE v_conversa_id bigint; v_mensagem_id bigint; v_created_conv boolean := false;
BEGIN
  IF NULLIF(trim(p_telefone), '') IS NULL OR p_idconexao IS NULL OR p_user_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'telefone, idConexao e userId (contaId) são obrigatórios');
  END IF;
  SELECT id INTO v_conversa_id FROM public."SAAS_Conversas_Agentes" WHERE telefone = p_telefone AND "idConexao" = p_idconexao LIMIT 1;
  IF v_conversa_id IS NULL THEN
    INSERT INTO public."SAAS_Conversas_Agentes" (telefone, "idConexao", "contaId", "idAgente", "nomeConversa", "fotoPerfil", "statusAtendimento")
    VALUES (p_telefone, p_idconexao, p_user_id, p_id_agente, NULL, NULL, 'aberto') RETURNING id INTO v_conversa_id;
    v_created_conv := true;
  ELSE
    UPDATE public."SAAS_Conversas_Agentes" SET "idAgente" = p_id_agente WHERE id = v_conversa_id;
  END IF;
  INSERT INTO public."SAAS_Mensagens" ("contaId", "conexaoId", "conversaId", mensagem, "tipoMensagem", "fromMe", apagada, "messageEvolutionId", enviada, "IA")
  VALUES (p_user_id, p_conexao_id, v_conversa_id, NULLIF(trim(p_mensagem), ''), 'conversation', true, false, NULLIF(trim(p_message_evolution_id), ''), true, true)
  RETURNING id INTO v_mensagem_id;
  RETURN jsonb_build_object('ok', true, 'conversaId', v_conversa_id, 'mensagemId', v_mensagem_id, 'conversaCriada', v_created_conv);
EXCEPTION WHEN OTHERS THEN RETURN jsonb_build_object('ok', false, 'error', SQLERRM);
END;
$$;

CREATE OR REPLACE FUNCTION public.f_mensagem_por_contato(
  p_contato_id bigint,
  p_id_conexao bigint,
  p_conta_id uuid,
  p_mensagem text DEFAULT NULL,
  p_url_arquivo text DEFAULT NULL,
  p_tipo_mensagem text DEFAULT 'conversation'
)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_conversa_id bigint;
  v_mensagem_id bigint;
  v_conversa_criada boolean := false;
  v_tipo_mensagem text;
  v_mensagem text;
  v_url_arquivo text;
  v_telefone text;
  v_nome_contato text;
  v_foto_contato text;
BEGIN
  IF p_contato_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'contatoId é obrigatório');
  END IF;
  IF p_id_conexao IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'idConexao é obrigatório');
  END IF;
  IF p_conta_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'contaId é obrigatório');
  END IF;

  v_mensagem := NULLIF(trim(COALESCE(p_mensagem, '')), '');
  v_url_arquivo := NULLIF(trim(COALESCE(p_url_arquivo, '')), '');
  v_tipo_mensagem := COALESCE(NULLIF(trim(COALESCE(p_tipo_mensagem, '')), ''), 'conversation');

  IF v_mensagem IS NULL AND v_url_arquivo IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'mensagem ou urlArquivo é obrigatório');
  END IF;

  SELECT
    NULLIF(trim(COALESCE(c.telefone, '')), ''),
    NULLIF(trim(COALESCE(c.nome, '')), ''),
    NULLIF(trim(COALESCE(c."fotoPerfil", '')), '')
  INTO v_telefone, v_nome_contato, v_foto_contato
  FROM public."SAAS_Contatos" c
  WHERE c.id = p_contato_id
    AND c."contaId" = p_conta_id
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'error', 'contatoId não encontrado para a conta informada');
  END IF;

  SELECT ca.id
  INTO v_conversa_id
  FROM public."SAAS_Conversas_Agentes" ca
  WHERE ca."contatoId" = p_contato_id
    AND ca."idConexao" = p_id_conexao
    AND ca."contaId" = p_conta_id
  ORDER BY ca.id DESC
  LIMIT 1;

  IF v_conversa_id IS NULL THEN
    BEGIN
      INSERT INTO public."SAAS_Conversas_Agentes" (
        "contaId", "idConexao", "contatoId", telefone, "nomeConversa", "fotoPerfil", lida, "statusAtendimento"
      )
      VALUES (
        p_conta_id, p_id_conexao, p_contato_id, v_telefone, v_nome_contato, v_foto_contato, false, 'aberto'
      )
      RETURNING id INTO v_conversa_id;
      v_conversa_criada := true;
    EXCEPTION
      WHEN unique_violation THEN
        SELECT ca.id
        INTO v_conversa_id
        FROM public."SAAS_Conversas_Agentes" ca
        WHERE ca."contatoId" = p_contato_id
          AND ca."idConexao" = p_id_conexao
          AND ca."contaId" = p_conta_id
        ORDER BY ca.id DESC
        LIMIT 1;
    END;
  END IF;

  -- Mensagem enviada pelo usuário/atendente do sistema
  INSERT INTO public."SAAS_Mensagens" (
    "contaId", "conexaoId", "conversaId", mensagem, "tipoMensagem", "arquivoUrl", "fromMe", apagada, enviada, "IA"
  )
  VALUES (
    p_conta_id, p_id_conexao, v_conversa_id, v_mensagem, v_tipo_mensagem, v_url_arquivo, true, false, true, false
  )
  RETURNING id INTO v_mensagem_id;

  -- Conversa deve permanecer como não lida no fluxo solicitado
  UPDATE public."SAAS_Conversas_Agentes"
     SET lida = false
   WHERE id = v_conversa_id;

  RETURN jsonb_build_object(
    'ok', true,
    'conversaId', v_conversa_id,
    'mensagemId', v_mensagem_id,
    'conversaCriada', v_conversa_criada
  );
EXCEPTION
  WHEN OTHERS THEN
    RETURN jsonb_build_object('ok', false, 'error', SQLERRM);
END;
$$;

CREATE OR REPLACE FUNCTION public.f_ingestao_mensagem_internal(
  p_conexao_id bigint,
  p_telefone text,
  p_mensagem text,
  p_tipo_mensagem text,
  p_from_me boolean,
  p_arquivo_url text DEFAULT NULL,
  p_nome_conversa text DEFAULT NULL,
  p_foto_perfil text DEFAULT NULL,
  p_message_evolution_id text DEFAULT NULL,
  p_apagada boolean DEFAULT false,
  p_mensagem_respondida text DEFAULT NULL,
  p_lid text DEFAULT NULL
)
RETURNS jsonb
LANGUAGE plpgsql
AS $$
DECLARE
  v_conta_id uuid;
  v_telefone_input text;
  v_lid_input text;
  v_is_lid boolean := false;
  v_telefone_sem_sufixo text;
  v_telefone_base text;
  v_telefone_alt text;
  v_candidatos_telefone text[] := ARRAY[]::text[];
  v_contato_telefone text;
  v_contato_id bigint;
  v_conversa_id bigint;
  v_mensagem_id bigint;
  v_conexao jsonb;
  v_agente jsonb;
  v_agente_id bigint;
  v_agente_pausar boolean := false;
  v_conversa_pausada boolean := false;
  v_status_atual text;
  v_conversa_criada boolean := false;
  v_contato_criado boolean := false;
  v_card_criado boolean := false;
  v_card_id bigint;
  v_mensagem_criada boolean := false;
  v_credito_esgotado boolean := false;
  v_segue_fluxo_ia boolean := false;
  v_parou_por_pausado boolean := false;
  v_abriu_atendimento_humano boolean := false;
  v_quadro_id bigint;
  v_etapa_id bigint;
  v_plano_qnt_creditos numeric;
  v_total_creditos numeric;
BEGIN
  IF p_conexao_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'conexaoId é obrigatório');
  END IF;
  IF NULLIF(trim(COALESCE(p_telefone, '')), '') IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'telefone é obrigatório');
  END IF;
  IF NULLIF(trim(COALESCE(p_tipo_mensagem, '')), '') IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'tipoMensagem é obrigatório');
  END IF;

  SELECT c."contaId", to_jsonb(c.*)
    INTO v_conta_id, v_conexao
    FROM public."SAAS_Conexões" c
   WHERE c.id = p_conexao_id
   LIMIT 1;

  IF v_conta_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'conexaoId inválido ou sem conta vinculada');
  END IF;

  v_telefone_input := trim(p_telefone);
  v_is_lid := lower(v_telefone_input) LIKE '%@lid';
  v_lid_input := NULLIF(trim(COALESCE(p_lid, '')), '');
  IF v_is_lid AND v_lid_input IS NULL THEN
    v_lid_input := v_telefone_input;
  END IF;

  IF v_is_lid THEN
    -- Para @lid: 1) tenta por coluna lid
    SELECT c.id, c.telefone
      INTO v_contato_id, v_contato_telefone
      FROM public."SAAS_Contatos" c
     WHERE c."contaId" = v_conta_id
       AND c.lid = v_lid_input
     LIMIT 1;

    -- Para @lid: 2) se não achou, tenta por coluna telefone
    IF v_contato_id IS NULL THEN
      SELECT c.id, c.telefone
        INTO v_contato_id, v_contato_telefone
        FROM public."SAAS_Contatos" c
       WHERE c."contaId" = v_conta_id
         AND c.telefone = v_telefone_input
       LIMIT 1;
    END IF;
  ELSE
    v_telefone_sem_sufixo := regexp_replace(v_telefone_input, '@s\.whatsapp\.net$', '', 'i');
    v_telefone_base := regexp_replace(v_telefone_sem_sufixo, '\D', '', 'g');

    IF v_telefone_base ~ '^55\d{10,11}$' THEN
      -- Regra do nono dígito para BR (DDI 55 + DDD + número local)
      IF length(v_telefone_base) = 13 AND substring(v_telefone_base from 5 for 1) = '9' THEN
        v_telefone_alt := substring(v_telefone_base from 1 for 4) || substring(v_telefone_base from 6);
      ELSIF length(v_telefone_base) = 12 THEN
        v_telefone_alt := substring(v_telefone_base from 1 for 4) || '9' || substring(v_telefone_base from 5);
      END IF;
    END IF;

    v_candidatos_telefone := array_remove(ARRAY[
      v_telefone_input,
      v_telefone_sem_sufixo,
      CASE WHEN v_telefone_sem_sufixo <> '' THEN v_telefone_sem_sufixo || '@s.whatsapp.net' END,
      v_telefone_base,
      CASE WHEN v_telefone_base <> '' THEN v_telefone_base || '@s.whatsapp.net' END,
      v_telefone_alt,
      CASE WHEN NULLIF(trim(COALESCE(v_telefone_alt, '')), '') IS NOT NULL THEN v_telefone_alt || '@s.whatsapp.net' END
    ], NULL);

    SELECT c.id, c.telefone
      INTO v_contato_id, v_contato_telefone
      FROM public."SAAS_Contatos" c
     WHERE c."contaId" = v_conta_id
       AND c.telefone = ANY(v_candidatos_telefone)
     ORDER BY CASE c.telefone
       WHEN v_telefone_input THEN 1
       WHEN v_telefone_sem_sufixo THEN 2
       WHEN v_telefone_base THEN 3
       WHEN v_telefone_alt THEN 4
       WHEN COALESCE(v_telefone_alt, '') || '@s.whatsapp.net' THEN 5
       ELSE 99
     END
     LIMIT 1;
  END IF;

  IF v_contato_id IS NULL THEN
    INSERT INTO public."SAAS_Contatos" (nome, telefone, "fotoPerfil", tipo, variaveis, "contaId", lid)
    VALUES (
      NULLIF(trim(COALESCE(p_nome_conversa, '')), ''),
      v_telefone_input,
      NULLIF(trim(COALESCE(p_foto_perfil, '')), ''),
      'contato',
      '{}'::jsonb,
      v_conta_id,
      v_lid_input
    )
    RETURNING id, telefone INTO v_contato_id, v_contato_telefone;
    v_contato_criado := true;
  ELSIF v_lid_input IS NOT NULL THEN
    UPDATE public."SAAS_Contatos"
       SET lid = COALESCE(NULLIF(trim(COALESCE(lid, '')), ''), v_lid_input, lid),
           nome = COALESCE(NULLIF(trim(COALESCE(nome, '')), ''), NULLIF(trim(COALESCE(p_nome_conversa, '')), ''), nome),
           "fotoPerfil" = COALESCE(NULLIF(trim(COALESCE("fotoPerfil", '')), ''), NULLIF(trim(COALESCE(p_foto_perfil, '')), ''), "fotoPerfil")
     WHERE id = v_contato_id
     RETURNING telefone INTO v_contato_telefone;
  ELSE
    UPDATE public."SAAS_Contatos"
       SET nome = COALESCE(NULLIF(trim(COALESCE(nome, '')), ''), NULLIF(trim(COALESCE(p_nome_conversa, '')), ''), nome),
           "fotoPerfil" = COALESCE(NULLIF(trim(COALESCE("fotoPerfil", '')), ''), NULLIF(trim(COALESCE(p_foto_perfil, '')), ''), "fotoPerfil")
     WHERE id = v_contato_id
    RETURNING telefone INTO v_contato_telefone;
  END IF;

  SELECT c.id, c.pausado, c."statusAtendimento"
    INTO v_conversa_id, v_conversa_pausada, v_status_atual
    FROM public."SAAS_Conversas_Agentes" c
   WHERE c."contatoId" = v_contato_id
     AND c."idConexao" = p_conexao_id
   LIMIT 1;

  IF v_conversa_id IS NULL THEN
    INSERT INTO public."SAAS_Conversas_Agentes" (
      "contaId", "idConexao", "contatoId", telefone, pausado, "ultimaMensagem", lida, "statusAtendimento"
    )
    VALUES (
      v_conta_id,
      p_conexao_id,
      v_contato_id,
      COALESCE(v_contato_telefone, v_telefone_input),
      false,
      now(),
      COALESCE(p_from_me, false),
      'aguardando'
    )
    RETURNING id INTO v_conversa_id;
    v_conversa_criada := true;
    v_conversa_pausada := false;
  ELSE
    UPDATE public."SAAS_Conversas_Agentes"
       SET "ultimaMensagem" = now(),
           lida = CASE WHEN COALESCE(p_from_me, false) THEN true ELSE false END,
           "statusAtendimento" = CASE
             WHEN lower(trim(COALESCE("statusAtendimento", ''))) = 'fechado' THEN 'aguardando'
             ELSE "statusAtendimento"
           END
     WHERE id = v_conversa_id;

    SELECT pausado INTO v_conversa_pausada
      FROM public."SAAS_Conversas_Agentes"
     WHERE id = v_conversa_id;
  END IF;

  -- Inserção robusta sem depender de ON CONFLICT (evita erro em ambientes sem constraint única).
  IF p_message_evolution_id IS NOT NULL AND trim(p_message_evolution_id) <> '' THEN
    SELECT m.id INTO v_mensagem_id
      FROM public."SAAS_Mensagens" m
     WHERE m."conversaId" = v_conversa_id
       AND m."messageEvolutionId" = trim(p_message_evolution_id)
     LIMIT 1;
  END IF;

  IF v_mensagem_id IS NULL THEN
    INSERT INTO public."SAAS_Mensagens" (
      "contaId", "conexaoId", "conversaId", mensagem, "tipoMensagem", "arquivoUrl",
      "fromMe", apagada, "messageEvolutionId", "mensagemRespondida", enviada, "IA"
    )
    VALUES (
      v_conta_id, p_conexao_id, v_conversa_id, NULLIF(trim(COALESCE(p_mensagem, '')), ''),
      trim(p_tipo_mensagem), NULLIF(trim(COALESCE(p_arquivo_url, '')), ''),
      COALESCE(p_from_me, false), COALESCE(p_apagada, false), NULLIF(trim(COALESCE(p_message_evolution_id, '')), ''),
      NULLIF(trim(COALESCE(p_mensagem_respondida, '')), ''), true, NULL
    )
    RETURNING id INTO v_mensagem_id;
    v_mensagem_criada := true;
  END IF;

  SELECT to_jsonb(a.*), a.id, COALESCE(a."pausarAtendimento", false)
    INTO v_agente, v_agente_id, v_agente_pausar
    FROM public."SAAS_AgentesIA" a
   WHERE a."contaId" = v_conta_id
     AND a."conexaoId" = p_conexao_id
     AND COALESCE(a.ativo, true) = true
   ORDER BY a.created_at DESC
   LIMIT 1;

  IF v_agente_id IS NOT NULL THEN
    UPDATE public."SAAS_Conversas_Agentes"
       SET "idAgente" = v_agente_id
     WHERE id = v_conversa_id
       AND ("idAgente" IS DISTINCT FROM v_agente_id);

    v_quadro_id := COALESCE(
      NULLIF(v_agente->'CRM'->>'idCRM', '')::bigint,
      NULLIF(v_agente->'CRM'->>'quadroId', '')::bigint
    );
    v_etapa_id := COALESCE(
      NULLIF(v_agente->'CRM'->>'idEtapa', '')::bigint,
      NULLIF(v_agente->'CRM'->>'etapaId', '')::bigint
    );

    IF v_quadro_id IS NOT NULL AND v_etapa_id IS NOT NULL THEN
      SELECT q.id INTO v_card_id
        FROM public."SAAS_Cards_Quadros" q
       WHERE q."quadroId" = v_quadro_id
         AND q."contatoId" = v_contato_id
       LIMIT 1;

      -- Card legado: mesmo quadro e telefone em `contato`, mas sem contatoId (ou divergente) — vincula ao contato atual
      IF v_card_id IS NULL THEN
        SELECT q.id INTO v_card_id
          FROM public."SAAS_Cards_Quadros" q
         WHERE q."quadroId" = v_quadro_id
           AND (
             NULLIF(trim(COALESCE(q.contato, '')), '') IS NOT NULL
             AND (
               trim(COALESCE(q.contato, '')) = trim(COALESCE(v_contato_telefone, v_telefone_input, ''))
               OR trim(COALESCE(q.contato, '')) = trim(COALESCE(v_telefone_input, ''))
               OR (v_contato_telefone IS NOT NULL AND trim(COALESCE(q.contato, '')) = trim(COALESCE(v_contato_telefone, '')))
             )
           )
         ORDER BY CASE WHEN q."contatoId" IS NULL THEN 0 ELSE 1 END, q.id DESC
         LIMIT 1;

        IF v_card_id IS NOT NULL THEN
          UPDATE public."SAAS_Cards_Quadros" c
             SET "contatoId" = v_contato_id,
                 nome = COALESCE(NULLIF(trim(COALESCE(c.nome, '')), ''), NULLIF(trim(COALESCE(p_nome_conversa, '')), ''), c.nome),
                 contato = COALESCE(NULLIF(trim(COALESCE(v_contato_telefone, '')), ''), NULLIF(trim(COALESCE(v_telefone_input, '')), ''), c.contato)
           WHERE c.id = v_card_id
             AND (c."contatoId" IS DISTINCT FROM v_contato_id OR c."contatoId" IS NULL);
        END IF;
      END IF;

      IF v_card_id IS NULL THEN
        INSERT INTO public."SAAS_Cards_Quadros" ("quadroId", "contatoId", "etapaQuadroId", nome, contato)
        VALUES (
          v_quadro_id,
          v_contato_id,
          v_etapa_id,
          COALESCE(NULLIF(trim(COALESCE(p_nome_conversa, '')), ''), COALESCE(v_contato_telefone, v_telefone_input)),
          COALESCE(v_contato_telefone, v_telefone_input)
        )
        RETURNING id INTO v_card_id;
        v_card_criado := true;
      END IF;
    END IF;
  END IF;

  SELECT v."planoQntCreditos", v.total_creditos
    INTO v_plano_qnt_creditos, v_total_creditos
    FROM public."vw_Contas_Com_Plano" v
   WHERE v.id = v_conta_id
   LIMIT 1;

  IF v_plano_qnt_creditos IS NOT NULL THEN
    v_credito_esgotado := COALESCE(v_total_creditos, 0) >= COALESCE(v_plano_qnt_creditos, 0);
  ELSE
    v_credito_esgotado := false;
  END IF;

  IF NOT v_credito_esgotado AND v_agente_id IS NOT NULL THEN
    IF COALESCE(p_from_me, false) THEN
      IF v_agente_pausar THEN
        UPDATE public."SAAS_Conversas_Agentes"
           SET "statusAtendimento" = 'aberto',
               pausado = true
         WHERE id = v_conversa_id;
        v_abriu_atendimento_humano := true;
      END IF;
      v_segue_fluxo_ia := false;
    ELSE
      SELECT pausado INTO v_conversa_pausada
        FROM public."SAAS_Conversas_Agentes"
       WHERE id = v_conversa_id;

      IF COALESCE(v_conversa_pausada, false) THEN
        UPDATE public."SAAS_Conversas_Agentes" SET lida = false WHERE id = v_conversa_id;
        v_parou_por_pausado := true;
        v_segue_fluxo_ia := false;
      ELSE
        v_segue_fluxo_ia := true;
      END IF;
    END IF;
  ELSE
    v_segue_fluxo_ia := false;
  END IF;

  RETURN jsonb_build_object(
    'ok', true,
    'contaId', v_conta_id,
    'conexaoId', p_conexao_id,
    'contatoId', v_contato_id,
    'conversaId', v_conversa_id,
    'mensagemId', v_mensagem_id,
    'contatoCriado', v_contato_criado,
    'conversaCriada', v_conversa_criada,
    'mensagemCriada', v_mensagem_criada,
    'cardCriado', v_card_criado,
    'cardId', v_card_id,
    'creditoEsgotado', v_credito_esgotado,
    'parouPorPausado', v_parou_por_pausado,
    'abriuAtendimentoHumano', v_abriu_atendimento_humano,
    'segueFluxoIA', v_segue_fluxo_ia,
    'conexao', v_conexao,
    'agente', v_agente
  );
EXCEPTION
  WHEN OTHERS THEN
    RETURN jsonb_build_object('ok', false, 'error', SQLERRM);
END;
$$;

-- Mantém apenas a função pública JSONB; remove assinatura antiga para evitar overload.
DROP FUNCTION IF EXISTS public.f_ingestao_mensagem(
  bigint, text, text, text, boolean, text, text, text, text, boolean, text, text
);

-- Overload: aceita JSONB (array com 1 objeto)
CREATE OR REPLACE FUNCTION public.f_ingestao_mensagem(p_input jsonb)
RETURNS jsonb
LANGUAGE plpgsql
AS $$
DECLARE
  v_item jsonb;
  v_data jsonb;
  v_evolu jsonb;
  v_conexao_id bigint;
  v_telefone text;
  v_mensagem text;
  v_tipo_mensagem text;
  v_from_me boolean;
  v_arquivo_url text;
  v_nome_conversa text;
  v_foto_perfil text;
  v_message_evolution_id text;
  v_apagada boolean;
  v_mensagem_respondida text;
  v_lid text;
  v_resultado jsonb;
  v_contato_id bigint;
  v_contato_criado boolean;
  v_foto_atual text;
  v_foto_url text;
  v_evolu_url text;
  v_http_body jsonb;
BEGIN
  -- Aceita array ou objeto único
  IF jsonb_typeof(p_input) = 'array' THEN
    v_item := p_input->0;
  ELSE
    v_item := p_input;
  END IF;

  v_data := v_item->'data';
  v_evolu := v_item->'evolu';

  -- Campos obrigatórios
  v_conexao_id := (v_item->'conexao'->>'id')::bigint;
  v_telefone := v_data->>'remoteJid';
  v_mensagem := v_data->>'conversation';
  v_tipo_mensagem := v_data->>'messageType';
  v_from_me := COALESCE((v_data->>'fromMe')::boolean, false);

  -- Campos opcionais
  v_arquivo_url := v_data->>'arquivoUrl';
  v_nome_conversa := v_data->>'pushName';
  v_foto_perfil := v_data->>'fotoPerfil';
  v_message_evolution_id := v_data->>'id';
  v_apagada := COALESCE((v_data->>'apagada')::boolean, false);
  v_mensagem_respondida := v_data->>'mensagemRespondida';
  v_lid := NULLIF(COALESCE(v_data->>'lid', ''), '');

  -- Chama a função original
  v_resultado := public.f_ingestao_mensagem_internal(
    v_conexao_id,
    v_telefone,
    v_mensagem,
    v_tipo_mensagem,
    v_from_me,
    v_arquivo_url,
    v_nome_conversa,
    v_foto_perfil,
    v_message_evolution_id,
    v_apagada,
    v_mensagem_respondida,
    v_lid
  );

  -- Busca foto de perfil via Evolution API se contato novo ou sem foto
  IF (v_resultado->>'ok')::boolean
     AND v_evolu IS NOT NULL
     AND v_evolu->>'server_url' IS NOT NULL
     AND v_evolu->>'instance' IS NOT NULL
     AND v_evolu->>'apikey' IS NOT NULL
     AND v_telefone IS NOT NULL
  THEN
    v_contato_id := (v_resultado->>'contatoId')::bigint;
    v_contato_criado := COALESCE((v_resultado->>'contatoCriado')::boolean, false);

    -- Verifica se foto está vazia
    SELECT NULLIF(trim(COALESCE("fotoPerfil", '')), '')
      INTO v_foto_atual
      FROM public."SAAS_Contatos"
     WHERE id = v_contato_id;

    IF v_contato_criado OR v_foto_atual IS NULL THEN
      BEGIN
        v_evolu_url := rtrim(v_evolu->>'server_url', '/')
                       || '/chat/fetchProfilePictureUrl/'
                       || (v_evolu->>'instance');

        -- SQL dinâmico: usa schema public (Supabase costuma instalar pg_http em public, não em extensions).
        EXECUTE format(
          'SELECT CASE WHEN (r.resp).status = 200
                      THEN NULLIF(trim(COALESCE(((r.resp).content::jsonb)->>''profilePictureUrl'', '''')), '''')
                      ELSE NULL
                 END
           FROM (
             SELECT public.http(
               (''POST'', %L,
                ARRAY[public.http_header(''apikey'', %L)],
                ''application/json'',
                %L
               )::public.http_request
             ) AS resp
           ) r',
          v_evolu_url,
          v_evolu->>'apikey',
          jsonb_build_object('number', v_telefone)::text
        ) INTO v_foto_url;

        IF v_foto_url IS NOT NULL THEN
          UPDATE public."SAAS_Contatos"
             SET "fotoPerfil" = v_foto_url
           WHERE id = v_contato_id;
        END IF;
      EXCEPTION
        WHEN OTHERS THEN
          NULL;
      END;
    END IF;
  END IF;

  RETURN v_resultado;
END;
$$;

CREATE OR REPLACE FUNCTION public.f_vincular_contatos_conversas_por_telefone()
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_novos_contatos bigint := 0;
  v_conversas_vinculadas bigint := 0;
BEGIN
  -- 1) Contatos que já existem com número sem sufixo: atualiza telefone para incluir @s.whatsapp.net
  UPDATE public."SAAS_Contatos" ct
     SET telefone = ct.telefone || '@s.whatsapp.net'
    FROM (
      SELECT DISTINCT c."contaId" AS conta_id, c.telefone AS tel_conversa
        FROM public."SAAS_Conversas_Agentes" c
       WHERE c."contaId" IS NOT NULL
         AND c.telefone IS NOT NULL
         AND trim(c.telefone) <> ''
         AND c.telefone LIKE '%@s.whatsapp.net'
    ) src
   WHERE ct."contaId" = src.conta_id
     AND ct.telefone = replace(src.tel_conversa, '@s.whatsapp.net', '')
     AND ct.telefone NOT LIKE '%@s.whatsapp.net';

  -- 2) Garante que todos os telefones de conversas tenham contato correspondente,
  -- aproveitando nomeConversa/fotoPerfil da conversa para preencher contato.
  WITH src AS (
    SELECT
      c.id AS conversa_id,
      c."contaId" AS conta_id,
      c.telefone AS telefone,
      NULLIF(trim(COALESCE(c."nomeConversa", '')), '') AS nome_conversa,
      NULLIF(trim(COALESCE(c."fotoPerfil", '')), '') AS foto_perfil
    FROM public."SAAS_Conversas_Agentes" c
    WHERE c."contaId" IS NOT NULL
      AND c.telefone IS NOT NULL
      AND trim(c.telefone) <> ''
  ),
  src_dedup AS (
    SELECT DISTINCT ON (s.conta_id, s.telefone)
      s.conta_id, s.telefone, s.nome_conversa, s.foto_perfil
    FROM src s
    ORDER BY s.conta_id, s.telefone, s.conversa_id
  ),
  to_insert AS (
    SELECT d.*
    FROM src_dedup d
    LEFT JOIN public."SAAS_Contatos" ct
      ON ct."contaId" = d.conta_id
     AND ct.telefone = d.telefone
    WHERE ct.id IS NULL
  ),
  ins AS (
    INSERT INTO public."SAAS_Contatos" (nome, telefone, "fotoPerfil", tipo, variaveis, "contaId")
    SELECT
      t.nome_conversa,
      t.telefone,
      t.foto_perfil,
      'contato',
      '{}'::jsonb,
      t.conta_id
    FROM to_insert t
    RETURNING id
  )
  SELECT COUNT(*) INTO v_novos_contatos FROM ins;

  -- 3) Atualiza dados faltantes (nome/foto) no contato a partir da conversa
  WITH src AS (
    SELECT
      c."contaId" AS conta_id,
      c.telefone AS telefone,
      NULLIF(trim(COALESCE(c."nomeConversa", '')), '') AS nome_conversa,
      NULLIF(trim(COALESCE(c."fotoPerfil", '')), '') AS foto_perfil
    FROM public."SAAS_Conversas_Agentes" c
    WHERE c."contaId" IS NOT NULL
      AND c.telefone IS NOT NULL
      AND trim(c.telefone) <> ''
  )
  UPDATE public."SAAS_Contatos" ct
     SET nome = COALESCE(NULLIF(trim(COALESCE(ct.nome, '')), ''), src.nome_conversa, ct.nome),
         "fotoPerfil" = COALESCE(NULLIF(trim(COALESCE(ct."fotoPerfil", '')), ''), src.foto_perfil, ct."fotoPerfil")
    FROM src
   WHERE ct."contaId" = src.conta_id
     AND ct.telefone = src.telefone
     AND (
       (NULLIF(trim(COALESCE(ct.nome, '')), '') IS NULL AND src.nome_conversa IS NOT NULL)
       OR (NULLIF(trim(COALESCE(ct."fotoPerfil", '')), '') IS NULL AND src.foto_perfil IS NOT NULL)
     );

  -- 4) Vincula contatoId em todas as conversas pelo par contaId+telefone
  WITH upd AS (
    UPDATE public."SAAS_Conversas_Agentes" c
       SET "contatoId" = ct.id
      FROM public."SAAS_Contatos" ct
     WHERE c."contaId" = ct."contaId"
       AND c.telefone = ct.telefone
       AND c.telefone IS NOT NULL
       AND trim(c.telefone) <> ''
       AND (c."contatoId" IS DISTINCT FROM ct.id)
    RETURNING c.id
  )
  SELECT COUNT(*) INTO v_conversas_vinculadas FROM upd;

  RETURN jsonb_build_object(
    'ok', true,
    'contatosCriados', v_novos_contatos,
    'conversasVinculadas', v_conversas_vinculadas
  );
EXCEPTION
  WHEN OTHERS THEN
    RETURN jsonb_build_object('ok', false, 'error', SQLERRM);
END;
$$;

-- Triggers de disparo (start/finalize)
CREATE OR REPLACE FUNCTION public.f_start_disparo()
RETURNS trigger LANGUAGE plpgsql AS $$ BEGIN
  IF OLD."Status"='pending' AND NEW."Status" IN ('processing','sent','failed') THEN
    UPDATE public."SAAS_Disparos" SET "StatusDisparo"='Em andamento' WHERE id=NEW."idDisparo" AND "StatusDisparo"='Aguardando';
  END IF;
  RETURN NEW;
END $$;

CREATE OR REPLACE FUNCTION public.f_finalize_disparo()
RETURNS trigger LANGUAGE plpgsql AS $$ BEGIN
  IF NEW."Status" IN ('sent','failed') AND OLD."Status" IS DISTINCT FROM NEW."Status" THEN
    UPDATE public."SAAS_Disparos" SET "MensagensDisparadas" = COALESCE("MensagensDisparadas",0) + 1 WHERE id = NEW."idDisparo";
    PERFORM 1 FROM public."SAAS_Detalhes_Disparos" WHERE "idDisparo"=NEW."idDisparo" AND "Status" IN ('pending','processing');
    IF NOT FOUND THEN
      UPDATE public."SAAS_Disparos" SET "StatusDisparo"='Finalizado' WHERE id=NEW."idDisparo";
    END IF;
  END IF;
  RETURN NEW;
END $$;

