CREATE OR REPLACE FUNCTION public.f_block_delete_lista_if_active()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $function$
BEGIN
  -- Desativar RLS apenas dentro desta função para validar disparos vinculados à lista
  PERFORM set_config('row_security', 'off', true);
  IF EXISTS (
    SELECT 1 FROM public."SAAS_Disparos" h
    WHERE h."StatusDisparo" IN ('Aguardando','Em andamento','Pausado')
      AND (OLD.id = ANY(h."idListas")
           OR EXISTS (SELECT 1 FROM public."SAAS_Detalhes_Disparos" d LEFT JOIN public."SAAS_Contatos" c ON c.id = d."idContato" LEFT JOIN public."SAAS_Grupos" g ON g.id = d."idGrupo"
                      WHERE d."idDisparo" = h.id AND (c."idLista" = OLD.id OR g."idLista" = OLD.id)))
  ) THEN
    RAISE EXCEPTION 'Não é possível excluir a lista %: há disparos não finalizados vinculados.', OLD.id;
  END IF;
  RETURN OLD;
END $function$;

CREATE OR REPLACE FUNCTION public.f_block_delete_contato_if_active()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $function$
BEGIN
  -- Permite limpeza dos vínculos mesmo quando houver RLS ativo nas tabelas relacionadas.
  PERFORM set_config('row_security', 'off', true);

  -- Disparos: remove detalhes vinculados ao contato (inclusive ativos/pending).
  IF to_regclass('public."SAAS_Detalhes_Disparos"') IS NOT NULL THEN
    DELETE FROM public."SAAS_Detalhes_Disparos"
    WHERE "idContato" = OLD.id;
  END IF;

  -- CRM: remove cards vinculados ao contato.
  IF to_regclass('public."SAAS_Cards_Quadros"') IS NOT NULL THEN
    DELETE FROM public."SAAS_Cards_Quadros"
    WHERE "contatoId" = OLD.id;
  END IF;

  -- Chat: remove conversas vinculadas; mensagens caem em cascata quando FK existir.
  IF to_regclass('public."SAAS_Conversas_Agentes"') IS NOT NULL THEN
    DELETE FROM public."SAAS_Conversas_Agentes"
    WHERE "contatoId" = OLD.id;
  END IF;

  -- Etiquetas e campos personalizados vinculados ao contato.
  IF to_regclass('public."SAAS_Contatos_Etiquetas"') IS NOT NULL THEN
    DELETE FROM public."SAAS_Contatos_Etiquetas"
    WHERE "contatoId" = OLD.id;
  END IF;

  IF to_regclass('public."SAAS_Valores_Campos_Personalizados"') IS NOT NULL THEN
    DELETE FROM public."SAAS_Valores_Campos_Personalizados"
    WHERE "idContato" = OLD.id;
  END IF;

  RETURN OLD;
END $function$;

CREATE OR REPLACE FUNCTION public.f_block_delete_grupo_if_active()
RETURNS trigger LANGUAGE plpgsql AS $func$
BEGIN
  IF EXISTS (
    SELECT 1 FROM public."SAAS_Detalhes_Disparos" d JOIN public."SAAS_Disparos" h ON h.id = d."idDisparo"
    WHERE d."idGrupo" = OLD.id AND h."StatusDisparo" IN ('Aguardando','Em andamento','Pausado')
  ) THEN
    RAISE EXCEPTION 'Não é possível excluir o grupo %: há disparos não finalizados vinculados.', OLD.id;
  END IF;
  RETURN OLD;
END $func$;

-- Expirar contas (dataValidade vencida); contas com super_admin nunca expiram
CREATE OR REPLACE FUNCTION public.p_expire_contas_daily()
RETURNS void LANGUAGE plpgsql AS $$
BEGIN
  UPDATE public."SAAS_Contas" c SET status = FALSE
  WHERE c.status IS DISTINCT FROM FALSE AND c."dataValidade" IS NOT NULL AND CURRENT_DATE > c."dataValidade"
    AND NOT EXISTS (SELECT 1 FROM public."SAAS_Usuarios" u WHERE u."contaId" = c.id AND u.super_admin = true);
END;
$$;

CREATE OR REPLACE FUNCTION public.p_expire_contas_now()
RETURNS void LANGUAGE plpgsql AS $$
BEGIN
  UPDATE public."SAAS_Contas" c SET status = false
  WHERE c."dataValidade" IS NOT NULL AND c."dataValidade" < CURRENT_DATE AND c.status IS DISTINCT FROM false
    AND NOT EXISTS (SELECT 1 FROM public."SAAS_Usuarios" u WHERE u."contaId" = c.id AND u.super_admin = true);
END;
$$;

-- Mirror auth → SAAS_Usuarios (alternativa; em conta o sync principal já cria Conta+Usuario)
CREATE OR REPLACE FUNCTION public.f_auth_to_saas_usuarios_mirror()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public, auth AS $$
DECLARE v_existing_id uuid; v_nome text; v_telefone text;
BEGIN
  PERFORM set_config('row_security', 'off', true);
  v_nome := COALESCE(NEW.raw_user_meta_data->>'full_name', NEW.raw_user_meta_data->>'name', NEW.raw_user_meta_data->>'nome');
  v_telefone := COALESCE(NEW.phone, NEW.raw_user_meta_data->>'phone', NEW.raw_user_meta_data->>'telefone');
  SELECT id INTO v_existing_id FROM public."SAAS_Usuarios" WHERE "Email" = NEW.email LIMIT 1;
  IF v_existing_id IS NOT NULL THEN
    UPDATE public."SAAS_Usuarios" SET auth_user_id = NEW.id, "Email" = NEW.email, nome = COALESCE(v_nome, nome), telefone = COALESCE(v_telefone, telefone) WHERE id = v_existing_id;
  END IF;
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN RETURN NEW;
END;
$$;

-- RLS SAAS_Usuarios: usuário vê a si e os demais da mesma conta (só leitura nos outros); edita apenas o próprio; admin pode inserir convites.
DO $$
BEGIN
  IF to_regclass('public."SAAS_Usuarios"') IS NOT NULL THEN
    ALTER TABLE public."SAAS_Usuarios" ENABLE ROW LEVEL SECURITY;
    DROP POLICY IF EXISTS "service_role_full_access" ON public."SAAS_Usuarios";
    CREATE POLICY "service_role_full_access" ON public."SAAS_Usuarios" TO service_role USING (true) WITH CHECK (true);
    DROP POLICY IF EXISTS "insert_usuario_admin" ON public."SAAS_Usuarios";
    -- Inserir: apenas admin da conta pode adicionar usuários (convite) na mesma conta
    CREATE POLICY "insert_usuario_admin" ON public."SAAS_Usuarios" FOR INSERT TO authenticated
      WITH CHECK (public.is_admin("contaId") OR public.is_super_admin());
    DROP POLICY IF EXISTS "select_meu_usuario" ON public."SAAS_Usuarios";
    DROP POLICY IF EXISTS "select_usuarios_da_conta" ON public."SAAS_Usuarios";
    DROP POLICY IF EXISTS "select_usuarios_mesma_conta" ON public."SAAS_Usuarios";
    -- Ver: próprio usuário ou outros da mesma conta (apenas visualizar); super_admin vê todos
    CREATE POLICY "select_usuarios_mesma_conta" ON public."SAAS_Usuarios" FOR SELECT TO authenticated
      USING ("contaId" = ANY(public.get_conta_ids_usuario()) OR public.is_super_admin());
    DROP POLICY IF EXISTS "update_meu_usuario" ON public."SAAS_Usuarios";
    -- Atualizar: apenas o próprio registro (auth_user_id = auth.uid()); super_admin pode atualizar qualquer
    CREATE POLICY "update_meu_usuario" ON public."SAAS_Usuarios" FOR UPDATE TO authenticated
      USING ("auth_user_id" = auth.uid() OR public.is_super_admin()) WITH CHECK ("auth_user_id" = auth.uid() OR public.is_super_admin());
    -- Excluir: apenas admin da conta pode excluir outros usuários da mesma conta (não pode excluir a si mesmo)
    DROP POLICY IF EXISTS "delete_usuario_admin" ON public."SAAS_Usuarios";
    CREATE POLICY "delete_usuario_admin" ON public."SAAS_Usuarios" FOR DELETE TO authenticated
      USING ((public.is_admin("contaId") OR public.is_super_admin()) AND ("auth_user_id" IS DISTINCT FROM auth.uid()));
    -- Autenticado não pode editar contaId nem super_admin: apenas Email, nome, telefone
    REVOKE UPDATE ON public."SAAS_Usuarios" FROM authenticated;
    GRANT SELECT, INSERT, UPDATE ("Email", nome, telefone) ON public."SAAS_Usuarios" TO authenticated;
  END IF;
END$$;

-- RLS SAAS_Contas: membros leem; super_admin vê/edita/cria/exclui tudo
DO $$
BEGIN
  IF to_regclass('public."SAAS_Contas"') IS NOT NULL THEN
    ALTER TABLE public."SAAS_Contas" ENABLE ROW LEVEL SECURITY;
    DROP POLICY IF EXISTS "authenticated_select_contas_membro" ON public."SAAS_Contas";
    CREATE POLICY "authenticated_select_contas_membro" ON public."SAAS_Contas" FOR SELECT TO authenticated USING (public.can_access_conta(id) OR public.is_super_admin());
    DROP POLICY IF EXISTS "admin_update_conta" ON public."SAAS_Contas";
    DROP POLICY IF EXISTS "super_admin_all_contas" ON public."SAAS_Contas";
    CREATE POLICY "super_admin_all_contas" ON public."SAAS_Contas" FOR ALL TO authenticated USING (public.is_super_admin()) WITH CHECK (public.is_super_admin());
    REVOKE INSERT, UPDATE, DELETE ON public."SAAS_Contas" FROM authenticated;
    GRANT SELECT, INSERT, UPDATE, DELETE ON public."SAAS_Contas" TO authenticated;
  END IF;
END$$;

