  DROP POLICY IF EXISTS "delete_detalhes_disparos" ON public."SAAS_Detalhes_Disparos";
  DROP POLICY IF EXISTS "delete_detalhes_disparos_trigger_owner" ON public."SAAS_Detalhes_Disparos";
  CREATE POLICY "select_detalhes_disparos" ON public."SAAS_Detalhes_Disparos" FOR SELECT TO authenticated
    USING (EXISTS (SELECT 1 FROM public."SAAS_Disparos" h WHERE h.id = "SAAS_Detalhes_Disparos"."idDisparo" AND (public.can_access_conta(h."contaId") OR public.is_super_admin())));
  CREATE POLICY "insert_detalhes_disparos" ON public."SAAS_Detalhes_Disparos" FOR INSERT TO authenticated
    WITH CHECK (EXISTS (SELECT 1 FROM public."SAAS_Disparos" h WHERE h.id = "SAAS_Detalhes_Disparos"."idDisparo" AND (public.can_access_conta(h."contaId") OR public.is_super_admin())));
  CREATE POLICY "update_detalhes_disparos" ON public."SAAS_Detalhes_Disparos" FOR UPDATE TO authenticated
    USING (EXISTS (SELECT 1 FROM public."SAAS_Disparos" h WHERE h.id = "SAAS_Detalhes_Disparos"."idDisparo" AND (public.can_access_conta(h."contaId") OR public.is_super_admin())))
    WITH CHECK (EXISTS (SELECT 1 FROM public."SAAS_Disparos" h WHERE h.id = "SAAS_Detalhes_Disparos"."idDisparo" AND (public.can_access_conta(h."contaId") OR public.is_super_admin())));
  -- DELETE permitido apenas se o disparo pai for da mesma conta (ou super_admin)
  CREATE POLICY "delete_detalhes_disparos" ON public."SAAS_Detalhes_Disparos" FOR DELETE
    USING (
