DO $$
BEGIN
  IF to_regclass('public."SAAS_Contatos"') IS NULL THEN RETURN; END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Contatos' AND column_name = 'atributos')
     AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'SAAS_Contatos' AND column_name = 'variaveis') THEN
