-- Views (formato multi-usuários)
CREATE OR REPLACE VIEW public."vw_Planos_Usuarios_Count" WITH (security_invoker = true) AS
SELECT p.id, p.created_at, p.nome, p.preco, p."qntConexoes", p."qntContatos", p."qntDisparos",
  COUNT(c.id) AS total_usuarios, p."qntUsuarios", p."qntQuadros", p."qntAgentesIa", p."qntCreditosIa", p.menu_ocultar
FROM public."SAAS_Planos" p
LEFT JOIN public."SAAS_Contas" c ON c.plano = p.id
GROUP BY p.id, p.created_at, p.nome, p.preco, p."qntConexoes", p."qntContatos", p."qntDisparos", p."qntUsuarios", p."qntQuadros", p."qntAgentesIa", p."qntCreditosIa", p.menu_ocultar;

-- vw_Detalhes_Completo: modelo novo (etiquetas) - grupos são contatos com tipo='grupo'
DROP VIEW IF EXISTS public."vw_Detalhes_Completo" CASCADE;
CREATE OR REPLACE VIEW public."vw_Detalhes_Completo" WITH (security_invoker = true) AS
SELECT d.id, d."idDisparo", d."idContato", d."Mensagem", d."idConexao", d."dataEnvio", d."Status", d."statusHttp", d."mensagemErro", d."respostaHttp", d."Payload", d."KeyRedis", d."FakeCall",
  disp."StatusDisparo",
  CASE WHEN c.tipo = 'contato' THEN c.telefone ELSE NULL END AS "TelefoneContato",
  c.variaveis->>'whatsappId' AS "WhatsAppIdGrupo",
  c.nome AS "NomeGrupo",
  cx."instanceName" AS "InstanceName", cx."Apikey" AS "ApikeyConexao",
  disp."contaId" AS "UserId", cx."NomeConexao", disp."TipoDisparo"
FROM public."SAAS_Detalhes_Disparos" d
LEFT JOIN public."SAAS_Disparos" disp ON disp.id = d."idDisparo"
LEFT JOIN public."SAAS_Contatos" c ON c.id = d."idContato"
LEFT JOIN public."SAAS_Conexões" cx ON cx.id = d."idConexao";

CREATE OR REPLACE VIEW public."vw_Contas_Com_Plano" WITH (security_invoker = true) AS
SELECT c.id, c.status, c."dataValidade", c.plano AS plano_id, p.nome AS plano_nome, p.preco AS plano_preco, p.created_at AS plano_created_at,
  CASE WHEN COALESCE(c.status, false) THEN p."qntConexoes" ELSE 0 END AS "plano_qntConexoes",
  CASE WHEN COALESCE(c.status, false) THEN p."qntContatos" ELSE 0 END AS "plano_qntContatos",
  CASE WHEN COALESCE(c.status, false) THEN p."qntDisparos" ELSE 0 END AS "plano_qntDisparos",
  CASE WHEN COALESCE(c.status, false) THEN p."qntQuadros" ELSE 0 END AS "plano_qntQuadros",
  CASE WHEN COALESCE(c.status, false) THEN p."qntAgentesIa" ELSE 0 END AS "planoQntAgentes",
  CASE WHEN COALESCE(c.status, false) THEN p."qntCreditosIa" ELSE 0 END AS "planoQntCreditos",
  COALESCE(cx.total_conexoes, 0::bigint) AS total_conexoes,
  COALESCE(ct.total_contatos, 0::bigint) AS total_contatos, COALESCE(dd.total_disparos, 0::bigint) AS total_disparos,
  COALESCE(qd.total_quadros, 0::bigint) AS total_quadros,
  COALESCE(ag.total_agentes, 0::bigint) AS total_agentes,
  COALESCE(uc.total_creditos, 0::numeric) AS total_creditos,
  CASE WHEN COALESCE(c.status, false) THEN p."qntUsuarios" ELSE 0 END AS "planoQntUsuarios",
  COALESCE(us.total_usuarios, 0::bigint) AS total_usuarios
FROM public."SAAS_Contas" c
LEFT JOIN public."SAAS_Planos" p ON p.id = c.plano
LEFT JOIN (SELECT "contaId", COUNT(*) AS total_conexoes FROM public."SAAS_Conexões" GROUP BY "contaId") cx ON cx."contaId" = c.id
LEFT JOIN (SELECT "contaId", COUNT(*) AS total_contatos FROM public."SAAS_Contatos" GROUP BY "contaId") ct ON ct."contaId" = c.id
LEFT JOIN (SELECT h."contaId" AS uid, COUNT(*) AS total_disparos FROM public."SAAS_Detalhes_Disparos" d JOIN public."SAAS_Disparos" h ON h.id = d."idDisparo"
  WHERE d."dataEnvio" >= date_trunc('month', now() AT TIME ZONE 'America/Sao_Paulo') AND d."dataEnvio" < (date_trunc('month', now() AT TIME ZONE 'America/Sao_Paulo') + '1 mon'::interval)
  GROUP BY h."contaId") dd ON dd.uid = c.id
LEFT JOIN (SELECT q."contaId" AS uid, COUNT(*) AS total_quadros FROM public."SAAS_Quadros" q GROUP BY q."contaId") qd ON qd.uid = c.id
LEFT JOIN (SELECT "SAAS_AgentesIA"."contaId" AS uid, COUNT(*) AS total_agentes FROM public."SAAS_AgentesIA" GROUP BY "contaId") ag ON ag.uid = c.id
LEFT JOIN (SELECT "contaId", COUNT(*) AS total_usuarios FROM public."SAAS_Usuarios" GROUP BY "contaId") us ON us."contaId" = c.id
LEFT JOIN (
  SELECT c2.id AS uid, COALESCE(c2.tokens, 0::numeric) AS total_creditos
  FROM public."SAAS_Contas" c2
) uc ON uc.uid = c.id;

CREATE OR REPLACE VIEW public."VW_SAAS_Etapas_Quadros"
WITH (security_invoker = true)
AS
SELECT
  q.id AS "quadroId",
  q.nome AS "nomeQuadro",
  e.id AS "etapaId",
  e.nome AS "nomeEtapa",
  e.ordem AS "ordemEtapa",
  COALESCE(
    (
      SELECT
        jsonb_agg(
          to_jsonb(c.*) || jsonb_build_object('ordemCard', c.ordem)
          ORDER BY c.ordem
        ) AS jsonb_agg
      FROM public."SAAS_Cards_Quadros" c
      WHERE c."quadroId" = q.id
        AND c."etapaQuadroId" = e.id
    ),
    '[]'::jsonb
  ) AS cards
FROM public."SAAS_Etapas_Quadros" e
JOIN public."SAAS_Quadros" q ON q.id = e."quadroId";

CREATE OR REPLACE VIEW public."VW_SAAS_AgentesIA_Conversas"
WITH (security_invoker = true)
AS
SELECT
  a.id, a.created_at, a."contaId", a.nome, a."conexaoId", a.instrucoes, a.modelo, a.criatividade,
  a."maxCreditos", a.ativo, a.conhecimento, a.cor, a."separarMensagens", a."ouvirAudio", a."analisarImagens",
  a."aparecerDigitando", a."pausarAtendimento", a."qntMsgHistorico", a."agruparMensagens", a."intervaloEntreMensagens",
  COALESCE(cnv.conversas_atendimento, 0::bigint) AS "conversasAtendimento",
  COALESCE(cnv.conversas_pausadas, 0::bigint) AS "ConversasPausadas",
  CASE WHEN p."qntCreditosIa" IS NULL THEN false
       ELSE COALESCE(uc.total_creditos, 0::bigint) >= p."qntCreditosIa"
  END AS "limiteAtingido",
  a."CRM"
FROM public."SAAS_AgentesIA" a
LEFT JOIN (
  SELECT "SAAS_Conversas_Agentes"."idAgente",
    COUNT(*) FILTER (WHERE "SAAS_Conversas_Agentes".pausado IS false) AS conversas_atendimento,
    COUNT(*) FILTER (WHERE "SAAS_Conversas_Agentes".pausado IS true) AS conversas_pausadas
  FROM public."SAAS_Conversas_Agentes" GROUP BY "idAgente"
) cnv ON cnv."idAgente" = a.id
LEFT JOIN public."SAAS_Contas" c ON c.id = a."contaId"
LEFT JOIN public."SAAS_Planos" p ON p.id = c.plano
LEFT JOIN (
  SELECT c3.id AS "contaId", COALESCE(c3.tokens, 0::numeric)::bigint AS total_creditos
  FROM public."SAAS_Contas" c3
) uc ON uc."contaId" = a."contaId";

CREATE OR REPLACE VIEW public."vw_SAAS_Quadros_CRM"
WITH (security_invoker = true)
AS
SELECT
  q.id, q.created_at, q.nome, q.descricao, q.cor, q."contaId", q.icone,
  COALESCE(c.total_cards, 0::bigint) AS total_cards,
  COALESCE(c.valor_total, 0::double precision) AS valor_total
FROM public."SAAS_Quadros" q
LEFT JOIN (
  SELECT "SAAS_Cards_Quadros"."quadroId" AS quadro_id,
    COUNT(*) AS total_cards,
    COALESCE(SUM("SAAS_Cards_Quadros".valor), 0::double precision) AS valor_total
  FROM public."SAAS_Cards_Quadros" GROUP BY "SAAS_Cards_Quadros"."quadroId"
) c ON c.quadro_id = q.id;

