-- =========================
-- Verificar se email já existe em SAAS_Usuarios (qualquer conta). Retorna { existe: bool, mesma_conta: bool }.
-- mesma_conta só é true quando existe e o registro pertence à conta informada.
CREATE OR REPLACE FUNCTION public.f_check_email_usuario(p_email text, p_conta_id uuid)
RETURNS jsonb LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path = public AS $$
DECLARE v_conta_id uuid;
BEGIN
  SELECT u."contaId" INTO v_conta_id FROM public."SAAS_Usuarios" u WHERE u."Email" = p_email LIMIT 1;
  IF v_conta_id IS NULL THEN
    RETURN jsonb_build_object('existe', false, 'mesma_conta', false);
  END IF;
  RETURN jsonb_build_object('existe', true, 'mesma_conta', (v_conta_id = p_conta_id));
END;
$$;

GRANT EXECUTE ON FUNCTION public.f_check_email_usuario(text, uuid) TO authenticated;

-- Funções de exclusão – uma função para cada operação de reset
-- Toda exclusão roda direto no Supabase (SECURITY DEFINER), respeitando is_admin
-- p_conta_id = contaId (frontend chama supabase.rpc('nome_funcao', { p_conta_id: contaId }))
-- =========================

-- 1) Limpar todas as listas (Contatos, Grupos, Listas)
CREATE OR REPLACE FUNCTION public.f_limpar_listas(p_conta_id uuid)
RETURNS boolean LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  IF NOT public.is_admin(p_conta_id) AND NOT public.is_super_admin() THEN
    RETURN false;
  END IF;
  IF to_regclass('public."SAAS_Contatos_Etiquetas"') IS NOT NULL THEN DELETE FROM public."SAAS_Contatos_Etiquetas" WHERE "contaId" = p_conta_id; END IF;
  DELETE FROM public."SAAS_Contatos" WHERE "contaId" = p_conta_id;
  IF to_regclass('public."SAAS_Etiquetas"') IS NOT NULL THEN DELETE FROM public."SAAS_Etiquetas" WHERE "contaId" = p_conta_id; END IF;
  IF to_regclass('public."SAAS_Grupos"') IS NOT NULL THEN DELETE FROM public."SAAS_Grupos" WHERE "contaId" = p_conta_id; END IF;
  IF to_regclass('public."SAAS_Listas"') IS NOT NULL THEN DELETE FROM public."SAAS_Listas" WHERE "contaId" = p_conta_id; END IF;
  RETURN true;
END;
$$;

-- 2) Limpar todas as conversas
CREATE OR REPLACE FUNCTION public.f_limpar_conversas(p_conta_id uuid)
RETURNS boolean LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  IF NOT public.is_admin(p_conta_id) AND NOT public.is_super_admin() THEN
    RETURN false;
  END IF;
  DELETE FROM public."SAAS_Conversas_Agentes" WHERE "contaId" = p_conta_id;
  RETURN true;
END;
$$;

-- 3) Limpar todas as conexões
CREATE OR REPLACE FUNCTION public.f_limpar_conexoes(p_conta_id uuid)
RETURNS boolean LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  IF NOT public.is_admin(p_conta_id) AND NOT public.is_super_admin() THEN
    RETURN false;
  END IF;
  DELETE FROM public."SAAS_Conexões" WHERE "contaId" = p_conta_id;
  RETURN true;
END;
$$;

-- 4) Limpar histórico de disparos (Detalhes_Disparos + Disparos)
CREATE OR REPLACE FUNCTION public.f_limpar_historico_disparos(p_conta_id uuid)
RETURNS boolean LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  IF NOT public.is_admin(p_conta_id) AND NOT public.is_super_admin() THEN
    RETURN false;
  END IF;
  DELETE FROM public."SAAS_Detalhes_Disparos" d
  USING public."SAAS_Disparos" h
  WHERE d."idDisparo" = h.id AND h."contaId" = p_conta_id;
  DELETE FROM public."SAAS_Disparos" WHERE "contaId" = p_conta_id;
  RETURN true;
END;
$$;

-- 5) Resetar toda a conta (todos os dados da conta)
CREATE OR REPLACE FUNCTION public.f_resetar_conta(p_conta_id uuid)
RETURNS boolean LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE
  conv_ids bigint[];
  disp_ids bigint[];
  quadro_ids bigint[];
BEGIN
  IF NOT public.is_admin(p_conta_id) AND NOT public.is_super_admin() THEN
    RETURN false;
  END IF;
  SELECT array_agg(id) INTO conv_ids FROM public."SAAS_Conversas_Agentes" WHERE "contaId" = p_conta_id;
  IF conv_ids IS NOT NULL AND array_length(conv_ids, 1) > 0 THEN
    DELETE FROM public."SAAS_Mensagens" WHERE "conversaId" = ANY(conv_ids);
  END IF;
  DELETE FROM public."SAAS_Conversas_Agentes" WHERE "contaId" = p_conta_id;
  SELECT array_agg(id) INTO disp_ids FROM public."SAAS_Disparos" WHERE "contaId" = p_conta_id;
  IF disp_ids IS NOT NULL AND array_length(disp_ids, 1) > 0 THEN
    DELETE FROM public."SAAS_Detalhes_Disparos" WHERE "idDisparo" = ANY(disp_ids);
  END IF;
  DELETE FROM public."SAAS_Disparos" WHERE "contaId" = p_conta_id;
  IF to_regclass('public."SAAS_Contatos_Etiquetas"') IS NOT NULL THEN DELETE FROM public."SAAS_Contatos_Etiquetas" WHERE "contaId" = p_conta_id; END IF;
  DELETE FROM public."SAAS_Contatos" WHERE "contaId" = p_conta_id;
  IF to_regclass('public."SAAS_Etiquetas"') IS NOT NULL THEN DELETE FROM public."SAAS_Etiquetas" WHERE "contaId" = p_conta_id; END IF;
  IF to_regclass('public."SAAS_Grupos"') IS NOT NULL THEN DELETE FROM public."SAAS_Grupos" WHERE "contaId" = p_conta_id; END IF;
  IF to_regclass('public."SAAS_Listas"') IS NOT NULL THEN DELETE FROM public."SAAS_Listas" WHERE "contaId" = p_conta_id; END IF;
  SELECT array_agg(id) INTO quadro_ids FROM public."SAAS_Quadros" WHERE "contaId" = p_conta_id;
  IF quadro_ids IS NOT NULL AND array_length(quadro_ids, 1) > 0 THEN
    DELETE FROM public."SAAS_Cards_Quadros" WHERE "quadroId" = ANY(quadro_ids);
  END IF;
  DELETE FROM public."SAAS_Etapas_Quadros" WHERE "contaId" = p_conta_id;
  DELETE FROM public."SAAS_Quadros" WHERE "contaId" = p_conta_id;
  DELETE FROM public."SAAS_Conexões" WHERE "contaId" = p_conta_id;
  DELETE FROM public."SAAS_AgentesIA" WHERE "contaId" = p_conta_id;
  DELETE FROM public."SAAS_Webhook" WHERE "contaId" = p_conta_id;
  IF to_regclass('public."SAAS_IntegracaoPagamento"') IS NOT NULL THEN DELETE FROM public."SAAS_IntegracaoPagamento"; END IF;
  DELETE FROM public."SAAS_Resposta_Rapidas" WHERE "contaId" = p_conta_id;
  RETURN true;
END;
$$;

