-- =========================
-- Storage RLS do bucket 'arquivos' (logo/favicon)
-- =========================
DO $$
BEGIN
  IF to_regnamespace('storage') IS NOT NULL AND to_regclass('storage.objects') IS NOT NULL THEN
    BEGIN
      -- Em alguns projetos managed, este ALTER exige owner de storage.objects.
      ALTER TABLE storage.objects ENABLE ROW LEVEL SECURITY;
    EXCEPTION
      WHEN insufficient_privilege THEN
        RAISE NOTICE 'Sem permissão para ALTER TABLE storage.objects. Prosseguindo sem alterar RLS.';
    END;

    BEGIN
      DROP POLICY IF EXISTS "arquivos_public_read" ON storage.objects;
      DROP POLICY IF EXISTS "arquivos_auth_insert" ON storage.objects;
      DROP POLICY IF EXISTS "arquivos_auth_update" ON storage.objects;
      DROP POLICY IF EXISTS "arquivos_auth_delete" ON storage.objects;

      -- Leitura pública dos arquivos do bucket (bucket público).
      CREATE POLICY "arquivos_public_read"
        ON storage.objects
        FOR SELECT
        TO public
        USING (bucket_id = 'arquivos');

      -- Escrita autenticada restrita aos arquivos de branding usados pelo admin.
      CREATE POLICY "arquivos_auth_insert"
        ON storage.objects
        FOR INSERT
        TO authenticated
        WITH CHECK (
          bucket_id = 'arquivos'
          AND (
            name ~* '^(LOGO PRINCIPAL|FAVICON)\.[A-Za-z0-9]+$'
            OR name LIKE 'personalizacao/%'
          )
        );

      CREATE POLICY "arquivos_auth_update"
        ON storage.objects
        FOR UPDATE
        TO authenticated
        USING (
          bucket_id = 'arquivos'
          AND (
            name ~* '^(LOGO PRINCIPAL|FAVICON)\.[A-Za-z0-9]+$'
            OR name LIKE 'personalizacao/%'
          )
        )
        WITH CHECK (
          bucket_id = 'arquivos'
          AND (
            name ~* '^(LOGO PRINCIPAL|FAVICON)\.[A-Za-z0-9]+$'
            OR name LIKE 'personalizacao/%'
          )
        );

      CREATE POLICY "arquivos_auth_delete"
        ON storage.objects
        FOR DELETE
        TO authenticated
        USING (
          bucket_id = 'arquivos'
          AND (
            name ~* '^(LOGO PRINCIPAL|FAVICON)\.[A-Za-z0-9]+$'
            OR name LIKE 'personalizacao/%'
          )
        );
    EXCEPTION
      WHEN insufficient_privilege THEN
        RAISE NOTICE 'Sem permissão para criar policies em storage.objects. Configure pelo Dashboard > Storage > Policies.';
    END;
  END IF;
END$$;

-- =========================
-- pg_cron: agendar expiração diária de contas (p_expire_contas_daily)
-- =========================
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM pg_available_extensions WHERE name = 'pg_cron') THEN
    BEGIN
      CREATE EXTENSION IF NOT EXISTS pg_cron;
    EXCEPTION
      WHEN insufficient_privilege THEN
        RAISE NOTICE 'Sem privilégio para criar extensão pg_cron';
      WHEN OTHERS THEN
        RAISE NOTICE 'Falha ao criar extensão pg_cron: %', SQLERRM;
    END;
  ELSE
    RAISE NOTICE 'Extensão pg_cron não disponível neste servidor';
  END IF;
END$$;

DO $$
BEGIN
  IF to_regnamespace('cron') IS NOT NULL AND to_regclass('cron.job') IS NOT NULL THEN
    BEGIN
      PERFORM cron.unschedule(jobid) FROM cron.job WHERE jobname = 'expire_contas_daily';
    EXCEPTION
      WHEN OTHERS THEN
        RAISE NOTICE 'Erro ao remover job expire_contas_daily: %', SQLERRM;
    END;

    BEGIN
      PERFORM cron.schedule(
        'expire_contas_daily',
        '1 3 * * *',
        'SELECT public.p_expire_contas_daily();'
      );
    EXCEPTION
      WHEN OTHERS THEN
        RAISE NOTICE 'Erro ao criar job expire_contas_daily: %', SQLERRM;
    END;
  ELSE
    RAISE NOTICE 'pg_cron não disponível. Pulando criação de jobs cron.';
  END IF;
END$$;

-- Cron: resetar créditos de agentes mensalmente
DO $$
BEGIN
