-- 3. Migrar SAAS_Grupos → SAAS_Contatos (tipo='grupo')
CREATE TEMP TABLE IF NOT EXISTS _map_grupo_contato (grupo_id BIGINT PRIMARY KEY, contato_id BIGINT);

DO $$
DECLARE rec RECORD; novo_id BIGINT; v_variaveis JSONB;
BEGIN
  IF to_regclass('public."SAAS_Contatos_Etiquetas"') IS NOT NULL THEN RETURN; END IF;
  IF to_regclass('public."SAAS_Grupos"') IS NULL THEN RETURN; END IF;
  FOR rec IN SELECT id, created_at, nome, "WhatsAppId", "idLista", atributos, "contaId" FROM public."SAAS_Grupos"
  LOOP
    v_variaveis := COALESCE(rec.atributos, '{}'::jsonb) || jsonb_build_object('whatsappId', rec."WhatsAppId");
    INSERT INTO public."SAAS_Contatos" (created_at, nome, telefone, tipo, variaveis, "contaId", "idLista")
    VALUES (rec.created_at, rec.nome, NULL, 'grupo', v_variaveis, rec."contaId", rec."idLista")
    RETURNING id INTO novo_id;
    INSERT INTO _map_grupo_contato (grupo_id, contato_id) VALUES (rec.id, novo_id) ON CONFLICT (grupo_id) DO UPDATE SET contato_id = EXCLUDED.contato_id;
  END LOOP;
  RAISE NOTICE 'Grupos migrados para SAAS_Contatos (tipo=grupo)';
END$$;

