-- 4. SAAS_Detalhes_Disparos: idGrupo → idContato
DO $$
BEGIN
  IF to_regclass('public."SAAS_Contatos_Etiquetas"') IS NOT NULL THEN RETURN; END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='SAAS_Detalhes_Disparos' AND column_name='idGrupo') THEN
    DROP VIEW IF EXISTS public."vw_Detalhes_Completo" CASCADE;
    UPDATE public."SAAS_Detalhes_Disparos" d SET "idContato" = m.contato_id, "idGrupo" = NULL
    FROM _map_grupo_contato m WHERE d."idGrupo" = m.grupo_id;
    ALTER TABLE public."SAAS_Detalhes_Disparos" DROP COLUMN IF EXISTS "idGrupo";
    RAISE NOTICE 'SAAS_Detalhes_Disparos: idGrupo migrado para idContato';
  END IF;
END$$;

