  IF to_regclass('public."SAAS_Valores_Campos_Personalizados"') IS NOT NULL THEN
    ALTER TABLE public."SAAS_Valores_Campos_Personalizados" ADD COLUMN IF NOT EXISTS "contaId" UUID REFERENCES public."SAAS_Contas"(id) ON UPDATE CASCADE ON DELETE CASCADE;
    UPDATE public."SAAS_Valores_Campos_Personalizados" v
    SET "contaId" = c."contaId"
    FROM public."SAAS_Contatos" c
    WHERE v."idContato" = c.id AND (v."contaId" IS DISTINCT FROM c."contaId");
    UPDATE public."SAAS_Valores_Campos_Personalizados" v
    SET "contaId" = cp."contaId"
    FROM public."SAAS_Campos_Personalizados" cp
    WHERE v."idCampo" = cp.id AND v."contaId" IS NULL;
    DELETE FROM public."SAAS_Valores_Campos_Personalizados" WHERE "contaId" IS NULL;
    ALTER TABLE public."SAAS_Valores_Campos_Personalizados" ALTER COLUMN "contaId" SET NOT NULL;
  END IF;
END $$;

-- Garantir no máximo um valor por par (idCampo, idContato)
DO $$
BEGIN
  IF to_regclass('public."SAAS_Valores_Campos_Personalizados"') IS NULL THEN RETURN; END IF;
  DELETE FROM public."SAAS_Valores_Campos_Personalizados" a
  USING public."SAAS_Valores_Campos_Personalizados" b
  WHERE a.ctid > b.ctid
    AND a."idCampo" = b."idCampo"
    AND a."idContato" = b."idContato";
  IF NOT EXISTS (
    SELECT 1
    FROM pg_constraint
    WHERE conrelid = 'public."SAAS_Valores_Campos_Personalizados"'::regclass
      AND conname = 'uq_valores_campos_idCampo_idContato'
  ) THEN
    BEGIN
      ALTER TABLE public."SAAS_Valores_Campos_Personalizados"
        ADD CONSTRAINT "uq_valores_campos_idCampo_idContato" UNIQUE ("idCampo", "idContato");
    EXCEPTION
      WHEN duplicate_object OR duplicate_table THEN NULL;
    END;
  END IF;
END $$;

