-- 6. Tratar contatos duplicados (contaId + telefone)
DO $$
DECLARE
  v_duplicados bigint := 0;
  v_job record;
BEGIN
  SELECT COALESCE(SUM(qtd - 1), 0)
  INTO v_duplicados
  FROM (
    SELECT COUNT(*) AS qtd
    FROM public."SAAS_Contatos"
    WHERE tipo = 'contato'
      AND telefone IS NOT NULL
      AND btrim(telefone) <> ''
    GROUP BY "contaId", btrim(telefone)
    HAVING COUNT(*) > 1
  ) t;

  IF v_duplicados > 0 THEN
    CREATE EXTENSION IF NOT EXISTS pg_cron;

    CREATE OR REPLACE FUNCTION public.excluir_contatos_duplicados_lote(p_lote integer DEFAULT 5000)
    RETURNS integer
    LANGUAGE plpgsql
    SECURITY DEFINER
    SET search_path = public
    AS $function$
    DECLARE
      v_removidos integer := 0;
    BEGIN
      -- Evita timeout no trigger de bloqueio durante limpeza técnica em lote
      SET LOCAL session_replication_role = replica;

      WITH alvo AS (
        SELECT id
        FROM (
          SELECT
            c.id,
            row_number() OVER (
              PARTITION BY c."contaId", btrim(c.telefone)
              ORDER BY c.id
            ) AS rn
          FROM public."SAAS_Contatos" c
          WHERE c.tipo = 'contato'
            AND c.telefone IS NOT NULL
            AND btrim(c.telefone) <> ''
        ) t
        WHERE t.rn > 1
        LIMIT p_lote
      )
      DELETE FROM public."SAAS_Conversas_Agentes" ca
      USING alvo
      WHERE ca."contatoId" = alvo.id;

      WITH alvo AS (
        SELECT id
        FROM (
          SELECT
            c.id,
            row_number() OVER (
              PARTITION BY c."contaId", btrim(c.telefone)
              ORDER BY c.id
            ) AS rn
          FROM public."SAAS_Contatos" c
          WHERE c.tipo = 'contato'
            AND c.telefone IS NOT NULL
            AND btrim(c.telefone) <> ''
        ) t
        WHERE t.rn > 1
        LIMIT p_lote
      )
      DELETE FROM public."SAAS_Contatos" c
      USING alvo
      WHERE c.id = alvo.id;

      GET DIAGNOSTICS v_removidos = ROW_COUNT;
      RETURN v_removidos;
    END;
    $function$;

    CREATE OR REPLACE FUNCTION public.worker_limpeza_contatos_duplicados()
    RETURNS void
    LANGUAGE plpgsql
    SECURITY DEFINER
    SET search_path = public
    AS $function$
    DECLARE
      v_removidos integer := 0;
      v_job record;
    BEGIN
      v_removidos := public.excluir_contatos_duplicados_lote(5000);

      IF v_removidos = 0 THEN
        CREATE OR REPLACE FUNCTION public.f_block_duplicate_contato()
        RETURNS trigger
        LANGUAGE plpgsql
        AS $inner$
        BEGIN
          IF NEW.tipo <> 'contato' THEN
            RETURN NEW;
          END IF;

          IF NEW.telefone IS NULL OR btrim(NEW.telefone) = '' THEN
            RETURN NEW;
          END IF;

          NEW.telefone := btrim(NEW.telefone);

          IF EXISTS (
            SELECT 1
            FROM public."SAAS_Contatos" c
            WHERE c."contaId" = NEW."contaId"
              AND btrim(c.telefone) = NEW.telefone
              AND c.tipo = 'contato'
              AND c.id <> COALESCE(NEW.id, -1)
          ) THEN
            RAISE EXCEPTION 'Contato duplicado para contaId % e telefone %', NEW."contaId", NEW.telefone;
          END IF;

          RETURN NEW;
        END;
        $inner$;

        DROP TRIGGER IF EXISTS trg_block_duplicate_contato ON public."SAAS_Contatos";
        CREATE TRIGGER trg_block_duplicate_contato
        BEFORE INSERT OR UPDATE OF "contaId", telefone, tipo ON public."SAAS_Contatos"
        FOR EACH ROW EXECUTE FUNCTION public.f_block_duplicate_contato();

        CREATE UNIQUE INDEX IF NOT EXISTS uq_saas_contatos_conta_telefone
        ON public."SAAS_Contatos"("contaId", telefone)
        WHERE telefone IS NOT NULL AND telefone != '';

        FOR v_job IN
          SELECT jobid
          FROM cron.job
          WHERE jobname = 'limpeza_contatos_duplicados_1min'
        LOOP
          PERFORM cron.unschedule(v_job.jobid);
        END LOOP;
      END IF;
    END;
    $function$;

    FOR v_job IN
      SELECT jobid FROM cron.job WHERE jobname = 'limpeza_contatos_duplicados_1min'
    LOOP
      PERFORM cron.unschedule(v_job.jobid);
    END LOOP;

    PERFORM cron.schedule(
      'limpeza_contatos_duplicados_1min',
      '* * * * *',
      $cron$SELECT public.worker_limpeza_contatos_duplicados();$cron$
    );

    RAISE NOTICE 'Foram encontrados % contatos duplicados. Cron agendado para remover 5000/min. SQL manual: SELECT public.excluir_contatos_duplicados_lote(5000);', v_duplicados;
  ELSE
    CREATE OR REPLACE FUNCTION public.f_block_duplicate_contato()
    RETURNS trigger
    LANGUAGE plpgsql
    AS $function$
    BEGIN
      IF NEW.tipo <> 'contato' THEN
        RETURN NEW;
      END IF;

      IF NEW.telefone IS NULL OR btrim(NEW.telefone) = '' THEN
        RETURN NEW;
      END IF;

      NEW.telefone := btrim(NEW.telefone);

      IF EXISTS (
        SELECT 1
        FROM public."SAAS_Contatos" c
        WHERE c."contaId" = NEW."contaId"
          AND btrim(c.telefone) = NEW.telefone
          AND c.tipo = 'contato'
          AND c.id <> COALESCE(NEW.id, -1)
      ) THEN
        RAISE EXCEPTION 'Contato duplicado para contaId % e telefone %', NEW."contaId", NEW.telefone;
      END IF;

      RETURN NEW;
    END;
    $function$;

    DROP TRIGGER IF EXISTS trg_block_duplicate_contato ON public."SAAS_Contatos";
    CREATE TRIGGER trg_block_duplicate_contato
    BEFORE INSERT OR UPDATE OF "contaId", telefone, tipo ON public."SAAS_Contatos"
    FOR EACH ROW EXECUTE FUNCTION public.f_block_duplicate_contato();

    CREATE UNIQUE INDEX IF NOT EXISTS uq_saas_contatos_conta_telefone
    ON public."SAAS_Contatos"("contaId", telefone)
    WHERE telefone IS NOT NULL AND telefone != '';
  END IF;
END$$;

