CREATE OR REPLACE FUNCTION public.f_block_delete_etiqueta_if_active()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $function$
BEGIN
  PERFORM set_config('row_security', 'off', true);
  IF EXISTS (SELECT 1 FROM public."SAAS_Disparos" h
    WHERE h."StatusDisparo" IN ('Aguardando','Em andamento','Pausado')
      AND (OLD.id = ANY(COALESCE(h."idEtiquetas", ARRAY[]::bigint[]))
           OR EXISTS (SELECT 1 FROM public."SAAS_Detalhes_Disparos" d
             JOIN public."SAAS_Contatos_Etiquetas" ce ON ce."contatoId" = d."idContato"
             WHERE d."idDisparo" = h.id AND ce."etiquetaId" = OLD.id))
  ) THEN RAISE EXCEPTION 'Não é possível excluir a etiqueta %: há disparos não finalizados.', OLD.id;
  END IF;
  RETURN OLD;
END $function$;

DROP TRIGGER IF EXISTS trg_block_delete_lista_if_active ON public."SAAS_Etiquetas";
DROP TRIGGER IF EXISTS trg_block_delete_etiqueta_if_active ON public."SAAS_Etiquetas";
CREATE TRIGGER trg_block_delete_etiqueta_if_active
BEFORE DELETE ON public."SAAS_Etiquetas" FOR EACH ROW EXECUTE FUNCTION public.f_block_delete_etiqueta_if_active();

-- create_disparo e create_disparo_grupo (modelo etiquetas)
CREATE OR REPLACE FUNCTION public.create_disparo(p_payload jsonb)
RETURNS bigint LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $function$
DECLARE
  v_conta_id uuid := (p_payload ->> 'userId')::uuid;
  v_nome_disparo text := NULLIF(COALESCE(p_payload->>'nomeCampanha', p_payload->>'nomeDisparo', ''), '');
  v_fake_call boolean := COALESCE((p_payload #>> '{settings,fakecall}')::boolean, false);
  v_messages jsonb[] := ARRAY(SELECT m FROM jsonb_array_elements(COALESCE(p_payload->'mensagens','[]'::jsonb)) m);
  v_msg_count int := COALESCE(array_length(v_messages, 1), 0);
  v_conn_ids bigint[] := COALESCE(ARRAY(SELECT (c->>'id')::bigint FROM jsonb_array_elements(COALESCE(p_payload->'connections','[]'::jsonb)) c WHERE (c->>'id') ~ '^\d+$'), array[]::bigint[]);
  v_conn_count int := COALESCE(array_length(v_conn_ids,1),0);
  v_etiqueta_ids bigint[] := COALESCE(ARRAY(SELECT (x)::bigint FROM jsonb_array_elements_text(COALESCE(p_payload->'idLista', p_payload->'idEtiqueta','[]'::jsonb)) x), array[]::bigint[]);
  v_stage_ids bigint[] := COALESCE(
    ARRAY(
      SELECT DISTINCT (f->>'stageId')::bigint
      FROM jsonb_array_elements(COALESCE(p_payload->'settings'->'crmFilters','[]'::jsonb)) f
      WHERE (f->>'stageId') ~ '^\d+$'
    ),
    ARRAY(
      SELECT DISTINCT (x)::bigint
      FROM jsonb_array_elements_text(COALESCE(p_payload->'settings'->'crmStageIds','[]'::jsonb)) x
      WHERE x ~ '^\d+$'
    ),
    array[]::bigint[]
  );
  v_interval_min int := COALESCE((p_payload #>> '{settings,intervalMin}')::int, 30);
  v_interval_max int := COALESCE((p_payload #>> '{settings,intervalMax}')::int, 60);
  v_pause_after int := COALESCE((p_payload #>> '{settings,pauseAfterMessages}')::int, 0);
  v_pause_minutes int := COALESCE((p_payload #>> '{settings,pauseMinutes}')::int, 0);
  v_start_time time := COALESCE((p_payload #>> '{settings,startTime}')::time, time '08:00');
  v_end_time time := COALESCE((p_payload #>> '{settings,endTime}')::time, time '18:00');
  v_days int[] := COALESCE(ARRAY(SELECT CASE WHEN dtxt='0' THEN 7 ELSE dtxt::int END FROM jsonb_array_elements_text(COALESCE(p_payload->'settings'->'selectedDays','[]'::jsonb)) WITH ORDINALITY AS t(dtxt,ord) WHERE dtxt ~ '^\d+$' ORDER BY ord), array[]::int[]);
  v_schedule_base timestamptz := COALESCE((p_payload #>> '{settings,scheduleData}')::timestamptz, now() + interval '2 minutes');
  v_cur_ts timestamptz; v_disparo_id bigint; v_first_ts timestamptz; v_total int := 0; v_idx_msg int := 1; v_idx_conn int := 1; v_counter int := 0; v_gap int;
  v_msg_obj jsonb; v_template text; v_media_hash text; v_conn_id bigint; v_rendered text; rec_cont record;
  v_limit_plan bigint; v_used_month bigint; v_to_send bigint; v_total_after bigint;
  v_month_start timestamptz := (date_trunc('month', now() AT TIME ZONE 'America/Sao_Paulo') AT TIME ZONE 'America/Sao_Paulo');
  v_next_month timestamptz := ((date_trunc('month', now() AT TIME ZONE 'America/Sao_Paulo') + interval '1 month') AT TIME ZONE 'America/Sao_Paulo');
BEGIN
  v_cur_ts := f_next_valid_time(v_schedule_base, v_start_time, v_end_time, v_days);
  SELECT p."qntDisparos"::bigint INTO v_limit_plan FROM public."SAAS_Contas" conta LEFT JOIN public."SAAS_Planos" p ON p.id = conta.plano WHERE conta.id = v_conta_id;
  IF v_limit_plan IS NOT NULL THEN
    SELECT COALESCE(COUNT(*),0)::bigint INTO v_used_month FROM public."SAAS_Detalhes_Disparos" d JOIN public."SAAS_Disparos" h ON h.id = d."idDisparo" WHERE h."contaId" = v_conta_id AND d."dataEnvio" >= v_month_start AND d."dataEnvio" < v_next_month;
    WITH etiqueta_contatos AS (
      SELECT DISTINCT c.id, c.telefone
      FROM public."SAAS_Contatos" c
      JOIN public."SAAS_Contatos_Etiquetas" ce ON ce."contatoId" = c.id
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'contato'
        AND c.telefone IS NOT NULL
        AND btrim(c.telefone) <> ''
        AND ce."etiquetaId" = ANY(v_etiqueta_ids)
    ),
    crm_contatos AS (
      SELECT DISTINCT c.id, c.telefone
      FROM public."SAAS_Contatos" c
      JOIN public."SAAS_Cards_Quadros" cq ON cq."contatoId" = c.id
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'contato'
        AND c.telefone IS NOT NULL
        AND btrim(c.telefone) <> ''
        AND cq."etapaQuadroId" = ANY(v_stage_ids)
    ),
    all_contatos AS (
      SELECT DISTINCT c.id, c.telefone
      FROM public."SAAS_Contatos" c
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'contato'
        AND c.telefone IS NOT NULL
        AND btrim(c.telefone) <> ''
        AND COALESCE(cardinality(v_etiqueta_ids),0) = 0
        AND COALESCE(cardinality(v_stage_ids),0) = 0
    ),
    base AS (
      SELECT telefone FROM etiqueta_contatos
      UNION
      SELECT telefone FROM crm_contatos
      UNION
      SELECT telefone FROM all_contatos
    )
    SELECT COALESCE(COUNT(*),0)::bigint INTO v_to_send FROM base;
    v_total_after := v_used_month + v_to_send;
    IF v_total_after > v_limit_plan THEN RAISE EXCEPTION 'limite atingido: % usados + % a enviar = %, limite = %', v_used_month, v_to_send, v_total_after, v_limit_plan USING ERRCODE='P0001'; END IF;
  END IF;
  INSERT INTO public."SAAS_Disparos" ("NomeDisparo","Mensagens","TipoDisparo","TotalDisparos","MensagensDisparadas","StatusDisparo","contaId","idEtiquetas","idConexoes","intervaloMin","intervaloMax","PausaAposMensagens","PausaMinutos","StartTime","EndTime","DiasSelecionados","DataAgendamento")
  VALUES (v_nome_disparo,v_messages,'Individual',0,0,'Aguardando',v_conta_id,v_etiqueta_ids,v_conn_ids,v_interval_min,v_interval_max,v_pause_after,v_pause_minutes,v_start_time,v_end_time,v_days::smallint[],CASE WHEN p_payload #>> '{settings,scheduleData}' IS NOT NULL THEN v_schedule_base ELSE NULL END)
  RETURNING id INTO v_disparo_id;
  FOR rec_cont IN
    WITH etiqueta_contatos AS (
      SELECT DISTINCT c.id, c.telefone, c.nome, COALESCE(c.variaveis,'{}'::jsonb) AS base_variaveis
      FROM public."SAAS_Contatos" c
      JOIN public."SAAS_Contatos_Etiquetas" ce ON ce."contatoId" = c.id
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'contato'
        AND c.telefone IS NOT NULL
        AND btrim(c.telefone) <> ''
        AND ce."etiquetaId" = ANY(v_etiqueta_ids)
    ),
    crm_contatos AS (
      SELECT DISTINCT c.id, c.telefone, c.nome, COALESCE(c.variaveis,'{}'::jsonb) AS base_variaveis
      FROM public."SAAS_Contatos" c
      JOIN public."SAAS_Cards_Quadros" cq ON cq."contatoId" = c.id
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'contato'
        AND c.telefone IS NOT NULL
        AND btrim(c.telefone) <> ''
        AND cq."etapaQuadroId" = ANY(v_stage_ids)
    ),
    all_contatos AS (
      SELECT DISTINCT c.id, c.telefone, c.nome, COALESCE(c.variaveis,'{}'::jsonb) AS base_variaveis
      FROM public."SAAS_Contatos" c
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'contato'
        AND c.telefone IS NOT NULL
        AND btrim(c.telefone) <> ''
        AND COALESCE(cardinality(v_etiqueta_ids),0) = 0
        AND COALESCE(cardinality(v_stage_ids),0) = 0
    ),
    base AS (
      SELECT * FROM etiqueta_contatos
      UNION
      SELECT * FROM crm_contatos
      UNION
      SELECT * FROM all_contatos
    ),
    contato_custom_fields AS (
      SELECT
        b.id AS contato_id,
        COALESCE(
          jsonb_object_agg(
            lower(regexp_replace(cp."nome", '\s+', '_', 'g')),
            COALESCE(vcp."valor",'')
          ) FILTER (WHERE cp.id IS NOT NULL),
          '{}'::jsonb
        ) AS custom_variaveis
      FROM base b
      LEFT JOIN public."SAAS_Valores_Campos_Personalizados" vcp ON vcp."idContato" = b.id AND vcp."contaId" = v_conta_id
      LEFT JOIN public."SAAS_Campos_Personalizados" cp ON cp.id = vcp."idCampo" AND cp."contaId" = v_conta_id
      GROUP BY b.id
    )
    SELECT DISTINCT ON (b.telefone)
      b.id,
      b.telefone,
      b.nome,
      (COALESCE(b.base_variaveis,'{}'::jsonb) || COALESCE(ccf.custom_variaveis,'{}'::jsonb)) AS variaveis
    FROM base b
    LEFT JOIN contato_custom_fields ccf ON ccf.contato_id = b.id
    ORDER BY b.telefone, b.id
  LOOP
    v_msg_obj := v_messages[v_idx_msg]; v_idx_msg := (v_idx_msg % v_msg_count) + 1;
    v_template := v_msg_obj->>'text'; v_media_hash := NULLIF(COALESCE(v_msg_obj->'media'->>'link', v_msg_obj->'media'->>'hashredis',''),'');
    v_conn_id := CASE WHEN v_conn_count > 0 THEN v_conn_ids[v_idx_conn] END;
    IF v_conn_count > 0 THEN v_idx_conn := (v_idx_conn % v_conn_count) + 1; END IF;
    IF v_pause_after > 0 AND v_counter > 0 AND v_counter % v_pause_after = 0 THEN v_cur_ts := f_next_valid_time(v_cur_ts + make_interval(mins => v_pause_minutes), v_start_time, v_end_time, v_days); END IF;
    v_rendered := f_render_message(v_template, rec_cont.nome, COALESCE(rec_cont.variaveis,'{}'::jsonb), v_cur_ts);
    INSERT INTO public."SAAS_Detalhes_Disparos" ("idDisparo","idContato","Mensagem","idConexao","dataEnvio","Status","KeyRedis","FakeCall")
    VALUES (v_disparo_id, rec_cont.id, v_rendered, v_conn_id, v_cur_ts, 'pending', v_media_hash, v_fake_call);
    IF v_total = 0 THEN v_first_ts := v_cur_ts; END IF;
    v_total := v_total + 1; v_counter := v_counter + 1;
    v_gap := v_interval_min + floor(random() * (v_interval_max - v_interval_min + 1))::int;
    v_cur_ts := f_next_valid_time(v_cur_ts + make_interval(secs => v_gap), v_start_time, v_end_time, v_days);
  END LOOP;
  UPDATE public."SAAS_Disparos" SET "TotalDisparos"=v_total, "StatusDisparo"=CASE WHEN v_first_ts > now() THEN 'Aguardando' ELSE 'Em andamento' END WHERE id=v_disparo_id;
  RETURN v_disparo_id;
END $function$;

CREATE OR REPLACE FUNCTION public.edit_disparo(p_payload jsonb)
RETURNS bigint LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $function$
DECLARE
  v_disparo_id bigint := (p_payload->>'idDisparo')::bigint;
  v_conta_id uuid := (p_payload->>'userId')::uuid;
  v_nome_disparo text := NULLIF(COALESCE(p_payload->>'nomeCampanha', p_payload->>'nomeDisparo', ''), '');
  v_messages jsonb[] := ARRAY(SELECT m FROM jsonb_array_elements(COALESCE(p_payload->'mensagens','[]'::jsonb)) m);
  v_msg_count int := coalesce(array_length(v_messages,1),0);
  v_conn_ids bigint[] := COALESCE(ARRAY(SELECT (c->>'id')::bigint FROM jsonb_array_elements(COALESCE(p_payload->'connections','[]'::jsonb)) c WHERE (c->>'id') ~ '^\d+$'), array[]::bigint[]);
  v_conn_count int := coalesce(array_length(v_conn_ids,1),0);
  v_etiqueta_ids bigint[] := COALESCE(ARRAY(SELECT (x)::bigint FROM jsonb_array_elements_text(COALESCE(p_payload->'idLista', p_payload->'idEtiqueta', '[]'::jsonb)) x), array[]::bigint[]);
  v_stage_ids bigint[] := COALESCE(
    ARRAY(
      SELECT DISTINCT (f->>'stageId')::bigint
      FROM jsonb_array_elements(COALESCE(p_payload->'settings'->'crmFilters', '[]'::jsonb)) f
      WHERE (f->>'stageId') ~ '^\d+$'
    ),
    ARRAY(
      SELECT DISTINCT (x)::bigint
      FROM jsonb_array_elements_text(COALESCE(p_payload->'settings'->'crmStageIds','[]'::jsonb)) x
      WHERE x ~ '^\d+$'
    ),
    array[]::bigint[]
  );
  v_interval_min int := COALESCE((p_payload #>> '{settings,intervalMin}')::int, 30);
  v_interval_max int := COALESCE((p_payload #>> '{settings,intervalMax}')::int, 60);
  v_pause_after int := COALESCE((p_payload #>> '{settings,pauseAfterMessages}')::int, 20);
  v_pause_minutes int := COALESCE((p_payload #>> '{settings,pauseMinutes}')::int, 10);
  v_start_time time := COALESCE((p_payload #>> '{settings,startTime}')::time, time '08:00');
  v_end_time time := COALESCE((p_payload #>> '{settings,endTime}')::time, time '18:00');
  v_days int[] := COALESCE(ARRAY(
    SELECT CASE WHEN dtxt='0' THEN 7 ELSE dtxt::int END
    FROM jsonb_array_elements_text(COALESCE(p_payload->'settings'->'selectedDays','[]'::jsonb)) WITH ORDINALITY AS t(dtxt,ord)
    WHERE dtxt ~ '^\d+$'
    ORDER BY ord
  ), array[]::int[]);
  v_schedule_base timestamptz := COALESCE((p_payload#>>'{settings,scheduleData}')::timestamptz, now() + interval '2 minutes');
  v_cur_ts timestamptz;
  v_idx_msg int := 1;
  v_idx_conn int := 1;
  v_counter int := 0;
  v_gap int;
  v_msg_obj jsonb;
  v_template text;
  v_media_hash text;
  v_conn_id bigint;
  v_rendered text;
  rec_cont record;
  v_pending_total int := 0;
  v_non_pending_total int := 0;
  v_first_pending_ts timestamptz := NULL;
  v_old_status text := NULL;
BEGIN
  IF v_disparo_id IS NULL OR v_conta_id IS NULL THEN
    RAISE EXCEPTION 'idDisparo e userId são obrigatórios' USING ERRCODE='P0001';
  END IF;
  IF v_msg_count = 0 THEN
    RAISE EXCEPTION 'mensagens não pode ser vazio' USING ERRCODE='P0001';
  END IF;

  PERFORM 1
  FROM public."SAAS_Disparos" d
  WHERE d.id = v_disparo_id
    AND d."contaId" = v_conta_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'disparo % não encontrado para a conta', v_disparo_id USING ERRCODE='P0001';
  END IF;

  IF v_interval_min <= 0 THEN v_interval_min := 30; END IF;
  IF v_interval_max <= 0 THEN v_interval_max := 60; END IF;
  IF v_interval_max < v_interval_min THEN v_interval_max := v_interval_min; END IF;
  IF v_pause_after < 0 THEN v_pause_after := 0; END IF;
  IF v_pause_minutes < 0 THEN v_pause_minutes := 0; END IF;
  IF COALESCE(cardinality(v_days),0) = 0 THEN v_days := ARRAY[1,2,3,4,5,6,7]; END IF;
  v_cur_ts := f_next_valid_time(v_schedule_base, v_start_time, v_end_time, v_days);

  CREATE TEMP TABLE IF NOT EXISTS _tmp_edit_disparo_targets (
    "idContato" bigint PRIMARY KEY,
    "Mensagem" text,
    "idConexao" bigint,
    "dataEnvio" timestamptz,
    "KeyRedis" text
  ) ON COMMIT DROP;
  TRUNCATE _tmp_edit_disparo_targets;
  CREATE TEMP TABLE IF NOT EXISTS _tmp_edit_disparo_pending_keep (
    id bigint PRIMARY KEY,
    "idContato" bigint UNIQUE
  ) ON COMMIT DROP;
  TRUNCATE _tmp_edit_disparo_pending_keep;

  FOR rec_cont IN
    WITH etiqueta_contatos AS (
      SELECT DISTINCT c.id, c.telefone, c.nome, COALESCE(c.variaveis,'{}'::jsonb) AS base_variaveis
      FROM public."SAAS_Contatos" c
      JOIN public."SAAS_Contatos_Etiquetas" ce ON ce."contatoId" = c.id
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'contato'
        AND c.telefone IS NOT NULL
        AND btrim(c.telefone) <> ''
        AND ce."etiquetaId" = ANY(v_etiqueta_ids)
    ),
    crm_contatos AS (
      SELECT DISTINCT c.id, c.telefone, c.nome, COALESCE(c.variaveis,'{}'::jsonb) AS base_variaveis
      FROM public."SAAS_Contatos" c
      JOIN public."SAAS_Cards_Quadros" cq ON cq."contatoId" = c.id
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'contato'
        AND c.telefone IS NOT NULL
        AND btrim(c.telefone) <> ''
        AND cq."etapaQuadroId" = ANY(v_stage_ids)
    ),
    all_contatos AS (
      SELECT DISTINCT c.id, c.telefone, c.nome, COALESCE(c.variaveis,'{}'::jsonb) AS base_variaveis
      FROM public."SAAS_Contatos" c
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'contato'
        AND c.telefone IS NOT NULL
        AND btrim(c.telefone) <> ''
        AND COALESCE(cardinality(v_etiqueta_ids),0) = 0
        AND COALESCE(cardinality(v_stage_ids),0) = 0
    ),
    base AS (
      SELECT * FROM etiqueta_contatos
      UNION
      SELECT * FROM crm_contatos
      UNION
      SELECT * FROM all_contatos
    ),
    contato_custom_fields AS (
      SELECT
        b.id AS contato_id,
        COALESCE(
          jsonb_object_agg(
            lower(regexp_replace(cp."nome", '\s+', '_', 'g')),
            COALESCE(vcp."valor",'')
          ) FILTER (WHERE cp.id IS NOT NULL),
          '{}'::jsonb
        ) AS custom_variaveis
      FROM base b
      LEFT JOIN public."SAAS_Valores_Campos_Personalizados" vcp ON vcp."idContato" = b.id AND vcp."contaId" = v_conta_id
      LEFT JOIN public."SAAS_Campos_Personalizados" cp ON cp.id = vcp."idCampo" AND cp."contaId" = v_conta_id
      GROUP BY b.id
    )
    SELECT DISTINCT ON (b.telefone)
      b.id,
      b.telefone,
      b.nome,
      (COALESCE(b.base_variaveis,'{}'::jsonb) || COALESCE(ccf.custom_variaveis,'{}'::jsonb)) AS variaveis
    FROM base b
    LEFT JOIN contato_custom_fields ccf ON ccf.contato_id = b.id
    ORDER BY b.telefone, b.id
  LOOP
    v_msg_obj := v_messages[v_idx_msg];
    v_idx_msg := (v_idx_msg % v_msg_count) + 1;
    v_template := v_msg_obj->>'text';
    v_media_hash := NULLIF(COALESCE(v_msg_obj->'media'->>'link', v_msg_obj->'media'->>'hashredis',''),'');
    v_conn_id := CASE WHEN v_conn_count > 0 THEN v_conn_ids[v_idx_conn] END;
    IF v_conn_count > 0 THEN v_idx_conn := (v_idx_conn % v_conn_count) + 1; END IF;

    IF v_pause_after > 0 AND v_counter > 0 AND v_counter % v_pause_after = 0 THEN
      v_cur_ts := f_next_valid_time(v_cur_ts + make_interval(mins => v_pause_minutes), v_start_time, v_end_time, v_days);
    END IF;

    v_rendered := f_render_message(v_template, rec_cont.nome, COALESCE(rec_cont.variaveis,'{}'::jsonb), v_cur_ts);
    INSERT INTO _tmp_edit_disparo_targets ("idContato","Mensagem","idConexao","dataEnvio","KeyRedis")
    VALUES (rec_cont.id, v_rendered, v_conn_id, v_cur_ts, v_media_hash)
    ON CONFLICT ("idContato") DO UPDATE
      SET "Mensagem" = EXCLUDED."Mensagem",
          "idConexao" = EXCLUDED."idConexao",
          "dataEnvio" = EXCLUDED."dataEnvio",
          "KeyRedis" = EXCLUDED."KeyRedis";

    IF v_first_pending_ts IS NULL THEN v_first_pending_ts := v_cur_ts; END IF;
    v_pending_total := v_pending_total + 1;
    v_counter := v_counter + 1;
    v_gap := v_interval_min + floor(random() * (v_interval_max - v_interval_min + 1))::int;
    v_cur_ts := f_next_valid_time(v_cur_ts + make_interval(secs => v_gap), v_start_time, v_end_time, v_days);
  END LOOP;

  INSERT INTO _tmp_edit_disparo_pending_keep (id, "idContato")
  SELECT DISTINCT ON (d."idContato")
    d.id, d."idContato"
  FROM public."SAAS_Detalhes_Disparos" d
  WHERE d."idDisparo" = v_disparo_id
    AND lower(COALESCE(d."Status",'')) = 'pending'
    AND d."idContato" IS NOT NULL
  ORDER BY d."idContato", d.id DESC;

  DELETE FROM public."SAAS_Detalhes_Disparos" d
  WHERE d."idDisparo" = v_disparo_id
    AND lower(COALESCE(d."Status",'')) = 'pending'
    AND (
      d.id NOT IN (SELECT k.id FROM _tmp_edit_disparo_pending_keep k)
      OR NOT EXISTS (
        SELECT 1
        FROM _tmp_edit_disparo_targets t
        WHERE t."idContato" = d."idContato"
      )
    );

  UPDATE public."SAAS_Detalhes_Disparos" d
  SET "Mensagem" = t."Mensagem",
      "idConexao" = t."idConexao",
      "dataEnvio" = t."dataEnvio",
      "KeyRedis" = t."KeyRedis"
  FROM _tmp_edit_disparo_targets t
  WHERE d."idDisparo" = v_disparo_id
    AND lower(COALESCE(d."Status",'')) = 'pending'
    AND d."idContato" = t."idContato";

  INSERT INTO public."SAAS_Detalhes_Disparos" ("idDisparo","idContato","Mensagem","idConexao","dataEnvio","Status","KeyRedis","FakeCall")
  SELECT v_disparo_id, t."idContato", t."Mensagem", t."idConexao", t."dataEnvio", 'pending', t."KeyRedis", false
  FROM _tmp_edit_disparo_targets t
  WHERE NOT EXISTS (
    SELECT 1
    FROM public."SAAS_Detalhes_Disparos" d
    WHERE d."idDisparo" = v_disparo_id
      AND lower(COALESCE(d."Status",'')) = 'pending'
      AND d."idContato" = t."idContato"
  );

  SELECT COALESCE(COUNT(*),0)::int INTO v_non_pending_total
  FROM public."SAAS_Detalhes_Disparos" d
  WHERE d."idDisparo" = v_disparo_id
    AND lower(COALESCE(d."Status",'')) <> 'pending';

  SELECT "StatusDisparo" INTO v_old_status FROM public."SAAS_Disparos" WHERE id = v_disparo_id;

  UPDATE public."SAAS_Disparos"
  SET "NomeDisparo" = COALESCE(v_nome_disparo, "NomeDisparo"),
      "Mensagens" = v_messages,
      "idEtiquetas" = v_etiqueta_ids,
      "idConexoes" = CASE WHEN v_conn_count > 0 THEN v_conn_ids ELSE NULL END,
      "DataAgendamento" = CASE WHEN p_payload #>> '{settings,scheduleData}' IS NOT NULL THEN v_schedule_base ELSE NULL END,
      "TotalDisparos" = v_non_pending_total + v_pending_total,
      "StatusDisparo" = CASE
        WHEN lower(COALESCE(v_old_status,'')) = 'pausado' THEN 'Pausado'
        WHEN v_pending_total = 0 THEN COALESCE(v_old_status, 'Finalizado')
        WHEN v_first_pending_ts > now() THEN 'Aguardando'
        ELSE 'Em andamento'
      END
  WHERE id = v_disparo_id
    AND "contaId" = v_conta_id;

  RETURN v_disparo_id;
END $function$;

CREATE OR REPLACE FUNCTION public.edit_disparo_grupo(p_payload jsonb)
