      FROM base b
      LEFT JOIN public."SAAS_Valores_Campos_Personalizados" vcp ON vcp."idContato" = b.id AND vcp."contaId" = v_conta_id
      LEFT JOIN public."SAAS_Campos_Personalizados" cp ON cp.id = vcp."idCampo" AND cp."contaId" = v_conta_id
      GROUP BY b.id
    )
    SELECT DISTINCT ON ((coalesce(b.base_variaveis->>'whatsappId','')))
      b.id,
      coalesce(b.base_variaveis->>'whatsappId','') AS "whatsappId",
      b.nome,
      (COALESCE(b.base_variaveis,'{}'::jsonb) || COALESCE(ccf.custom_variaveis,'{}'::jsonb)) AS variaveis
    FROM base b
    LEFT JOIN contato_custom_fields ccf ON ccf.contato_id = b.id
    ORDER BY (coalesce(b.base_variaveis->>'whatsappId','')), b.id
  LOOP
    v_msg_obj := v_messages[v_idx_msg];
    v_idx_msg := (v_idx_msg % v_msg_count) + 1;
    v_template := v_msg_obj->>'text';
    v_media_hash := NULLIF(COALESCE(v_msg_obj->'media'->>'link', v_msg_obj->'media'->>'hashredis',''),'');

    IF v_pause_after > 0 AND v_counter > 0 AND v_counter % v_pause_after = 0 THEN
      v_cur_ts := f_next_valid_time(v_cur_ts + make_interval(mins => v_pause_minutes), v_start_time, v_end_time, v_days);
    END IF;

    v_rendered := public.f_render_message(v_template, rec_cont.nome, COALESCE(rec_cont.variaveis,'{}'::jsonb), v_cur_ts);
    INSERT INTO _tmp_edit_disparo_grupo_targets ("idContato","whatsappId","Mensagem","dataEnvio","KeyRedis")
    VALUES (rec_cont.id, rec_cont."whatsappId", v_rendered, v_cur_ts, v_media_hash)
    ON CONFLICT ("idContato") DO UPDATE
      SET "whatsappId" = EXCLUDED."whatsappId",
          "Mensagem" = EXCLUDED."Mensagem",
          "dataEnvio" = EXCLUDED."dataEnvio",
          "KeyRedis" = EXCLUDED."KeyRedis";

    IF v_first_pending_ts IS NULL THEN v_first_pending_ts := v_cur_ts; END IF;
    v_pending_total := v_pending_total + 1;
    v_counter := v_counter + 1;
    v_gap := v_interval_min + floor(random() * (v_interval_max - v_interval_min + 1))::int;
    v_cur_ts := f_next_valid_time(v_cur_ts + make_interval(secs => v_gap), v_start_time, v_end_time, v_days);
  END LOOP;

  INSERT INTO _tmp_edit_disparo_grupo_pending_keep (id, "idContato")
  SELECT DISTINCT ON (d."idContato")
    d.id, d."idContato"
  FROM public."SAAS_Detalhes_Disparos" d
  WHERE d."idDisparo" = v_disparo_id
    AND lower(COALESCE(d."Status",'')) = 'pending'
    AND d."idContato" IS NOT NULL
  ORDER BY d."idContato", d.id DESC;

  DELETE FROM public."SAAS_Detalhes_Disparos" d
  WHERE d."idDisparo" = v_disparo_id
    AND lower(COALESCE(d."Status",'')) = 'pending'
    AND (
      d.id NOT IN (SELECT k.id FROM _tmp_edit_disparo_grupo_pending_keep k)
      OR NOT EXISTS (
        SELECT 1
        FROM _tmp_edit_disparo_grupo_targets t
        WHERE t."idContato" = d."idContato"
      )
    );

  UPDATE public."SAAS_Detalhes_Disparos" d
  SET "Mensagem" = t."Mensagem",
      "idConexao" = v_conn_id,
      "dataEnvio" = t."dataEnvio",
      "KeyRedis" = t."KeyRedis",
      "FakeCall" = v_mention_all
  FROM _tmp_edit_disparo_grupo_targets t
  WHERE d."idDisparo" = v_disparo_id
    AND lower(COALESCE(d."Status",'')) = 'pending'
    AND d."idContato" = t."idContato";

  INSERT INTO public."SAAS_Detalhes_Disparos" ("idDisparo","idContato","Mensagem","idConexao","dataEnvio","Status","KeyRedis","FakeCall")
  SELECT v_disparo_id, t."idContato", t."Mensagem", v_conn_id, t."dataEnvio", 'pending', t."KeyRedis", v_mention_all
  FROM _tmp_edit_disparo_grupo_targets t
  WHERE NOT EXISTS (
    SELECT 1
    FROM public."SAAS_Detalhes_Disparos" d
    WHERE d."idDisparo" = v_disparo_id
      AND lower(COALESCE(d."Status",'')) = 'pending'
      AND d."idContato" = t."idContato"
  );

  SELECT COALESCE(COUNT(*),0)::int INTO v_non_pending_total
  FROM public."SAAS_Detalhes_Disparos" d
  WHERE d."idDisparo" = v_disparo_id
    AND lower(COALESCE(d."Status",'')) <> 'pending';

  SELECT "StatusDisparo" INTO v_old_status FROM public."SAAS_Disparos" WHERE id = v_disparo_id;

  UPDATE public."SAAS_Disparos"
  SET "NomeDisparo" = COALESCE(v_nome_disparo, "NomeDisparo"),
      "Mensagens" = v_messages,
      "idEtiquetas" = v_etiqueta_ids,
      "idConexoes" = CASE WHEN v_conn_id IS NOT NULL THEN ARRAY[v_conn_id] ELSE NULL END,
      "DataAgendamento" = CASE WHEN p_payload #>> '{settings,scheduleData}' IS NOT NULL THEN v_schedule_base ELSE NULL END,
      "TotalDisparos" = v_non_pending_total + v_pending_total,
      "StatusDisparo" = CASE
        WHEN lower(COALESCE(v_old_status,'')) = 'pausado' THEN 'Pausado'
        WHEN v_pending_total = 0 THEN COALESCE(v_old_status, 'Finalizado')
        WHEN v_first_pending_ts > now() THEN 'Aguardando'
        ELSE 'Em andamento'
      END
  WHERE id = v_disparo_id
    AND "contaId" = v_conta_id;

  RETURN v_disparo_id;
END $function$;

CREATE OR REPLACE FUNCTION public.create_disparo_grupo(p_payload jsonb)
RETURNS bigint LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $function$
DECLARE
  v_conta_id uuid := (p_payload->>'userId')::uuid;
  v_nome_disparo text := NULLIF(COALESCE(p_payload->>'nomeCampanha', p_payload->>'nomeDisparo', ''), '');
  v_mention_all boolean := coalesce((p_payload#>>'{settings,mencionarTodos}')::boolean,false);
  v_messages jsonb[] := ARRAY(SELECT m FROM jsonb_array_elements(COALESCE(p_payload->'mensagens','[]'::jsonb)) m);
  v_msg_count int := coalesce(array_length(v_messages,1),0);
  v_conn_id bigint := (SELECT (c->>'id')::bigint FROM jsonb_array_elements(COALESCE(p_payload->'connections','[]'::jsonb)) c WHERE (c->>'id') ~ '^\d+$' ORDER BY 1 LIMIT 1);
  v_etiqueta_ids bigint[] := COALESCE(ARRAY(SELECT (x)::bigint FROM jsonb_array_elements_text(COALESCE(p_payload->'idLista', p_payload->'idEtiqueta','[]'::jsonb)) x), array[]::bigint[]);
  v_stage_ids bigint[] := COALESCE(
    ARRAY(
      SELECT DISTINCT (f->>'stageId')::bigint
      FROM jsonb_array_elements(COALESCE(p_payload->'settings'->'crmFilters','[]'::jsonb)) f
      WHERE (f->>'stageId') ~ '^\d+$'
    ),
    ARRAY(
      SELECT DISTINCT (x)::bigint
      FROM jsonb_array_elements_text(COALESCE(p_payload->'settings'->'crmStageIds','[]'::jsonb)) x
      WHERE x ~ '^\d+$'
    ),
    array[]::bigint[]
  );
  v_month_start timestamptz := (date_trunc('month', now() AT TIME ZONE 'America/Sao_Paulo') AT TIME ZONE 'America/Sao_Paulo');
  v_next_month timestamptz := ((date_trunc('month', now() AT TIME ZONE 'America/Sao_Paulo') + interval '1 month') AT TIME ZONE 'America/Sao_Paulo');
  v_limit_plan bigint; v_used_month bigint; v_to_send bigint; v_total_after bigint;
  v_interval_min int := COALESCE((p_payload #>> '{settings,intervalMin}')::int, 30);
  v_interval_max int := COALESCE((p_payload #>> '{settings,intervalMax}')::int, 60);
  v_pause_after int := COALESCE((p_payload #>> '{settings,pauseAfterMessages}')::int, 20);
  v_pause_minutes int := COALESCE((p_payload #>> '{settings,pauseMinutes}')::int, 10);
  v_start_time time := COALESCE((p_payload #>> '{settings,startTime}')::time, time '08:00');
  v_end_time time := COALESCE((p_payload #>> '{settings,endTime}')::time, time '18:00');
  v_days int[] := COALESCE(ARRAY(SELECT CASE WHEN dtxt='0' THEN 7 ELSE dtxt::int END FROM jsonb_array_elements_text(COALESCE(p_payload->'settings'->'selectedDays','[]'::jsonb)) WITH ORDINALITY AS t(dtxt,ord) WHERE dtxt ~ '^\d+$' ORDER BY ord), array[]::int[]);
  v_schedule_base timestamptz := COALESCE((p_payload#>>'{settings,scheduleData}')::timestamptz, now() + interval '2 minutes');
  v_cur_ts timestamptz; v_disparo_id bigint; v_first_ts timestamptz; v_total int := 0; v_idx_msg int := 1; v_counter int := 0; v_gap int;
  v_msg_obj jsonb; v_template text; v_media_hash text; v_rendered text; rec_cont record;
BEGIN
  IF v_interval_min <= 0 THEN v_interval_min := 30; END IF;
  IF v_interval_max <= 0 THEN v_interval_max := 60; END IF;
  IF v_interval_max < v_interval_min THEN v_interval_max := v_interval_min; END IF;
  IF v_pause_after < 0 THEN v_pause_after := 0; END IF;
  IF v_pause_minutes < 0 THEN v_pause_minutes := 0; END IF;
  IF COALESCE(cardinality(v_days),0) = 0 THEN v_days := ARRAY[1,2,3,4,5,6,7]; END IF;
  v_cur_ts := f_next_valid_time(v_schedule_base, v_start_time, v_end_time, v_days);

  SELECT p."qntDisparos"::bigint INTO v_limit_plan FROM public."SAAS_Contas" conta LEFT JOIN public."SAAS_Planos" p ON p.id = conta.plano WHERE conta.id = v_conta_id;
  IF v_limit_plan IS NOT NULL THEN
    SELECT COALESCE(COUNT(*),0)::bigint INTO v_used_month FROM public."SAAS_Detalhes_Disparos" d JOIN public."SAAS_Disparos" h ON h.id = d."idDisparo" WHERE h."contaId" = v_conta_id AND d."dataEnvio" >= v_month_start AND d."dataEnvio" < v_next_month;
    WITH etiqueta_grupos AS (
      SELECT DISTINCT c.id, (c.variaveis->>'whatsappId') AS wid
      FROM public."SAAS_Contatos" c
      JOIN public."SAAS_Contatos_Etiquetas" ce ON ce."contatoId" = c.id
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'grupo'
        AND ce."etiquetaId" = ANY(v_etiqueta_ids)
        AND NULLIF(btrim(c.variaveis->>'whatsappId'),'') IS NOT NULL
    ),
    crm_grupos AS (
      SELECT DISTINCT c.id, (c.variaveis->>'whatsappId') AS wid
      FROM public."SAAS_Contatos" c
      JOIN public."SAAS_Cards_Quadros" cq ON cq."contatoId" = c.id
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'grupo'
        AND cq."etapaQuadroId" = ANY(v_stage_ids)
        AND NULLIF(btrim(c.variaveis->>'whatsappId'),'') IS NOT NULL
    ),
    all_grupos AS (
      SELECT DISTINCT c.id, (c.variaveis->>'whatsappId') AS wid
      FROM public."SAAS_Contatos" c
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'grupo'
        AND NULLIF(btrim(c.variaveis->>'whatsappId'),'') IS NOT NULL
        AND COALESCE(cardinality(v_etiqueta_ids),0) = 0
        AND COALESCE(cardinality(v_stage_ids),0) = 0
    ),
    base AS (
      SELECT wid FROM etiqueta_grupos
      UNION
      SELECT wid FROM crm_grupos
      UNION
      SELECT wid FROM all_grupos
    )
    SELECT COALESCE(COUNT(*),0)::bigint INTO v_to_send FROM base;
    v_total_after := v_used_month + v_to_send;
    IF v_total_after > v_limit_plan THEN RAISE EXCEPTION 'limite atingido: % usados + % a enviar = %', v_used_month, v_to_send, v_total_after USING ERRCODE='P0001'; END IF;
  END IF;
  INSERT INTO public."SAAS_Disparos" ("NomeDisparo","Mensagens","TipoDisparo","TotalDisparos","MensagensDisparadas","StatusDisparo","contaId","idEtiquetas","idConexoes","DataAgendamento")
  VALUES (v_nome_disparo,v_messages,'Grupos',0,0,'Aguardando',v_conta_id,v_etiqueta_ids,CASE WHEN v_conn_id IS NOT NULL THEN ARRAY[v_conn_id] ELSE NULL END,CASE WHEN p_payload #>> '{settings,scheduleData}' IS NOT NULL THEN v_schedule_base ELSE NULL END)
  RETURNING id INTO v_disparo_id;
  FOR rec_cont IN
    WITH etiqueta_grupos AS (
      SELECT DISTINCT c.id, c.nome, COALESCE(c.variaveis,'{}'::jsonb) AS base_variaveis
      FROM public."SAAS_Contatos" c
      JOIN public."SAAS_Contatos_Etiquetas" ce ON ce."contatoId" = c.id
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'grupo'
        AND ce."etiquetaId" = ANY(v_etiqueta_ids)
        AND NULLIF(btrim(c.variaveis->>'whatsappId'),'') IS NOT NULL
    ),
    crm_grupos AS (
      SELECT DISTINCT c.id, c.nome, COALESCE(c.variaveis,'{}'::jsonb) AS base_variaveis
      FROM public."SAAS_Contatos" c
      JOIN public."SAAS_Cards_Quadros" cq ON cq."contatoId" = c.id
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'grupo'
        AND cq."etapaQuadroId" = ANY(v_stage_ids)
        AND NULLIF(btrim(c.variaveis->>'whatsappId'),'') IS NOT NULL
    ),
    all_grupos AS (
      SELECT DISTINCT c.id, c.nome, COALESCE(c.variaveis,'{}'::jsonb) AS base_variaveis
      FROM public."SAAS_Contatos" c
      WHERE c."contaId" = v_conta_id
        AND c.tipo = 'grupo'
        AND NULLIF(btrim(c.variaveis->>'whatsappId'),'') IS NOT NULL
        AND COALESCE(cardinality(v_etiqueta_ids),0) = 0
        AND COALESCE(cardinality(v_stage_ids),0) = 0
    ),
    base AS (
      SELECT * FROM etiqueta_grupos
      UNION
      SELECT * FROM crm_grupos
      UNION
      SELECT * FROM all_grupos
    ),
    contato_custom_fields AS (
      SELECT
        b.id AS contato_id,
        COALESCE(
          jsonb_object_agg(
            lower(regexp_replace(cp."nome", '\s+', '_', 'g')),
            COALESCE(vcp."valor",'')
          ) FILTER (WHERE cp.id IS NOT NULL),
          '{}'::jsonb
        ) AS custom_variaveis
      FROM base b
      LEFT JOIN public."SAAS_Valores_Campos_Personalizados" vcp ON vcp."idContato" = b.id AND vcp."contaId" = v_conta_id
      LEFT JOIN public."SAAS_Campos_Personalizados" cp ON cp.id = vcp."idCampo" AND cp."contaId" = v_conta_id
      GROUP BY b.id
    )
    SELECT DISTINCT ON ((coalesce(b.base_variaveis->>'whatsappId','')))
      b.id,
      coalesce(b.base_variaveis->>'whatsappId','') AS "whatsappId",
      b.nome,
      (COALESCE(b.base_variaveis,'{}'::jsonb) || COALESCE(ccf.custom_variaveis,'{}'::jsonb)) AS variaveis
    FROM base b
    LEFT JOIN contato_custom_fields ccf ON ccf.contato_id = b.id
    ORDER BY (coalesce(b.base_variaveis->>'whatsappId','')), b.id
  LOOP
    v_msg_obj := v_messages[v_idx_msg]; v_idx_msg := (v_idx_msg % v_msg_count) + 1;
    v_template := v_msg_obj->>'text'; v_media_hash := NULLIF(COALESCE(v_msg_obj->'media'->>'link', v_msg_obj->'media'->>'hashredis',''),'');
    IF v_pause_after > 0 AND v_counter > 0 AND v_counter % v_pause_after = 0 THEN v_cur_ts := f_next_valid_time(v_cur_ts + make_interval(mins => v_pause_minutes), v_start_time, v_end_time, v_days); END IF;
    v_rendered := public.f_render_message(v_template, rec_cont.nome, COALESCE(rec_cont.variaveis,'{}'::jsonb), v_cur_ts);
    INSERT INTO public."SAAS_Detalhes_Disparos" ("idDisparo","idContato","Mensagem","idConexao","dataEnvio","Status","KeyRedis","FakeCall")
    VALUES (v_disparo_id, rec_cont.id, v_rendered, v_conn_id, v_cur_ts, 'pending', v_media_hash, v_mention_all);
    IF v_total = 0 THEN v_first_ts := v_cur_ts; END IF;
    v_total := v_total + 1; v_counter := v_counter + 1;
    v_gap := v_interval_min + floor(random() * (v_interval_max - v_interval_min + 1))::int;
    v_cur_ts := f_next_valid_time(v_cur_ts + make_interval(secs => v_gap), v_start_time, v_end_time, v_days);
  END LOOP;
  UPDATE public."SAAS_Disparos" SET "TotalDisparos"=v_total, "StatusDisparo"=CASE WHEN v_first_ts > now() THEN 'Aguardando' ELSE 'Em andamento' END WHERE id=v_disparo_id;
  RETURN v_disparo_id;
END $function$;

CREATE OR REPLACE FUNCTION public.f_limpar_etiquetas(p_conta_id uuid)
RETURNS boolean LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  IF NOT public.is_admin(p_conta_id) AND NOT public.is_super_admin() THEN RETURN false; END IF;
  DELETE FROM public."SAAS_Contatos_Etiquetas" WHERE "contaId" = p_conta_id;
  DELETE FROM public."SAAS_Contatos" WHERE "contaId" = p_conta_id;
  DELETE FROM public."SAAS_Etiquetas" WHERE "contaId" = p_conta_id;
  RETURN true;
END;
$$;

CREATE OR REPLACE FUNCTION public.f_resetar_conta(p_conta_id uuid)
RETURNS boolean LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE conv_ids bigint[]; disp_ids bigint[]; quadro_ids bigint[];
BEGIN
  IF NOT public.is_admin(p_conta_id) AND NOT public.is_super_admin() THEN RETURN false; END IF;
  SELECT array_agg(id) INTO conv_ids FROM public."SAAS_Conversas_Agentes" WHERE "contaId" = p_conta_id;
  IF conv_ids IS NOT NULL AND array_length(conv_ids, 1) > 0 THEN DELETE FROM public."SAAS_Mensagens" WHERE "conversaId" = ANY(conv_ids); END IF;
  DELETE FROM public."SAAS_Conversas_Agentes" WHERE "contaId" = p_conta_id;
  SELECT array_agg(id) INTO disp_ids FROM public."SAAS_Disparos" WHERE "contaId" = p_conta_id;
  IF disp_ids IS NOT NULL AND array_length(disp_ids, 1) > 0 THEN DELETE FROM public."SAAS_Detalhes_Disparos" WHERE "idDisparo" = ANY(disp_ids); END IF;
  DELETE FROM public."SAAS_Disparos" WHERE "contaId" = p_conta_id;
  DELETE FROM public."SAAS_Contatos_Etiquetas" WHERE "contaId" = p_conta_id;
  DELETE FROM public."SAAS_Contatos" WHERE "contaId" = p_conta_id;
  DELETE FROM public."SAAS_Etiquetas" WHERE "contaId" = p_conta_id;
  SELECT array_agg(id) INTO quadro_ids FROM public."SAAS_Quadros" WHERE "contaId" = p_conta_id;
  IF quadro_ids IS NOT NULL AND array_length(quadro_ids, 1) > 0 THEN DELETE FROM public."SAAS_Cards_Quadros" WHERE "quadroId" = ANY(quadro_ids); END IF;
  DELETE FROM public."SAAS_Etapas_Quadros" WHERE "contaId" = p_conta_id;
  DELETE FROM public."SAAS_Quadros" WHERE "contaId" = p_conta_id;
  DELETE FROM public."SAAS_Conexões" WHERE "contaId" = p_conta_id;
  DELETE FROM public."SAAS_AgentesIA" WHERE "contaId" = p_conta_id;
  DELETE FROM public."SAAS_Webhook" WHERE "contaId" = p_conta_id;
  IF to_regclass('public."SAAS_IntegracaoPagamento"') IS NOT NULL THEN DELETE FROM public."SAAS_IntegracaoPagamento"; END IF;
  DELETE FROM public."SAAS_Resposta_Rapidas" WHERE "contaId" = p_conta_id;
  RETURN true;
END;
$$;

