  END IF;
END $$;

-- RLS e GRANTs etiquetas
DO $$
BEGIN
  IF to_regclass('public."SAAS_Etiquetas"') IS NOT NULL THEN
    ALTER TABLE public."SAAS_Etiquetas" ENABLE ROW LEVEL SECURITY;
    DROP POLICY IF EXISTS "select_listas" ON public."SAAS_Etiquetas";
    DROP POLICY IF EXISTS "insert_listas" ON public."SAAS_Etiquetas";
    DROP POLICY IF EXISTS "update_listas" ON public."SAAS_Etiquetas";
    DROP POLICY IF EXISTS "delete_listas_admin" ON public."SAAS_Etiquetas";
    DROP POLICY IF EXISTS "select_etiquetas" ON public."SAAS_Etiquetas";
    DROP POLICY IF EXISTS "insert_etiquetas" ON public."SAAS_Etiquetas";
    DROP POLICY IF EXISTS "update_etiquetas" ON public."SAAS_Etiquetas";
    DROP POLICY IF EXISTS "delete_etiquetas_admin" ON public."SAAS_Etiquetas";
    CREATE POLICY "select_etiquetas" ON public."SAAS_Etiquetas" FOR SELECT TO authenticated USING (public.can_access_conta("contaId") OR public.is_super_admin());
    CREATE POLICY "insert_etiquetas" ON public."SAAS_Etiquetas" FOR INSERT TO authenticated WITH CHECK (public.can_access_conta("contaId") OR public.is_super_admin());
    CREATE POLICY "update_etiquetas" ON public."SAAS_Etiquetas" FOR UPDATE TO authenticated USING (public.can_access_conta("contaId") OR public.is_super_admin()) WITH CHECK (public.can_access_conta("contaId") OR public.is_super_admin());
    CREATE POLICY "delete_etiquetas_admin" ON public."SAAS_Etiquetas" FOR DELETE TO authenticated USING (public.is_admin("contaId") OR public.is_super_admin());
  END IF;
  IF to_regclass('public."SAAS_Contatos_Etiquetas"') IS NOT NULL THEN
    ALTER TABLE public."SAAS_Contatos_Etiquetas" ENABLE ROW LEVEL SECURITY;
    DROP POLICY IF EXISTS "select_contatos_etiquetas" ON public."SAAS_Contatos_Etiquetas";
    DROP POLICY IF EXISTS "insert_contatos_etiquetas" ON public."SAAS_Contatos_Etiquetas";
    DROP POLICY IF EXISTS "delete_contatos_etiquetas" ON public."SAAS_Contatos_Etiquetas";
    DROP POLICY IF EXISTS "delete_contatos_etiquetas_admin" ON public."SAAS_Contatos_Etiquetas";
    CREATE POLICY "select_contatos_etiquetas" ON public."SAAS_Contatos_Etiquetas" FOR SELECT TO authenticated USING (public.can_access_conta("contaId") OR public.is_super_admin());
    CREATE POLICY "insert_contatos_etiquetas" ON public."SAAS_Contatos_Etiquetas" FOR INSERT TO authenticated WITH CHECK (public.can_access_conta("contaId") OR public.is_super_admin());
    CREATE POLICY "delete_contatos_etiquetas_admin" ON public."SAAS_Contatos_Etiquetas" FOR DELETE TO authenticated USING (public.is_admin("contaId") OR public.is_super_admin());
  END IF;
  IF to_regclass('public."SAAS_Campos_Personalizados"') IS NOT NULL THEN
    ALTER TABLE public."SAAS_Campos_Personalizados" ENABLE ROW LEVEL SECURITY;
    DROP POLICY IF EXISTS "select_campos_personalizados" ON public."SAAS_Campos_Personalizados";
    DROP POLICY IF EXISTS "insert_campos_personalizados" ON public."SAAS_Campos_Personalizados";
    DROP POLICY IF EXISTS "update_campos_personalizados" ON public."SAAS_Campos_Personalizados";
    DROP POLICY IF EXISTS "delete_campos_personalizados_admin" ON public."SAAS_Campos_Personalizados";
    CREATE POLICY "select_campos_personalizados" ON public."SAAS_Campos_Personalizados" FOR SELECT TO authenticated USING (public.can_access_conta("contaId") OR public.is_super_admin());
    CREATE POLICY "insert_campos_personalizados" ON public."SAAS_Campos_Personalizados" FOR INSERT TO authenticated WITH CHECK (public.can_access_conta("contaId") OR public.is_super_admin());
    CREATE POLICY "update_campos_personalizados" ON public."SAAS_Campos_Personalizados" FOR UPDATE TO authenticated USING (public.can_access_conta("contaId") OR public.is_super_admin()) WITH CHECK (public.can_access_conta("contaId") OR public.is_super_admin());
    CREATE POLICY "delete_campos_personalizados_admin" ON public."SAAS_Campos_Personalizados" FOR DELETE TO authenticated USING (public.is_admin("contaId"));
  END IF;
  IF to_regclass('public."SAAS_Valores_Campos_Personalizados"') IS NOT NULL THEN
    ALTER TABLE public."SAAS_Valores_Campos_Personalizados" ENABLE ROW LEVEL SECURITY;
    DROP POLICY IF EXISTS "select_valores_campos_personalizados" ON public."SAAS_Valores_Campos_Personalizados";
    DROP POLICY IF EXISTS "insert_valores_campos_personalizados" ON public."SAAS_Valores_Campos_Personalizados";
    DROP POLICY IF EXISTS "update_valores_campos_personalizados" ON public."SAAS_Valores_Campos_Personalizados";
    DROP POLICY IF EXISTS "delete_valores_campos_personalizados_admin" ON public."SAAS_Valores_Campos_Personalizados";
    CREATE POLICY "select_valores_campos_personalizados" ON public."SAAS_Valores_Campos_Personalizados" FOR SELECT TO authenticated
      USING (
        EXISTS (
          SELECT 1
          FROM public."SAAS_Campos_Personalizados" cp
          WHERE cp.id = "SAAS_Valores_Campos_Personalizados"."idCampo"
            AND (public.can_access_conta(cp."contaId") OR public.is_super_admin())
        )
      );
    CREATE POLICY "insert_valores_campos_personalizados" ON public."SAAS_Valores_Campos_Personalizados" FOR INSERT TO authenticated
      WITH CHECK (
        EXISTS (
          SELECT 1
          FROM public."SAAS_Campos_Personalizados" cp
          JOIN public."SAAS_Contatos" c ON c.id = "SAAS_Valores_Campos_Personalizados"."idContato"
          WHERE cp.id = "SAAS_Valores_Campos_Personalizados"."idCampo"
            AND cp."contaId" = c."contaId"
            AND "SAAS_Valores_Campos_Personalizados"."contaId" = cp."contaId"
            AND "SAAS_Valores_Campos_Personalizados"."contaId" = c."contaId"
            AND (public.can_access_conta(cp."contaId") OR public.is_super_admin())
        )
      );
    CREATE POLICY "update_valores_campos_personalizados" ON public."SAAS_Valores_Campos_Personalizados" FOR UPDATE TO authenticated
      USING (
        EXISTS (
          SELECT 1
          FROM public."SAAS_Campos_Personalizados" cp
          WHERE cp.id = "SAAS_Valores_Campos_Personalizados"."idCampo"
            AND (public.can_access_conta(cp."contaId") OR public.is_super_admin())
        )
      )
      WITH CHECK (
        EXISTS (
          SELECT 1
          FROM public."SAAS_Campos_Personalizados" cp
          JOIN public."SAAS_Contatos" c ON c.id = "SAAS_Valores_Campos_Personalizados"."idContato"
          WHERE cp.id = "SAAS_Valores_Campos_Personalizados"."idCampo"
            AND cp."contaId" = c."contaId"
            AND "SAAS_Valores_Campos_Personalizados"."contaId" = cp."contaId"
            AND "SAAS_Valores_Campos_Personalizados"."contaId" = c."contaId"
            AND (public.can_access_conta(cp."contaId") OR public.is_super_admin())
        )
      );
    CREATE POLICY "delete_valores_campos_personalizados_admin" ON public."SAAS_Valores_Campos_Personalizados" FOR DELETE TO authenticated
      USING (
        EXISTS (
          SELECT 1
          FROM public."SAAS_Campos_Personalizados" cp
          WHERE cp.id = "SAAS_Valores_Campos_Personalizados"."idCampo"
            AND (public.can_access_conta(cp."contaId") OR public.is_super_admin())
        )
      );
  END IF;
END$$;

