-- View vw_Detalhes_Completo
CREATE OR REPLACE VIEW public."vw_Detalhes_Completo" WITH (security_invoker = true) AS
SELECT d.id, d."idDisparo", d."idContato", d."Mensagem", d."idConexao", d."dataEnvio", d."Status", d."statusHttp", d."mensagemErro", d."respostaHttp", d."Payload", d."KeyRedis", d."FakeCall",
  disp."StatusDisparo",
  CASE WHEN c.tipo = 'contato' THEN c.telefone ELSE NULL END AS "TelefoneContato",
  c.variaveis->>'whatsappId' AS "WhatsAppIdGrupo",
  c.nome AS "NomeGrupo",
  cx."instanceName" AS "InstanceName", cx."Apikey" AS "ApikeyConexao",
  disp."contaId" AS "UserId", cx."NomeConexao", disp."TipoDisparo"
FROM public."SAAS_Detalhes_Disparos" d
LEFT JOIN public."SAAS_Disparos" disp ON disp.id = d."idDisparo"
LEFT JOIN public."SAAS_Contatos" c ON c.id = d."idContato"
LEFT JOIN public."SAAS_Conexões" cx ON cx.id = d."idConexao";
